-- Poems batch 274
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d79bf99b-8b20-4adf-99fc-ff100dfa283f','送退齋先生歸武夷  其一','林若存','宋','宋诗','song-poetry','','[]','我未識退齋，虛生七十載。',60,'全唐诗/poet.song.242000.json','["我未識退齋，虛生七十載。", "一旦過諸途，未語心先拜。", "堂堂眉睫間，禮樂見三代。", "正塗日以荒，良心日以壞。", "天不産斯人，吾道將疇頼。"]'),
('94eeee1b-a8c1-417c-8b2a-ebfba4b10a14','送退齋先生歸武夷  其二','林若存','宋','宋诗','song-poetry','','[]','書院新鰲峰，五賢祠學宮。',60,'全唐诗/poet.song.242000.json','["書院新鰲峰，五賢祠學宮。", "馬邵獨避席，將無道不同。", "專專論的派，此理誰當窮。", "獨學無師友，前儒議溫公。", "準繩規矩內，安得鞭霆風。"]'),
('0178dbe7-97a8-4acb-9435-aca315510f14','送退齋先生歸武夷  其三','林若存','宋','宋诗','song-poetry','','[]','我七君六旬，從會知無期。',60,'全唐诗/poet.song.242000.json','["我七君六旬，從會知無期。", "但貪言議合，不悞光景非。", "先生明當別，吾將儔决疑。", "欲言尚何限，記一十已遺。", "及其未溘先，幸無靳珍題。"]'),
('687b040e-1f2a-4588-bccc-7e0ae6428887','送退齋先生歸武夷  其四','林若存','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','大運何茫茫，海桑逝不留。',168,'全唐诗/poet.song.242000.json','["大運何茫茫，海桑逝不留。", "武夷有喬木，虯枝尚相樛。", "自昔擢巍科，爲今闡大猷。", "萬里憚北上，三年喜南游。", "長身古衣冠，龐眉瞭雙眸。", "雖與今人居，不與今人儔。", "和風顔子春，泰山鄒孟秋。", "一雙憂世淚，濺入銀河流。", "相期入聖域，舍子誰當優。", "奈何棄我去，犖确歸途修。", "我欲斷中流，去棹何悠悠。", "我欲息天風，別袂何颼颼。", "明晨君已遠，晚歲吾何求。", "恐無後會期，笑作來生謀。"]'),
('5ca9dac3-2d15-4ffb-8ea4-8a0567176e53','句  其一','尤冰寮','宋','宋诗','song-poetry','','[]','累重無歌舞，官閑省簿書。',12,'全唐诗/poet.song.242000.json','["累重無歌舞，官閑省簿書。"]'),
('fefe23ba-cceb-430b-be4b-43fcf53c9897','句  其二','尤冰寮','宋','宋诗','song-poetry','','[]','三條椽下歸空榻，百尺樓中透遠峰。',16,'全唐诗/poet.song.242000.json','["三條椽下歸空榻，百尺樓中透遠峰。"]'),
('ad9998c4-b466-473b-a121-4b5de5f0e517','句  其三','尤冰寮','宋','宋诗','song-poetry','','[]','蟻返愁尋穴，鴉歸喜見巢。',12,'全唐诗/poet.song.242000.json','["蟻返愁尋穴，鴉歸喜見巢。"]'),
('238eee8a-df9f-4def-a4b3-e01b50e45a55','凌源閣','戴應魁','宋','宋诗','song-poetry','','[]','天風吹鈴語不煩，菩提樹杪碧闌干。',64,'全唐诗/poet.song.242000.json','["天風吹鈴語不煩，菩提樹杪碧闌干。", "恒河月滿三千界，大樹雲棲五百尊。", "辟支腦現赤蛇死，玉局手澤蒼苔乾。", "老僧出定蟠龍吼，喚醒諸寮佛子孫。"]'),
('7e8f5f1a-ac8f-4d13-8747-201e5f5f157d','海月巖','戴應魁','宋','宋诗','song-poetry','','[]','誰把巉巖巧鑿開，分明幻出小蓬萊。',64,'全唐诗/poet.song.242000.json','["誰把巉巖巧鑿開，分明幻出小蓬萊。", "風迎蜃氣樓臺起，浪湧蟾光宮闕來。", "海闊魚龍自吞吐，雲深鸞鶴共徘徊。", "禪師九座經遊處，一訪遺蹤爲拂埃。"]'),
('75f01b69-45de-4264-967f-fb7b146060e3','贈疊山先生','毛直方','宋','宋诗','song-poetry','','[]','一襟書傳日星懸，湖海聲名五十年。',64,'全唐诗/poet.song.242000.json','["一襟書傳日星懸，湖海聲名五十年。", "事不求知惟此理，文之未喪豈皆天。", "人方驚怪歐陽子，我獨悲傷魯仲連。", "看鏡倚樓秋已暮，風巾霜屨重依然。"]'),
('a2280e8d-7a5e-4be4-986c-c5c70675a85b','擬古  其一','毛直方','宋','宋诗','song-poetry','','[]','高堂列綺席，賓御何委蛇。',108,'全唐诗/poet.song.242000.json','["高堂列綺席，賓御何委蛇。", "粲粲金芙蓉，春葩照蛾眉。", "檀槽起清籟，鐵撥弦鵾雞。", "祇聞筵中曲，不聞曲中詞。", "蕭蕭青冢魂，化作秋雁歸。", "玉關去時淚，點點濕朱絲。", "豈知哀怨情，及此歡笑期。", "彈者錦纏頭，聽者金屈卮。", "但令今人樂，不惜古人悲。"]'),
('b8111fe0-a375-4b2a-bae2-493686403fbf','擬古  其二','毛直方','宋','宋诗','song-poetry','','[]','野色倏已暝，零落沾我裳。',84,'全唐诗/poet.song.242000.json','["野色倏已暝，零落沾我裳。", "行役悲險艱，仰愧歸鳥翔。", "羈愁浩難收，壯髮日已蒼。", "遠林烟火微，投宿扣村莊。", "居人畢刈穫，笑語井臼傍。", "問客來何疲，毋乃仕與商。", "所慎在出門，奚怨中路長。"]'),
('afccd4bd-a61c-4220-99c1-a0a8171fc150','雜怨  其一','毛直方','宋','宋诗','song-poetry','','[]','種蓮恨不早，得藕常苦遲。',24,'全唐诗/poet.song.242000.json','["種蓮恨不早，得藕常苦遲。", "誰知心中事，久已落懷思。"]'),
('5554a140-45e4-46d4-b0ae-52207c3dd7f6','雜怨  其二','毛直方','宋','宋诗','song-poetry','','[]','花開能夜合，草發解宜男。',24,'全唐诗/poet.song.242000.json','["花開能夜合，草發解宜男。", "對花今有恨，見草祇應慚。"]'),
('a598ef73-c044-4c18-9db3-53e22cb54fbe','江南曲  其一','毛直方','宋','宋诗','song-poetry','','[]','津頭聞別語，三載以爲期。',24,'全唐诗/poet.song.242000.json','["津頭聞別語，三載以爲期。", "安得中山酒，醒日是歸時。"]'),
('7e144685-25d9-4b34-a099-2a92a22c0cd3','江南曲  其二','毛直方','宋','宋诗','song-poetry','','[]','沽酒酹江神，發船相送餞。',24,'全唐诗/poet.song.242000.json','["沽酒酹江神，發船相送餞。", "船去浪如席，船回風似箭。"]'),
('5da0f113-f7fd-481b-9d7d-ad1b8b99d758','妾薄命','毛直方','宋','宋诗','song-poetry','','[]','妾肌如玉顔如花，長眉窈窈青山斜。',180,'全唐诗/poet.song.242000.json','["妾肌如玉顔如花，長眉窈窈青山斜。", "深閨學成新婦禮，鏡鸞不與留年華。", "昨朝東鄰裁嫁衣，今朝西鄰催結褵。", "自憐孤燈照春夢，年年風雨梨花時。", "不怨父母貧，不恨蹇修拙。", "妾生賦命自坎壈，底用閒情寫紅葉。", "千絲萬絲霜練光，與誰織作雲錦裳。", "千針萬針兩黼黻，與誰佩服朝明堂。", "吁嗟妾薄命，薄命可奈何。", "失時還自羞，失身羞更多。", "妾寧失時無失身，平生分定月下繩。", "但把貞心守貞色，肯信嬋娟解誤人。"]'),
('7e85652a-4806-43f4-b34e-055aab4ba619','獨駿圖','毛直方','宋','宋诗','song-poetry','','[]','連天苜蓿青茫茫，鹽車鼓車紛道傍。',128,'全唐诗/poet.song.242000.json','["連天苜蓿青茫茫，鹽車鼓車紛道傍。", "肉騣汗血不可常，權奇倜儻晦若藏。", "五之六之無留良，如此獨步何堂堂。", "日三品豆慎所嘗，天閑逸氣誰能量。", "一尺之箠五尺韁，了與轡絡俱相忘。", "大僕御直儼冠裳，庭前榻上婉清揚。", "有詔有詔且勿忙，一洗凡馬鑾鏘鏘。", "我觀此圖筆意長，欲言尚寄田子方。"]'),
('5ad90f3c-8276-47a8-a2cc-4903f32a01df','贈督師曹將軍','毛直方','宋','宋诗','song-poetry','','[]','泰階煌煌色已齊，祥飆爲掃蚩尤旗。',168,'全唐诗/poet.song.242000.json','["泰階煌煌色已齊，祥飆爲掃蚩尤旗。", "幅員浩蕩春臺熙，不遣桴鼓驚鋤犂。", "羽林宿衛環三陲，居安却慮忘戰危。", "整暇自許忘其機，司馬八法律以規。", "蒐苗獼狩凜弗違，碧油有幢儼軍師。", "手持虎節談魚麗，閩關不以山與溪。", "歌舞七德宣皇威，有來視師省檄飛。", "將軍名已草木知，干戈俎豆睢陽時。", "已分勾當江南歸，流芳奕葉今孫枝，此行且賦從軍詩。", "時清未用歌采薇，天子有道守四夷。"]'),
('9824347a-8c21-48c6-a7ec-1c63f8188346','野宿','毛直方','宋','宋诗','song-poetry','','[]','歸恨逐春深，遲休欲縮程。',48,'全唐诗/poet.song.242000.json','["歸恨逐春深，遲休欲縮程。", "遠山何處碧，落日故鄉明。", "路改柴門僻，村空石磑鳴。", "乞蔬仍買米，一宿尚營營。"]'),
('d30e0c16-8725-4bd9-b805-1a3c2ea0f28c','秋感','毛直方','宋','宋诗','song-poetry','','[]','宇宙百年身，江湖萬里心。',48,'全唐诗/poet.song.242000.json','["宇宙百年身，江湖萬里心。", "世情高枕遠，詩味閉門深。", "白髮銷窮達，青山傲古今。", "情知秋亦客，何事感秋吟。"]'),
('2e295691-0cb3-4e44-b5d1-35189fd8dde6','漁父辭  其一','毛直方','宋','宋诗','song-poetry','','[]','萬里清江兩槳船，一竿一縷水雲邊。',32,'全唐诗/poet.song.242000.json','["萬里清江兩槳船，一竿一縷水雲邊。", "平生不識書與劍，也得醉飽供閒眠。"]'),
('e78309ae-8e91-46c6-b8ac-dc50646574af','漁父辭  其二','毛直方','宋','宋诗','song-poetry','','[]','呼兒買米得新粳，漁村且喜見秋成。',32,'全唐诗/poet.song.242000.json','["呼兒買米得新粳，漁村且喜見秋成。", "今朝嘗新莫草草，好釣鱸魚來煮羹。"]'),
('d6848d79-aedb-4e43-9869-e6de59a2d52d','漁父辭  其三','毛直方','宋','宋诗','song-poetry','','[]','得魚穿柳持上溪，溪村杳杳屋稀稀。',32,'全唐诗/poet.song.242000.json','["得魚穿柳持上溪，溪村杳杳屋稀稀。", "莫怪漁翁頭易白，去年買魚人又非。"]'),
('f7d3befa-286c-4cbc-8f07-023225f323b1','漁父辭  其四','毛直方','宋','宋诗','song-poetry','','[]','黄旗綱運牛馬走，皂衣追呼雞狗喧。',32,'全唐诗/poet.song.242000.json','["黄旗綱運牛馬走，皂衣追呼雞狗喧。", "深傍蘆花摇櫓去，遥望漁人是水仙。"]'),
('710702d6-5752-43d0-b48f-7a3acfb8ab3a','漁父辭  其五','毛直方','宋','宋诗','song-poetry','','[]','本無租賦本無田，不知曆日不知年。',32,'全唐诗/poet.song.242000.json','["本無租賦本無田，不知曆日不知年。", "誰信漁家小船上，猶是無懷并葛天。"]'),
('a8282c04-2b6c-4aa0-883f-17d8fb9044c4','漁父辭  其六','毛直方','宋','宋诗','song-poetry','','[]','黄昏船泊有鄰居，明朝船散又還無。',32,'全唐诗/poet.song.242000.json','["黄昏船泊有鄰居，明朝船散又還無。", "君笑我如浮萍草，我看君似水中鳬。"]'),
('999c25cd-fb9e-4e37-852e-6b905936a583','漁父辭  其七','毛直方','宋','宋诗','song-poetry','','[]','溪橋竹邊有酒沽，携魚換酒滿葫蘆。',32,'全唐诗/poet.song.242000.json','["溪橋竹邊有酒沽，携魚換酒滿葫蘆。", "篷頭月上不覺醉，自卷蘆葉吹嗚嗚。"]'),
('b35f35f1-2123-42e6-a348-104c216bc7f5','悼亡  其一','毛直方','宋','宋诗','song-poetry','','[]','從事龜山亦偶然，寧知長別恨終天。',32,'全唐诗/poet.song.242000.json','["從事龜山亦偶然，寧知長別恨終天。", "當時去就商量錯，不似牛衣十八年。"]'),
('1827d90c-4dcc-4bf5-a0b4-424b689c6b5a','悼亡  其二','毛直方','宋','宋诗','song-poetry','','[]','客中自有未招魂，剪紙空教夜祭門。',32,'全唐诗/poet.song.242000.json','["客中自有未招魂，剪紙空教夜祭門。", "萬一相逢今夜夢，恨多應是兩忘言。"]'),
('b9d18c43-9d8e-4985-8614-31eb5f417b7e','悼亡  其三','毛直方','宋','宋诗','song-poetry','','[]','奉倩傷神不是癡，人生百感有真機。',32,'全唐诗/poet.song.242000.json','["奉倩傷神不是癡，人生百感有真機。", "飄零遺墨殘針線，與淚無期自一揮。"]'),
('622221f5-c58e-46e0-a453-41dd06ecbb2f','悼亡  其四','毛直方','宋','宋诗','song-poetry','','[]','推愁不去竟何如，欲鼓莊盆懶有餘。',32,'全唐诗/poet.song.242000.json','["推愁不去竟何如，欲鼓莊盆懶有餘。", "頼是此□猶解事，避人對客與觀書。"]'),
('6b393715-ab95-48ed-a44d-a32d5ca40ba7','寄梅村山人  其一','毛直方','宋','宋诗','song-poetry','','[]','古松樹下晝陰寒，雲亦何心去不還。',32,'全唐诗/poet.song.242000.json','["古松樹下晝陰寒，雲亦何心去不還。", "却怪建州城裏夢，一春多在湛盧山。"]'),
('96f0950a-d19e-41f3-a1c6-367e75de1bc1','寄梅村山人  其二','毛直方','宋','宋诗','song-poetry','','[]','去年三客賦荼䕷，忽見新花發故枝。',32,'全唐诗/poet.song.242000.json','["去年三客賦荼䕷，忽見新花發故枝。", "省到死生離合處，春風消得幾相思。"]'),
('a48101ce-e409-4f95-b873-d3b71ec93eac','泥滑滑','毛直方','宋','宋诗','song-poetry','','[]','泥滑滑，日已西。',40,'全唐诗/poet.song.242000.json','["泥滑滑，日已西。", "泥深屨滑涴征衣，征衣涴盡不肯歸。", "分明數聲行不得，請君更聽鷓鴣啼。"]'),
('0be835fa-cef3-42e1-9956-c8904a6e233b','送縣尹任滿','毛直方','宋','宋诗','song-poetry','','[]','卓魯久不作，臨風重懷人。',168,'全唐诗/poet.song.242000.json','["卓魯久不作，臨風重懷人。", "錦溪有美錦，善製當誰稱。", "器之汾陽君，燁燁馳華聲。", "往來試樵邑，口碑播甌閩。", "東陽修何行，桃李三年春。", "安得百器之，布滿弦歌城。", "奈何斗以南，紛紛蒲璧榮。", "令君一何廉，廉乃不近名。", "令君一何明，明乃不見形。", "令君一何有，有若權在衡。", "令君一何了，又若刃發硎。", "能令政事簡，罰者懷其仁。", "官府有直氣，閭門無枉情。", "物論久逾定，去思見民真。"]'),
('0c982780-3e5c-42fa-bf6a-ffa24aca1eaf','時秋積雨霽','毛直方','宋','宋诗','song-poetry','','[]','醖釀豐年付老農，挽回凉信報詩翁。',64,'全唐诗/poet.song.242000.json','["醖釀豐年付老農，挽回凉信報詩翁。", "巫山久暗埋寒碧，湘水初明浴晚紅。", "簾卷柳陰先得月，簟橫梧影早噓風。", "天公快我披雲願，萬里乾坤一望中。"]'),
('fa099900-6f5c-49d9-bccb-4bc409f7a1b9','贈退齋同年貢舉','吳語溪','宋','宋诗','song-poetry','','[]','看花携手鬢俱青，一轉頭來昨夢驚。',64,'全唐诗/poet.song.242000.json','["看花携手鬢俱青，一轉頭來昨夢驚。", "四海同年今有幾，相逢此日得無情。", "著書君已名千載，廢學吾方悔半生。", "離合升沉何足計，相期進德是功名。"]'),
('fb63223b-40e7-4c60-a008-a0d0834bd4b6','挽趙秋曉  其一','張登辰','宋','宋诗','song-poetry','','[]','儒風凋落盡，生意僅如絲。',48,'全唐诗/poet.song.242000.json','["儒風凋落盡，生意僅如絲。", "一自先生死，深爲吾道悲。", "頹波誰砥柱，善類孰綱維。", "有子森如玉，斯文想未衰。"]'),
('fd0f742f-268f-4451-8b46-f364733b19bf','挽趙秋曉  其二','張登辰','宋','宋诗','song-poetry','','[]','自古名而壽，宗臣罕有之。',48,'全唐诗/poet.song.242000.json','["自古名而壽，宗臣罕有之。", "嘗陵終落魄，賀白不期頤。", "天涸璇源派，霜摧玉樹枝。", "遊魂歸故國，忍見黍離離。"]'),
('9ff767fb-390c-438c-8639-e3cbc59529e0','挽趙秋曉  其三','張登辰','宋','宋诗','song-poetry','','[]','羈貫分燈讀，論交若弟兄。',48,'全唐诗/poet.song.242000.json','["羈貫分燈讀，論交若弟兄。", "羨君先得雋，嗟我老無成。", "幾載同憂患，終年隔死生。", "夢中猶歷歷，笑語若生平。"]'),
('1c01388b-cd9c-42d5-b2d5-34332967d212','赭衣舂','張登辰','宋','宋诗','song-poetry','','[]','赭衣舂永巷，酸風起暮杵。',148,'全唐诗/poet.song.242000.json','["赭衣舂永巷，酸風起暮杵。", "聲聲碎妾心，妾兒痛隔三千里。", "灞水歡迎骨肉恩，子母再見無由緣。", "誰將鴆羽飲龍子，晨獵上林如意死。", "妾耳縱能聞，妾目那能視。", "妾口縱能言，妾足安能履。", "白日改色天容愁，未央宮中桐葉秋。", "堂堂豐沛龍準公，三尺造漢烹英雄。", "擊布歸來尚無恙，預置股肱如指掌。", "明知戇勃可安劉，何爲存妾子母無良謀。"]'),
('b0484ae0-1be2-4991-a958-824b2f51e89a','挽陳東湖先生  其一','張衡','宋','宋诗','song-poetry','','[]','真病藥無功，精魂奪鬼工。',48,'全唐诗/poet.song.242000.json','["真病藥無功，精魂奪鬼工。", "百年終有盡，諸相等成空。", "圓滿缺陷世，逍遥兜率宮。", "一池漚水意，分付蓼花風。"]'),
('246e73a3-8178-43c6-9e1f-d82d5a1e2ac5','挽陳東湖先生  其二','張衡','宋','宋诗','song-poetry','','[]','德星難再聚，薤露重興悲。',48,'全唐诗/poet.song.242000.json','["德星難再聚，薤露重興悲。", "客憶芹邊膾，孫尋膝上飴。", "入門惟水竹，拜像見鬚眉。", "吾父亦丁丑，白雲增夢思。"]'),
('69470eb9-8728-4874-88e5-0a2f5c34aeea','挽陳東湖先生  其三','張衡','宋','宋诗','song-poetry','','[]','四大假合相，六根清淨緣。',48,'全唐诗/poet.song.242000.json','["四大假合相，六根清淨緣。", "祇知心是佛，不惜藥成仙。", "魚泣銜沙立，鷗疑側腦眠。", "凄其野人奠，秋菊薦寒泉。"]'),
('5ac8c56c-3eec-436f-8dae-e836b172eb47','用廣陳君以畫徵題','張衡','宋','宋诗','song-poetry','','[]','陳君昨從江右歸，元龍豪氣如虹霓。',192,'全唐诗/poet.song.242000.json','["陳君昨從江右歸，元龍豪氣如虹霓。", "清晨訪我敘契闊，手持錦軸徵余題。", "遠山近山凡幾簇，三兩人家住溪曲。", "酒旗摇曳朝日晴，漁舟來往煙波綠。", "屬玉鵁鶄聚暖沙，疏籬老屋带煙霞。", "竹邊有客燒新笋，林下何人掃落花。", "景趣無窮來宛轉，一抹嵐光見平遠。", "斯圖精緻非尋常，妙筆原知歸北苑。", "君家舊住橋子東，森森喬木含清風。", "潁川世系年應遠，使節勳名孰與同。", "君視黄金猶土苴，好畫如逢不論價。", "何當乘興去相尋，索看新收古名畫。"]'),
('2609bc81-cdf7-415d-acc2-dd18d6bcf732','杜鵑','張衡','宋','宋诗','song-poetry','','[]','猛爲春歸苦口嘶，桐花滿地綠蔭齊。',32,'全唐诗/poet.song.242000.json','["猛爲春歸苦口嘶，桐花滿地綠蔭齊。", "自從康節先生後，孤汝天津故意啼。"]'),
('9d0adc6a-488a-45c7-b6e0-34b5dfaa97b0','經史閣四言詩','張衡','宋','宋诗','song-poetry','','[]','玄黄氤氳，混沌未死。',240,'全唐诗/poet.song.242000.json','["玄黄氤氳，混沌未死。", "道隠冥默，文鬰雕跂。", "蚩蚩熙熙，結繩而治。", "誰鑿七竅，鴻濛拊髀。", "馬圖鳥迹，彷彿文字。", "羲軒勳華，授受一理。", "典謨訓誥，渾渾無擬。", "天生素王，躬服仁義。", "憲章祖述，參贊經緯。", "經揭日月，史嚴辭事。", "九流說鈴，諸子疣贅。", "秦灰小厄，魯壁闡秘。", "白首齊生，口誦臆記。", "枝葉扶疏，風流委靡。", "漢興購求，六經大備。", "舒向校讎，班馬傳紀。", "爾雅同風，沿襲世次。", "宋三百年，超軼姚姒。", "際海薄天，聲教漸被。", "惟此東邑，藹藹多士。", "孔牆巍巍，重屋丹綺。", "羣玉之府，五經之笥。", "排籤插架，堆案盈几。", "藻飾皇猷，馳騁帝軌。"]'),
('32f86fee-606b-44f4-a62a-0f468bc53e0f','龍潭瀑布泉','張衡','宋','宋诗','song-poetry','','[]','古木千章蔭淺灘，干霄危石噀飛湍。',32,'全唐诗/poet.song.242000.json','["古木千章蔭淺灘，干霄危石噀飛湍。", "水晶簾下誰家女，亂擲珍珠落玉盤。"]'),
('b5c80a81-7d51-4bd3-852a-59754524271a','挽陳東湖先生  其一','張衡','宋','宋诗','song-poetry','','[]','清溝名父子，濁世福人家。',48,'全唐诗/poet.song.242000.json','["清溝名父子，濁世福人家。", "二妙手誰抗，一翁顛未華。", "天方老猿鶴，歲忽值龍蛇。", "公死可無憾，吾生未有涯。"]'),
('29380d59-31d9-4369-9a12-894b64ecc9f3','挽陳東湖先生  其二','張衡','宋','宋诗','song-poetry','','[]','亂世沒吾寧，何須滿百齡。',48,'全唐诗/poet.song.242000.json','["亂世沒吾寧，何須滿百齡。", "雲封靈壽杖，天殞少微星。", "長夜泉臺黑，幽林鬼火青。", "西風吹木葉，無語慰飄零。"]'),
('2cc8b55f-7adc-4a66-afcd-42fbd4115b90','贈桂琴隠先生','桂正夫','宋','宋诗','song-poetry','','[]','重賁衡門日，盤餐愧負羈。',48,'全唐诗/poet.song.242000.json','["重賁衡門日，盤餐愧負羈。", "經年疏問道，靜夜飽聽詩。", "近子覺形穢，服車羞耳垂。", "快哉過庭鯉，咫尺鳳凰池。"]'),
('2968aeaf-f623-42f8-995d-e5286add193d','寄友','朱浚','宋','宋诗','song-poetry','','[]','溪月知相憶，江雲約共吟。',24,'全唐诗/poet.song.242000.json','["溪月知相憶，江雲約共吟。", "夜船書一紙，飛過赤楓林。"]'),
('c9589b61-4c71-4db0-b3d0-bd2960589d81','秋日西湖','朱浚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幾州陵變谷，經月雨爲霖。',24,'全唐诗/poet.song.242000.json','["幾州陵變谷，經月雨爲霖。", "世事今如此，西風動客心。"]'),
('80e294ce-6b3a-4764-9b8e-2c3d84d1c9b8','贈賣墨呂雲叔訪陳烟山  其一','朱浚','宋','宋诗','song-poetry','','[]','仙宗傳訣自分明，未數當年老樹精。',32,'全唐诗/poet.song.242000.json','["仙宗傳訣自分明，未數當年老樹精。", "一片紫雲光滴滴，丹墀成就幾公卿。"]'),
('d9539c3e-6647-4b4b-b738-d04650297ef8','贈賣墨呂雲叔訪陳烟山  其二','朱浚','宋','宋诗','song-poetry','','[]','蓬萊仙子世偏珍，琮璧多携問楚津。',32,'全唐诗/poet.song.242000.json','["蓬萊仙子世偏珍，琮璧多携問楚津。", "若向積烟峰下過，殷勤傳語卧樓人。"]'),
('7e4a89e9-9a5c-4fb1-9242-7e90d03f0f75','都城初秋和趙京倅  其一','朱浚','宋','宋诗','song-poetry','','[]','從來美玉價連城，結佩乘風十二京。',32,'全唐诗/poet.song.242000.json','["從來美玉價連城，結佩乘風十二京。", "携上崢嶸今有約，好留彩筆調清平。"]'),
('0d884eeb-f535-49e5-897c-edfbf6a9d326','都城初秋和趙京倅  其二','朱浚','宋','宋诗','song-poetry','','[]','暑夢蟲蟲似醉中，片雲挾雨過長空。',32,'全唐诗/poet.song.242000.json','["暑夢蟲蟲似醉中，片雲挾雨過長空。", "不知秋色來多少，分數煖凉卜晚風。"]'),
('c1e9067e-2109-4781-a8e0-8065eff3fad9','都城初秋和趙京倅  其三','朱浚','宋','宋诗','song-poetry','','[]','宇宙清愁望眼中，誰將凉雨借龍公。',32,'全唐诗/poet.song.242000.json','["宇宙清愁望眼中，誰將凉雨借龍公。", "秋風夜入關河迥，破賊紅旗𥏌曉空。"]'),
('2bbe0975-d72c-472c-a34d-3eb2241e93e6','句  其一','朱浚','宋','宋诗','song-poetry','','[]','寺鐘城鼓兩相和，共醉烟關感慨多。',32,'全唐诗/poet.song.242000.json','["寺鐘城鼓兩相和，共醉烟關感慨多。", "堤柳垂金春幾許，檐花鳴玉夜如何。"]'),
('f5b1c1b9-57ee-446e-ae1a-bbe428ef5072','句  其二','朱浚','宋','宋诗','song-poetry','','[]','西風落葉長安夢，晚節寒華老圃心。',16,'全唐诗/poet.song.242000.json','["西風落葉長安夢，晚節寒華老圃心。"]'),
('ed47933e-720f-4610-8d15-e6c48a6f518a','句  其三','朱浚','宋','宋诗','song-poetry','','[]','玉帳分兵賦采薇，梅花吹雪上戎衣。',32,'全唐诗/poet.song.242000.json','["玉帳分兵賦采薇，梅花吹雪上戎衣。", "將軍意氣中江楫，丞相功名采石磯。"]'),
('52c47436-b944-44cc-8260-23566e7d7431','句  其四','朱浚','宋','宋诗','song-poetry','','[]','紅雲近處催班急，只待春前奏凱歸。',16,'全唐诗/poet.song.242000.json','["紅雲近處催班急，只待春前奏凱歸。"]'),
('18f8fd9c-e181-4b52-a0aa-354bf36db7a3','句  其五','朱浚','宋','宋诗','song-poetry','','[]','蓬萊春思重雲上，江漢秋情十載前。',16,'全唐诗/poet.song.242000.json','["蓬萊春思重雲上，江漢秋情十載前。"]'),
('d7d96c44-35c8-429e-ac66-a39471855c0d','句  其六','朱浚','宋','宋诗','song-poetry','','[]','金寒霜氣山無虎，劍動星光水有龍。',16,'全唐诗/poet.song.242000.json','["金寒霜氣山無虎，劍動星光水有龍。"]'),
('5dac0271-3b7d-48a4-a5d2-307bdf4734f9','句  其七','朱浚','宋','宋诗','song-poetry','','[]','皇帝當年第九春，宮符仍詔刻麒麟。',32,'全唐诗/poet.song.242000.json','["皇帝當年第九春，宮符仍詔刻麒麟。", "軍咨祭酒金臺客，國子先生鐵壁人。"]'),
('2b760487-120f-434a-93c5-b8a9c23f8072','句  其八','朱浚','宋','宋诗','song-poetry','','[]','明明采石兵前樣，參贊歸來即近臣。',16,'全唐诗/poet.song.242000.json','["明明采石兵前樣，參贊歸來即近臣。"]'),
('9fcf49d7-67a1-4f83-a899-38bd215154e5','句  其九','朱浚','宋','宋诗','song-poetry','','[]','落花水煖千船聚，芳草春深一鶴歸。',16,'全唐诗/poet.song.242000.json','["落花水煖千船聚，芳草春深一鶴歸。"]'),
('a698cd2e-9a80-4c81-8ad9-112820577850','句  其一○','朱浚','宋','宋诗','song-poetry','','[]','米車已過塵迷路，漁網纔收月滿船。',16,'全唐诗/poet.song.242000.json','["米車已過塵迷路，漁網纔收月滿船。"]'),
('9eae4558-6941-421c-aca4-ad4b2b5115d8','句  其一一','朱浚','宋','宋诗','song-poetry','','[]','海燕故人意，杜鵑游子心。',12,'全唐诗/poet.song.242000.json','["海燕故人意，杜鵑游子心。"]'),
('a421432b-ceb4-40be-9d94-74f0b412fb84','句  其一二','朱浚','宋','宋诗','song-poetry','','[]','故里千山隔，終年一字無。',12,'全唐诗/poet.song.242000.json','["故里千山隔，終年一字無。"]'),
('c815d459-e723-4e66-8c53-88ba16f34a8d','大茅峰','梁棟','宋','宋诗','song-poetry','','[]','杖藜絕頂窮追尋，青山世路爭嶇嶔。',144,'全唐诗/poet.song.242000.json','["杖藜絕頂窮追尋，青山世路爭嶇嶔。", "碧雲遮斷天外眼，春風吹老人間心。", "大龍上天寶劍化，小龍入海明珠沈。", "無人更守玄帝鼎，有客欲問秦皇金。", "顛崖誰念受辛苦，古洞未易潛幽深。", "神光不破黑暗惱，山鬼空學離騷吟。", "我來俛仰一慨慷，山川良昔人民今。", "安得長松撐日月，華陽世界收層陰。", "一聲長嘯下山去，草木爲我留清音。"]'),
('0d8674e3-52ac-4c5d-ac4d-3b01ec2f17b0','四禽言四首  其一','梁棟','宋','宋诗','song-poetry','','[]','不如歸去，錦官宮殿迷煙樹。',34,'全唐诗/poet.song.242000.json','["不如歸去，錦官宮殿迷煙樹。", "天津橋上一兩聲，叫破中原無住處。", "不如歸去。"]'),
('644074f6-b46e-4b60-9f49-2d5bd66b1cbb','四禽言四首  其二','梁棟','宋','宋诗','song-poetry','','[]','脫却布袴，貧家能有幾尺布。',34,'全唐诗/poet.song.242000.json','["脫却布袴，貧家能有幾尺布。", "織盡寒機無得裁，可人不來廉叔度。", "脫却布袴。"]'),
('76764b62-11a4-414c-bb7c-7997665b1a20','四禽言四首  其三','梁棟','宋','宋诗','song-poetry','','[]','行不得也哥哥，湖南湖北春水多。',38,'全唐诗/poet.song.242000.json','["行不得也哥哥，湖南湖北春水多。", "九嶷山前叫虞舜，柰此乾坤無路何。", "行不得也哥哥。"]'),
('d5c37bf5-90d0-4474-8c82-86b058c68217','四禽言四首  其四','梁棟','宋','宋诗','song-poetry','','[]','提葫蘆，年來酒賤頻頻沽。',32,'全唐诗/poet.song.242000.json','["提葫蘆，年來酒賤頻頻沽。", "衆人皆醉我亦醉，哀哉誰問醒三閭。", "提葫蘆。"]'),
('93b3249a-fc63-4999-8409-c875a258e7ca','金陵廢宮','梁棟','宋','宋诗','song-poetry','','[]','六代俄然又一唐，青山坐閲幾興亡。',64,'全唐诗/poet.song.242000.json','["六代俄然又一唐，青山坐閲幾興亡。", "心知江左非王業，口說中原是帝鄉。", "落日有時登北固，春風吹夢過錢塘。", "荆墳檜宅依然在，留與烏衣話短長。"]'),
('dd53d1aa-bc8b-4634-ab69-8301995bf209','鳳凰臺','梁棟','宋','宋诗','song-poetry','','[]','白髮久孤鸚鵡盃，碧梧自老鳳凰臺。',64,'全唐诗/poet.song.242000.json','["白髮久孤鸚鵡盃，碧梧自老鳳凰臺。", "管夷吾亦僅如許，李謫仙今安在哉。", "城郭是非秋雨外，江山形勝暮潮來。", "小留只等中秋月，且放青冥萬里開。"]'),
('9d9a93ec-9ef7-49c6-8661-2aa5df2bfe4e','白鷺亭','梁棟','宋','宋诗','song-poetry','','[]','荻花蘆葉老風煙，獨上秋城思渺然。',64,'全唐诗/poet.song.242000.json','["荻花蘆葉老風煙，獨上秋城思渺然。", "白鷺不知如許事，赤烏又隔幾何年。", "六朝往事秦淮水，一笛晚風江浦船。", "我輩人今竟誰許，只堪漁艇夕陽邊。"]'),
('7314bda9-5a7e-464c-8ead-cf701e7609fd','雨花臺','梁棟','宋','宋诗','song-poetry','','[]','孤雲落日倚西風，歷歷興亡望眼中。',64,'全唐诗/poet.song.242000.json','["孤雲落日倚西風，歷歷興亡望眼中。", "山入六朝青未了，江浮五馬恨無窮。", "客愁已付蒲萄綠，逕雨空餘瑪瑙紅。", "我亦欲談當世事，無人喚醒紫髯翁。"]'),
('c8174fc5-550d-46f7-9386-1e2d8510cf6a','題寅叔小園','梁棟','宋','宋诗','song-poetry','','[]','深巷渾無市井喧，主人有客便開樽。',64,'全唐诗/poet.song.242000.json','["深巷渾無市井喧，主人有客便開樽。", "數竿修竹三間屋，幾樹閒花一畝園。", "楚岫和雲移怪石，秦淮流月下高源。", "此身且比淵明樂，母在高堂子候門。"]'),
('abca68c5-3d3a-4cf6-8a58-1d826f68df25','久雨有感二首  其一','梁棟','宋','宋诗','song-poetry','','[]','冥雲生八荒，驟雨忽然至。',48,'全唐诗/poet.song.242000.json','["冥雲生八荒，驟雨忽然至。", "中宵揭屋破，漏溼無處避。", "牀牀不得乾，僵立見憔悴。", "嬌兒莫啼哭，少須待晴霽。"]'),
('11423b03-4ad5-4df5-bf2c-26d76007da7f','久雨有感二首  其二','梁棟','宋','宋诗','song-poetry','','[]','少年不學稼，老大生理拙。',48,'全唐诗/poet.song.242000.json','["少年不學稼，老大生理拙。", "入山採黄精，窮冬一尺雪。", "虎狼正縱橫，原野有白骨。", "傷心重傷心，吾饑何足恤。"]'),
('d9bcfae2-21c3-48c7-a476-d36e4a5f8e6d','贈嘉興徐同年','梁棟','宋','宋诗','song-poetry','','[]','憶昔青龍在戊辰，馬蹄同踏杏園春。',64,'全唐诗/poet.song.242000.json','["憶昔青龍在戊辰，馬蹄同踏杏園春。", "歸田令尹空書晉，執戟郎君盡美新。", "萬事不醒中酒聖，一貧無奈訟錢神。", "相逢莫效窮途泣，自古求仁要得仁。"]'),
('37ade074-3a4c-4b71-a216-5718aff15029','野水孤舟','梁棟','宋','宋诗','song-poetry','','[]','前村雨過溪流亂，行路迷漫都間斷。',64,'全唐诗/poet.song.242000.json','["前村雨過溪流亂，行路迷漫都間斷。", "孤洲盡日少人來，小舟繫在垂楊岸。", "主人空有濟川心，坐見門前水日深。", "袖手歸來茅屋下，任他鷗鳥自浮沈。"]'),
('5961ba3b-3abc-4ee8-96de-541a3b4ab586','黄葵','梁棟','宋','宋诗','song-poetry','','[]','乾坤有正氣，間色皆爲臣。',132,'全唐诗/poet.song.242000.json','["乾坤有正氣，間色皆爲臣。", "名葩據中央，紅紫誰敢鄰。", "傾日不忘君，衛足恐傷身。", "冥然無知識，忠孝出本真。", "林林天地間，戴履而爲人。", "明靈秀萬物，孰不尊君親。", "嗟嗟叔季後，利欲泯天倫。", "邈哉望帝國，産此瑞世珍。", "九夏不趨炎，三月不爭春。", "高秋風露冷，孤標出清塵。", "背時還獨立，攬芳淚沾巾。"]'),
('0d4d8138-9cce-4acb-bddd-951ed63ff259','金陵三遷有感','梁棟','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u5fe7\u56fd\u5fe7\u6c11", "\u58ee\u5fd7\u96be\u916c"]','憔悴城南短李紳，多情烏帽染黄塵。',64,'全唐诗/poet.song.242000.json','["憔悴城南短李紳，多情烏帽染黄塵。", "讀書不了平生事，閲世空存後死身。", "落日江山宜喚酒，西風天地正愁人。", "任他蜂蝶黄花老，明月園林是小春。"]'),
('05b1edd6-03e2-45bb-bb4e-18c4b9926f7f','淵明携酒圖','梁棟','宋','宋诗','song-poetry','','[]','淵明無心雲，纔出便歸岫。',96,'全唐诗/poet.song.242000.json','["淵明無心雲，纔出便歸岫。", "東臯半頃秫，所種不常有。", "苦恨無酒錢，閒却持盃手。", "今朝有一壺，携之訪親友。", "惜無好事人，能消幾壺酒。", "區區謀一醉，豈望名不朽。", "閒吟籬下菊，自傳門前柳。", "試問劉寄奴，還識此人不。"]'),
('8db1e301-fc82-43e8-aeda-2bad48486350','春日郊遊和友人韻','梁棟','宋','宋诗','song-poetry','','[]','憶昔東風御柳斜，枯腸一日萬周車。',64,'全唐诗/poet.song.242000.json','["憶昔東風御柳斜，枯腸一日萬周車。", "壯心難起泥中絮，老眼羞看霧裏花。", "巷陌幾家無主燕，池塘一種爲官蛙。", "江南寒食無煙火，白晝沈沈似月華。"]'),
('6d2e3f42-f4d7-445f-8bea-17619df92bcb','登鎮海樓聞角聲賦','梁棟','宋','宋诗','song-poetry','','[]','聽徹哀吟獨倚樓，碧天無際思悠悠。',32,'全唐诗/poet.song.242000.json','["聽徹哀吟獨倚樓，碧天無際思悠悠。", "誰知盡是中原恨，吹到東南第一州。"]'),
('37117f1b-949d-4a42-a8e5-48e1b3ed6717','送李北山歸建康  其一','梁棟','宋','宋诗','song-poetry','','[]','人生無百年，胡爲在遠道。',36,'全唐诗/poet.song.242000.json','["人生無百年，胡爲在遠道。", "遊子悲故鄉，王孫怨芳草。", "有田歸去來，無田歸亦好。"]'),
('1841d93d-a854-4c41-9da9-be850f0338b9','送李北山歸建康  其二','梁棟','宋','宋诗','song-poetry','','[]','貧賤有餓死，富貴履危機。',36,'全唐诗/poet.song.242000.json','["貧賤有餓死，富貴履危機。", "東海不可漁，西山采無薇。", "四方已一氣，我今將安歸。"]'),
('fcca77d3-4a72-4983-9f05-ce3118f6c2f8','哀毘陵','梁棟','宋','宋诗','song-poetry','','[]','荆溪水腥泊船早，落日無人行古道。',144,'全唐诗/poet.song.242000.json','["荆溪水腥泊船早，落日無人行古道。", "髑髏有眼不識春，東風吹出青青草。", "荒基猶認是人家，敗柵曾將當城堡。", "當時壓境兵百萬，不脫靴尖堪蹴倒。", "短兵相接逾四旬，毒手尊拳日攻討。", "內儲外援兩消沈，一縷人心堅自保。", "孤臣守土輕性命，赤子效死塗肝腦。", "朝廷有爵愧降附，幽壤無恩澤枯槁。", "願箋司命錄英雄，收拾忠魂畀穹昊。"]'),
('57d66c55-8d3e-43e5-ade6-6c422f3375a7','送存書記','梁棟','宋','宋诗','song-poetry','','[]','一聲兩聲松子落，一片兩片楓葉飛。',32,'全唐诗/poet.song.242000.json','["一聲兩聲松子落，一片兩片楓葉飛。", "夕陽在山新月上，道人相伴一僧歸。"]'),
('22aa16e1-59e9-4157-901b-7a196afe5d2d','題葉東叔賓月堂','梁棟','宋','宋诗','song-poetry','','[]','人生自是人間客，月亦天邊寄此身。',32,'全唐诗/poet.song.242000.json','["人生自是人間客，月亦天邊寄此身。", "彼此虛空無著處，誰歟是主復誰賓。"]'),
('809bafae-fd9a-4a5c-b488-2a4c06b6f57d','謁御史張月卿','梁棟','宋','宋诗','song-poetry','','[]','我家元住君鄰州，我父當時亦故侯。',64,'全唐诗/poet.song.242000.json','["我家元住君鄰州，我父當時亦故侯。", "中原百年龍戰野，南濱一日鰲吞鈎。", "遺黎常恨舊隔絕，故鄉喜遇新交遊。", "路人行行望驄馬，山中却爲詩淹留。"]'),
('f2b28768-f4e3-4ccc-abbd-e8dcd63d4200','賦蔬','梁棟','宋','宋诗','song-poetry','','[]','家貧忽暴富，菜種二十七。',36,'全唐诗/poet.song.242000.json','["家貧忽暴富，菜種二十七。", "癡兒不解事，問我何從得。", "于義苟有違，吾寧饑不食。"]'),
('84667abb-c6b3-4ac6-88e8-5a92640f1a9a','雨花臺','梁棟','宋','宋诗','song-poetry','','[]','春中景物尚凄然，小立崇臺古樹邊。',64,'全唐诗/poet.song.242000.json','["春中景物尚凄然，小立崇臺古樹邊。", "潮信不嫌城寂寞，山光似與客留連。", "英雄馬鬣無餘地，氣勢龍蟠得幾年。", "眼底興亡總閑事，不如有酒醉花前。"]'),
('085a38a9-a0ef-4a40-97f1-f7ae8a7f8973','謝氏梅園','梁棟','宋','宋诗','song-poetry','','[]','纖腰凍欲折，來探前村雪。',24,'全唐诗/poet.song.242000.json','["纖腰凍欲折，來探前村雪。", "幽禽莫相猜，歲寒心似鐵。"]'),
('9b319255-172a-4611-bc6d-ed5a7c18fdbf','多景樓','梁棟','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','思歸不覺歲華侵，倦撫旌旗感慨深。',64,'全唐诗/poet.song.242000.json','["思歸不覺歲華侵，倦撫旌旗感慨深。", "舊日家鄉今日客，一年時序百年心。", "城餘故址元非鐵，山得虛名不是金。", "檻外長江成底事，英雄對酒話蹄涔。"]'),
('44b9bf11-63ee-4842-9865-aedc37c22b19','句  其一','梁棟','宋','宋诗','song-poetry','','[]','浮雲暗不見青天。',8,'全唐诗/poet.song.242000.json','["浮雲暗不見青天。"]'),
('133cde00-ea1c-4180-a605-7ea1506cc6dc','句  其二','梁棟','宋','宋诗','song-poetry','','[]','千株守紅死，一點反魂歸。',12,'全唐诗/poet.song.242000.json','["千株守紅死，一點反魂歸。"]'),
('e2b21f43-66bd-46fb-8dc7-67f3c33e28b3','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其一','戴表元','宋','宋诗','song-poetry','','[]','美人乘天風，手吹玉參差。',60,'全唐诗/poet.song.242000.json','["美人乘天風，手吹玉參差。", "我有龍門桐，綴之冰蠶絲。", "空中一偈答，聞者爲忘機。", "神馬已出河，鳳皇且鳴岐。", "悠悠百年內，儻有相逢時。"]'),
('0d5c58b4-1099-4bc1-ba1c-098c6ce18b3d','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其二','戴表元','宋','宋诗','song-poetry','','[]','我登海山巔，群丘眇如芥。',24,'全唐诗/poet.song.242000.json','["我登海山巔，群丘眇如芥。", "客來談九州，更詰誰小大。"]'),
('86c99959-771c-4618-8b3f-119df3ffd764','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其三','戴表元','宋','宋诗','song-poetry','','[]','神疲穆滿馭，足繭神始載。',24,'全唐诗/poet.song.242000.json','["神疲穆滿馭，足繭神始載。", "終然方寸心，擾擾軀殻外。"]'),
('4ffe276c-28f5-4d19-880f-58b6654a3193','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其四','戴表元','宋','宋诗','song-poetry','','[]','流光如急水，一去難復再。',24,'全唐诗/poet.song.242000.json','["流光如急水，一去難復再。", "歸來坐虛室，始覺身安泰。"]'),
('7606a5b0-5cc5-41cc-9733-88cb48b8e355','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其五','戴表元','宋','宋诗','song-poetry','','[]','老馬寧爲駒，即且或甘带。',24,'全唐诗/poet.song.242000.json','["老馬寧爲駒，即且或甘带。", "名跡吾不嫌，全生聊遠害。"]'),
('b721fd74-a705-4993-bcde-913c3d0573e0','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其六','戴表元','宋','宋诗','song-poetry','','[]','明有不見睫，智有不衛足。',24,'全唐诗/poet.song.242000.json','["明有不見睫，智有不衛足。", "學靜三十年，晚始悟無欲。"]'),
('cf0150d9-50d8-408f-b538-3a38546cc092','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其七','戴表元','宋','宋诗','song-poetry','','[]','履卑懼名高，居群忌行獨。',24,'全唐诗/poet.song.242000.json','["履卑懼名高，居群忌行獨。", "不見歌鍾家，白日卧金谷。"]'),
('59265e03-af22-482d-80c0-64758ac0fc56','大名元復初郎中携示感遇五言八章次韻并陳東平曹子貞編修薊丘曹克明  其八','戴表元','宋','宋诗','song-poetry','','[]','不見带索生，行吟扣哀竹。',24,'全唐诗/poet.song.242000.json','["不見带索生，行吟扣哀竹。", "爲君慎燕息，顧兔方在腹。"]'),
('3e2a676f-6854-405e-8a93-fa36d9ab5e9a','東陽方韶卿惠古意七篇久不得和五月二十六日將假館宗陽橋稍有閒暇乃爲次韻因寄訊彼中吳子善前輩  其一','戴表元','宋','宋诗','song-poetry','','[]','長歲狎紛諠，新廬稍疏靜。',48,'全唐诗/poet.song.242000.json','["長歲狎紛諠，新廬稍疏靜。", "虛名亦相累，簪珮來整整。", "青天戍樓柳，白日仙林杏。", "散書一長謠，消此清夏永。"]'),
('bc39c691-4823-497a-8f00-553d27ec5386','東陽方韶卿惠古意七篇久不得和五月二十六日將假館宗陽橋稍有閒暇乃爲次韻因寄訊彼中吳子善前輩  其二','戴表元','宋','宋诗','song-poetry','','[]','營營寄巢蜂，白晝爭空花。',48,'全唐诗/poet.song.242000.json','["營營寄巢蜂，白晝爭空花。", "跋跋緣壁蟲，喧飛亂如麻。", "譬如惡俗士，便不揮鞭撾。", "桐君何處來，隔壁聞瓠巴。"]'),
('04c28d16-1bbf-4101-93e0-bcb6fcd4c84f','東陽方韶卿惠古意七篇久不得和五月二十六日將假館宗陽橋稍有閒暇乃爲次韻因寄訊彼中吳子善前輩  其三','戴表元','宋','宋诗','song-poetry','','[]','舊文空中雲，零落跡易消。',48,'全唐诗/poet.song.242000.json','["舊文空中雲，零落跡易消。", "新交江上流，來去同奔潮。", "藹藹玄英孫，望之十舍遥。", "願爾多黍稌，相投共簞瓢。"]'),
('7f4eef1a-111f-489b-b642-6b52ce136eae','東陽方韶卿惠古意七篇久不得和五月二十六日將假館宗陽橋稍有閒暇乃爲次韻因寄訊彼中吳子善前輩  其四','戴表元','宋','宋诗','song-poetry','','[]','人膽小於壺，揣想無限極。',48,'全唐诗/poet.song.242000.json','["人膽小於壺，揣想無限極。", "及其遂所願，不過一消息。", "金華文物府，前哲餘楷則。", "千年萬年名，豈使夸者得。"]'),
('4f120790-263c-4d17-8474-ffb4f2e54fdf','東陽方韶卿惠古意七篇久不得和五月二十六日將假館宗陽橋稍有閒暇乃爲次韻因寄訊彼中吳子善前輩  其五','戴表元','宋','宋诗','song-poetry','','[]','作詩如挽船，學力乃篙櫓。',48,'全唐诗/poet.song.242000.json','["作詩如挽船，學力乃篙櫓。", "向來牛耳盟，諸老肯多許。", "玄暉雲樹荒，仲宣江海阻。", "之子歸未歸，相思慰風雨。"]'),
('602b1d07-910b-4542-a2a9-d8ad7630e700','東陽方韶卿惠古意七篇久不得和五月二十六日將假館宗陽橋稍有閒暇乃爲次韻因寄訊彼中吳子善前輩  其六','戴表元','宋','宋诗','song-poetry','','[]','德孤誰願高，氣寒誰願清。',48,'全唐诗/poet.song.242000.json','["德孤誰願高，氣寒誰願清。", "斯文鄒魯來，壈坎勞其生。", "豈無性命憂，艱難愈同情。", "如何及門士，亦作胡越聲。"]'),
('2e910be3-706b-47cc-b1ee-678783a66824','東陽方韶卿惠古意七篇久不得和五月二十六日將假館宗陽橋稍有閒暇乃爲次韻因寄訊彼中吳子善前輩  其七','戴表元','宋','宋诗','song-poetry','','[]','永康經濟學，近古將無同。',48,'全唐诗/poet.song.242000.json','["永康經濟學，近古將無同。", "甥孫世其業，汗馬收全功。", "我欲攬遺跡，雙眸冰鏡空。", "君亦跨黄鵠，吹簫白雲中。"]'),
('fcbf79a5-2a27-4570-b8f7-8f76c7bbf3d5','韓君美經歷賦孟夏木長五詩示僕因寫鄙懷通呈阮使君','戴表元','宋','宋诗','song-poetry','','[]','吾評陶淵明，略似段干木。',60,'全唐诗/poet.song.242000.json','["吾評陶淵明，略似段干木。", "詩文雖滿家，不飽妻子腹。", "仰瞻清風柯，俯窺白雲谷。", "誰能爲升斗，辛苦受羈束。", "因君寄高韻，千古動遐矚。"]'),
('f8b8dba1-d1f1-4988-9709-f7890909732d','以羔裘如濡洵美且侯韻爲八詩送夾谷子括赴明州推官  其一','戴表元','宋','宋诗','song-poetry','','[]','鑑虛磨愈明，絃柔調自直。',48,'全唐诗/poet.song.242000.json','["鑑虛磨愈明，絃柔調自直。", "臨民要儒術，非但用三尺。", "君看春秋學，從士能斷國。", "人情豈相遠，贈子以不惑。"]'),
('29d0b6ef-0a83-4b38-8999-d3fe78f5299a','以羔裘如濡洵美且侯韻爲八詩送夾谷子括赴明州推官  其二','戴表元','宋','宋诗','song-poetry','','[]','水耕當用牛，陸行當用馬。',48,'全唐诗/poet.song.242000.json','["水耕當用牛，陸行當用馬。", "詩書無近功，平世安可捨。", "吾州兵荒來，冠蓋多苟且。", "寧無段干木，意氣能少下。"]'),
('b025c37c-927a-4cd3-bd94-7cc4ba58a31b','送袁季源之婺州因簡范經歷','戴表元','宋','宋诗','song-poetry','','[]','爲山不願高，爲水不願深。',279,'全唐诗/poet.song.242000.json','["爲山不願高，爲水不願深。", "水深蛟龍集，山高虎豹蹲。", "我有避人法，終日衣冠林。", "煌煌錢塘城，游塵晝爲陰。", "豈無青雲交，難在相知心。", "豈弟袁大夫，寒窗理閑琴。", "峻坂爲牛力，炎天九秋襟。", "膠漆四十年，齠齔以至今。", "天欲饑餓我，使子無黄金。", "勸仕拙不諧，驅耕弱難任。", "低回向誰門，後生氣駸駸。", "今晨積潦霽，烏烏有好音。", "約我共行役，東平步嶔嶔。", "皎皎婺女精，瀰瀰雙溪潯。", "臺有白馬生，風稜共蕭森。", "文林惜妄動，動必向所欽。", "吾評古毛義，志行近騫參。", "公府許辟召，屈身非祿淫。", "斯人我知舊，長髯善{口吳}吟。", "穴蟻夢離合，風花命浮沉。", "往者納千贄，終然遺一簪。", "欲行又不得，出門失前禽。", "子往再拜問，何由振聾喑。"]'),
('a554270b-b810-4bed-a2ad-428d6d3e4a85','次韻答朱侯招遊海山','戴表元','宋','宋诗','song-poetry','','[]','江南春草黄，江北秋雁飛。',192,'全唐诗/poet.song.242000.json','["江南春草黄，江北秋雁飛。", "窮居念還往，故物悉已非。", "我有青雲交，山林可同歸。", "十年學撫琴，對客輒累欷。", "豈不願和悅，調苦心易爲。", "青天無古今，白日相因依。", "向來炎炎人，所得一何微。", "成者化埃塵，不成翻禍機。", "玉美受雕鎸，馬良遭絆鞿。", "所以曠達士，但貴知我希。", "請休接輿歌，且急梁鴻噫。", "名微少士責，身閒免官譏。", "寧無一日力，相尋盡崎嶇。", "霜魚碧玉鱠，水菊黄金輝。", "君歌我按筑，我舞君攬衣。", "此日爲君歡，醉遊敞船扉。"]'),
('9e17d762-cb3a-4d53-8cc1-0013357c2f39','題陳高士所藏冬青枝上白頭翁畫','戴表元','宋','宋诗','song-poetry','','[]','飛高得珍叢，青子饑可食。',48,'全唐诗/poet.song.242000.json','["飛高得珍叢，青子饑可食。", "不知何憂愁，二鳥頭亦白。", "道人天機深，清齋意相許。", "頼汝不能鳴，一鳴嫌殺汝。"]'),
('ed4dd8fa-8b19-49bb-aa82-d8871ecbff88','以空飛本無迹韻爲五詩往扣廣微張公','戴表元','宋','宋诗','song-poetry','','[]','智有不近名，賢有不踐迹。',48,'全唐诗/poet.song.242000.json','["智有不近名，賢有不踐迹。", "百年如飄風，誰作遠行客。", "所要在持久，以道自消息。", "吾師豈欺我，白首方學易。"]'),
('259dfbbe-542d-49d7-a60a-5a3f8cf04637','浴蠶沙溪水一首爲上饒陳烈婦作','戴表元','宋','宋诗','song-poetry','','[]','浴蠶沙溪水，採桑玉山巔。',132,'全唐诗/poet.song.242000.json','["浴蠶沙溪水，採桑玉山巔。", "絲成白稜稜，膠作烈婦絃。", "烈婦何所言，絃中意纏綿。", "一說鸞影孤，二訴雛巢穿。", "巢穿尚可葺，影孤恨終天。", "有食不自肥，衆禽仰喉咽。", "真宰憫其疲，勞役盡弛蠲。", "及今雛長成，雛群亦蹁躚。", "朝陽照岩林，枯槁生光妍。", "黄蘗誰謂苦，鐵石誰謂堅。", "請君屏俗耳，聽我沙溪篇。"]'),
('6cb8c940-90ec-48e1-8d01-bb86672cc2da','書歎七首  其一','戴表元','宋','宋诗','song-poetry','','[]','王生困縲紲，劉子急徵追。',60,'全唐诗/poet.song.242000.json','["王生困縲紲，劉子急徵追。", "舒叟挈家走，幾遭鞭與笞。", "我無三人辱，闔門但窮饑。", "飽死世更多，徒憂何以爲。", "敢作小夫歎，聊爲才士悲。"]'),
('d3b2babb-b87c-469d-94ec-31c7d4bdc8fc','書歎七首  其二','戴表元','宋','宋诗','song-poetry','','[]','舒子高品藻，王生怪衣冠。',60,'全唐诗/poet.song.242000.json','["舒子高品藻，王生怪衣冠。", "處世那得爾，譊譊真自殘。", "劉子最多愛，逢人傾肺肝。", "勸我學其道，縮身可泥蟠。", "胡爲亦不免，念此坐長歎。"]'),
('d9ab7ce9-2f05-4e96-86f4-a1c18c9bba24','書歎七首  其三','戴表元','宋','宋诗','song-poetry','','[]','英英天上星，碌碌澗中石。',60,'全唐诗/poet.song.242000.json','["英英天上星，碌碌澗中石。", "升沉雖不同，精爽或相激。", "我有知名文，四海邯鄲壁。", "遭逢不自閟，頗爲談者惜。", "談者自不知，斯人寧易得。"]'),
('d7ea3677-71fe-4e2c-a1d2-053300c722a6','書歎七首  其四','戴表元','宋','宋诗','song-poetry','','[]','袁弟豁達人，陳兄靜默士。',60,'全唐诗/poet.song.242000.json','["袁弟豁達人，陳兄靜默士。", "平生少附麗，頗與同憂喜。", "邇來怪事發，談笑不可擬。", "一爲脫淵魚，一爲墜柯蟻。", "吁嗟其奈何，天運固如此。"]'),
('6ce1614b-f302-425f-8303-9f2ae739cd21','書歎七首  其五','戴表元','宋','宋诗','song-poetry','','[]','數友越州居，無書已三年。',60,'全唐诗/poet.song.242000.json','["數友越州居，無書已三年。", "台州已無數，逢人每相賢。", "日夜憶遠友，遠者隔蠻烟。", "風氣不擇州，俗情輕目前。", "管鮑死何處，寄酒灑其阡。"]'),
('37f16ea3-65ef-4dde-9c39-6fd7d9960154','書歎七首  其六','戴表元','宋','宋诗','song-poetry','','[]','結友何用多，管鮑無三人。',60,'全唐诗/poet.song.242000.json','["結友何用多，管鮑無三人。", "讀書何用博，得少全其身。", "君有狥名子，擾擾起風塵。", "朝逐富兒餐，暮聯豪士茵。", "歸來反如客，魚鳥亦相嗔。"]'),
('55cd6164-5d7a-4148-ab0e-e6428589d0fe','書歎七首  其七','戴表元','宋','宋诗','song-poetry','','[]','蘇州米空熟，越州人不來。',60,'全唐诗/poet.song.242000.json','["蘇州米空熟，越州人不來。", "緩急托遠婚，不如傍蒿萊。", "蒿萊在籬落，爲我障浮埃。", "生女屬他人，生男尚嬰孩。", "從何得饘粥，作此聊自咍。"]'),
('e2977097-86ea-45aa-9a3e-889a58e35c77','觀村中禱雨三首  其一','戴表元','宋','宋诗','song-poetry','','[]','十里不同雲，五里不同雨。',72,'全唐诗/poet.song.242000.json','["十里不同雲，五里不同雨。", "天公白茫茫，乃爾多肺腑。", "人言蛟龍神，象類可以取。", "蛇蟲當此時，行路誰敢侮。", "飛騰信有術，忍待號者苦。", "咄哉神禹功，浩蕩流萬古。"]'),
('89149414-20d9-4cf8-8f5e-9bdf0867686f','觀村中禱雨三首  其二','戴表元','宋','宋诗','song-poetry','','[]','昨日苗穗赤，今朝灑然青。',72,'全唐诗/poet.song.242000.json','["昨日苗穗赤，今朝灑然青。", "頗知窮旅人，百金換顔形。", "念爾雖微根，同稟造化靈。", "自古有枯旱，人類幾千齡。", "恐是自生化，難皆問蒼冥。", "野草人不憐，何獨不凋零。"]'),
('ba6cc35c-454c-4cc9-8d18-c4ce1220d5f9','觀村中禱雨三首  其三','戴表元','宋','宋诗','song-poetry','','[]','西村送龍歸，東村請龍出。',72,'全唐诗/poet.song.242000.json','["西村送龍歸，東村請龍出。", "西村雨綿綿，東村猶出日。", "共稱西人良，或是窮可恤。", "誰知所雨粟，盡入東村室。", "儒生無愛憎，但喜蔬蓏實。", "通年一飽厨，猶在兔園帙。"]'),
('78d365b8-497e-4014-a2d6-be5bc9af4fea','山中玩物雜言十首  其一','戴表元','宋','宋诗','song-poetry','','[]','時露下百草，流螢此飛翻。',48,'全唐诗/poet.song.242000.json','["時露下百草，流螢此飛翻。", "初如灰燼微，忽作秋星繁。", "念彼生育處，回光照其根。", "君莫輕流螢，流螢尚知恩。"]'),
('0abf3ae0-a8db-4090-947d-b4ac4b87eb34','山中玩物雜言十首  其二','戴表元','宋','宋诗','song-poetry','','[]','青橘霜露時，英英秀中園。',48,'全唐诗/poet.song.242000.json','["青橘霜露時，英英秀中園。", "問訊訊居人，今歲胡不蕃。", "云有孤兒來，手觸枝上丸。", "嗚呼此義木，痛感在吾言。"]'),
('f21ea9a3-1c6d-4df7-bafb-4121c2d38b8f','山中玩物雜言十首  其三','戴表元','宋','宋诗','song-poetry','','[]','野果散高林，雀鼠食之宜。',48,'全唐诗/poet.song.242000.json','["野果散高林，雀鼠食之宜。", "設非人所殘，一顆不敢窺。", "寧由網罻防，亦無神物司。", "食道固當爾，雀鼠猶有知。"]'),
('f99d3845-7f56-43f4-98e5-b69a4885ce73','山中玩物雜言十首  其四','戴表元','宋','宋诗','song-poetry','','[]','見狗須不走，見蛇須拱手。',48,'全唐诗/poet.song.242000.json','["見狗須不走，見蛇須拱手。", "不走爾非偷，拱手亦相厚。", "無欺物自信，能勝誰肯負。", "不見吳山虎，郭文探其口。"]'),
('0f2320a5-688b-48fe-bd8e-1323ea0b7ac8','山中玩物雜言十首  其五','戴表元','宋','宋诗','song-poetry','','[]','鳥有反舌者，自古比讒人。',48,'全唐诗/poet.song.242000.json','["鳥有反舌者，自古比讒人。", "時氣一朝遷，此舌竟不伸。", "衆鳥莫不然，更鳴以存身。", "如何能言士，聒聒無止辰。"]'),
('d67ed738-b17d-483c-aa39-350b49bc1591','山中玩物雜言十首  其六','戴表元','宋','宋诗','song-poetry','','[]','犂牛有土德，體厚靜綏綏。',48,'全唐诗/poet.song.242000.json','["犂牛有土德，體厚靜綏綏。", "豈無牝牡情，不自求其雌。", "終朝草棧間，若忘渴與饑。", "嗟彼位兒高，乃爾難自持。"]'),
('426a6191-3ec3-4e6d-a110-3c39fbeae717','山中玩物雜言十首  其七','戴表元','宋','宋诗','song-poetry','','[]','精衛勇填海，鶡旦苦求明。',48,'全唐诗/poet.song.242000.json','["精衛勇填海，鶡旦苦求明。", "明尚可得求，填海何時成。", "我觀飛鳴族，一一各有營。", "但爲口腹謀，遂爾遺其名。"]'),
('2be61462-95f2-4cbe-98d5-7e7f9b9d27e3','山中玩物雜言十首  其八','戴表元','宋','宋诗','song-poetry','','[]','燕是孝義鳥，常棲孝義家。',48,'全唐诗/poet.song.242000.json','["燕是孝義鳥，常棲孝義家。", "堂簷白日暖，上下靜無譁。", "以此托軀羽，禍福審不差。", "誰云知數歷，俗士義之夸。"]'),
('eabb1d15-999b-48c6-b2ff-5751f5bb3ab8','山中玩物雜言十首  其九','戴表元','宋','宋诗','song-poetry','','[]','圃人憂孽蟲，爲蔬畜雞雛。',48,'全唐诗/poet.song.242000.json','["圃人憂孽蟲，爲蔬畜雞雛。", "小雞擇蟲啄，大雞遂啄蔬。", "蟲去蔬亦盡，對之可欷歔。", "昂昂高冠幘，反不小雞如。"]'),
('45e2dd7f-c637-4912-b9d3-7c938e14cae5','山中玩物雜言十首  其一○','戴表元','宋','宋诗','song-poetry','','[]','蚯蚓食土壤，蚩蚩何所爲。',48,'全唐诗/poet.song.242000.json','["蚯蚓食土壤，蚩蚩何所爲。", "蜩蟬飲風露，蛻上高高枝。", "卑者慕其仙，飄颻安可追。", "倘令智相及，無羨亦無悲。"]'),
('276ef156-d435-46e7-a3fd-a7bde634e2dc','自居剡源少遇樂歲辛巳之秋山田可擬上熟吾貧庶幾得少安乎乃和淵明貧士七首與鄰人歌而樂之  其一','戴表元','宋','宋诗','song-poetry','','[]','貧賤如故舊，少壯即相依。',72,'全唐诗/poet.song.242000.json','["貧賤如故舊，少壯即相依。", "中心不敢厭，但覺少光輝。", "向來乘時士，亦有能奮飛。", "一朝權勢歇，欲退無所歸。", "不如行其素，辛苦耐寒饑。", "人生係天運，何用發深悲。"]'),
('326f3e9e-4797-4003-9a20-751edd168291','自居剡源少遇樂歲辛巳之秋山田可擬上熟吾貧庶幾得少安乎乃和淵明貧士七首與鄰人歌而樂之  其二','戴表元','宋','宋诗','song-poetry','','[]','我居在窮巷，來往無華軒。',72,'全唐诗/poet.song.242000.json','["我居在窮巷，來往無華軒。", "辛勤衣食物，出此二畝園。", "薤菘鬰朝露，桑柘浮春烟。", "以茲亂心曲，智計無他妍。", "擇勝不在奢，興至發清言。", "相逢樵牧徒，混混誰愚賢。"]'),
('561e89a9-6e9a-411e-8375-49eb41906ae2','自居剡源少遇樂歲辛巳之秋山田可擬上熟吾貧庶幾得少安乎乃和淵明貧士七首與鄰人歌而樂之  其三','戴表元','宋','宋诗','song-poetry','','[]','松風四山來，清宵響瑶琴。',72,'全唐诗/poet.song.242000.json','["松風四山來，清宵響瑶琴。", "聽之不能寐，中有怨歎音。", "旦起繞其樹，磈砢不計尋。", "清音可敷席，有酒誰與斟。", "由來大度士，不受流俗侵。", "浩歌相倡答，慰此雪霜心。"]'),
('296f1f5f-aaaa-42a9-adcc-baa990c1908e','自居剡源少遇樂歲辛巳之秋山田可擬上熟吾貧庶幾得少安乎乃和淵明貧士七首與鄰人歌而樂之  其四','戴表元','宋','宋诗','song-poetry','','[]','中年涉事熟，欲學唾面婁。',72,'全唐诗/poet.song.242000.json','["中年涉事熟，欲學唾面婁。", "逡巡避少年，起穢不敢酬。", "旁人吁已甚，自喜計慮周。", "微勞消厚疚，淺辱勝深憂。", "從知爲下安，處上反無儔。", "人生各有志，勇懦從所求。"]'),
('76f7225f-c131-463a-9084-675afb9f4f9c','自居剡源少遇樂歲辛巳之秋山田可擬上熟吾貧庶幾得少安乎乃和淵明貧士七首與鄰人歌而樂之  其五','戴表元','宋','宋诗','song-poetry','','[]','古人重畎畝，有祿不待干。',72,'全唐诗/poet.song.242000.json','["古人重畎畝，有祿不待干。", "德成祿自至，釋耒列王官。", "不仕亦不貧，本自足饔餐。", "後世恥躬耕，號呼脫饑寒。", "我生千禩後，念此愧在顔。", "爲農倘可飽，何用出柴關。"]'),
('0bad93c8-3713-4be7-93a8-cf94b3304c32','自居剡源少遇樂歲辛巳之秋山田可擬上熟吾貧庶幾得少安乎乃和淵明貧士七首與鄰人歌而樂之  其六','戴表元','宋','宋诗','song-poetry','','[]','村郊多父老，面垢頭如蓬。',72,'全唐诗/poet.song.242000.json','["村郊多父老，面垢頭如蓬。", "我嘗使之言，辭語不待工。", "古來名節士，敢望彭城龔。", "有叟誚其後，更恨道不同。", "鄙哉譊譊者，爲隘不爲通。", "低頭拜野老，負耒吾願從。"]'),
('87fbe825-f8a0-4927-a29e-67de22788fa4','自居剡源少遇樂歲辛巳之秋山田可擬上熟吾貧庶幾得少安乎乃和淵明貧士七首與鄰人歌而樂之  其七','戴表元','宋','宋诗','song-poetry','','[]','去年秋事荒，販糴仰鄰州。',72,'全唐诗/poet.song.242000.json','["去年秋事荒，販糴仰鄰州。", "健者道路間，什伯成朋儔。", "今年漸向熟，庶幾民不流。", "書生自無田，與衆同喜憂。", "作詩勞鄰曲，有唱誰與酬。", "亦無採詩者，此職何可修。"]'),
('2333dd76-9898-4523-841d-1141808d6ac5','丁氏厚德堂','戴表元','宋','宋诗','song-poetry','','[]','賤士懷永憂，一物常恐枯。',132,'全唐诗/poet.song.242000.json','["賤士懷永憂，一物常恐枯。", "貴者止營私，智或遺妻孥。", "肉食從古鄙，黄金使人愚。", "我游四十年，錢塘車馬區。", "但見插桃李，誰曾種桑榆。", "白頭識丁子，儀冠儼于于。", "示我厚德編，嘉名在塘隅。", "談之爲踊躍，喜氣生眉鬚。", "願子富倉庾，人人飽餐餔。", "願子多酒漿，日日開樽壺。", "行藏自有命，不謁守錢奴。"]'),
('e0f43952-5aa5-4e0c-a844-ac51c0b0bdf7','排律十七韻賀阮侯伯子','戴表元','宋','宋诗','song-poetry','','[]','芳城春樹晚，清海月弦初。',204,'全唐诗/poet.song.242000.json','["芳城春樹晚，清海月弦初。", "瑞出三神島，光纏五馬車。", "眼中新鸑鷟，膝下小璠璵。", "錦褓看爭羨，犀顱畫不如。", "試啼賓錯愕，獻夢媼勤渠。", "庭舞張公鶴，門填孔氏魚。", "一時官府慶，數世甲科儲。", "聞說衣冠里，高增棨戟閭。", "民隨阮公姓，鄰禁宛溪魚。", "東去龜浮印，南遊雉繞車。", "陰移棠芾芾，騎擁竹舒舒。", "政有兒童戀，謠聽父老餘。", "攢眉詢賦額，正色署刑書。", "暗室天如鏡，心田老自畬。", "看騎金腰褭，待弄玉蟾蜍。", "我欲歌三賈，誰能說兩徐。", "先隨湯餠祝，聊當賀錢醵。"]'),
('e5e09d8e-ea46-4a69-9211-993adaacc4ac','傍家東北有山曰紹地余幸得之規以爲素莊也','戴表元','宋','宋诗','song-poetry','','[]','紹地吾所欣，他時以藏我。',108,'全唐诗/poet.song.242000.json','["紹地吾所欣，他時以藏我。", "岡原見逾美，松柏栽已夥。", "雙流交在右，一几平連左。", "憶昔初經營，登高忘蹩跛。", "年衰已漸怯，步暫石頻坐。", "居然契券叶，偶爾龜策可。", "心手之勤勞，軀骸庶安妥。", "况復近芳茨，時能薦蔬果。", "雖無劉伶鍾，略慕王孫躶。"]'),
('6978ef6d-a572-4752-9db8-fd0f4beff209','謝陳君祥憲使','戴表元','宋','宋诗','song-poetry','','[]','鸞凰不鷙暴，珪璧無鋒銛。',288,'全唐诗/poet.song.242000.json','["鸞凰不鷙暴，珪璧無鋒銛。", "評材容一切，未覺世論嚴。", "僕昔江東歸，二紀操鋤鐮。", "聞山但廬霍，慕水惟沱潜。", "宮車歲千兩，未省謁帷幨。", "豈無趙張倫，居突不得黔。", "新年有吉語，所在興循廉。", "惟此沮洳氓，生涯嗇而纖。", "廛管疲負挈，陸取困塗霑。", "赫赫金鋪門，風雨今無簷。", "皎皎華裾生，塵土今無襜。", "分臺得陳侯，笑語脫烹爓。", "仁賢所居國，不言革頑憸。", "侯家仲舉峻，何如太丘謙。", "問侯何所爲，深坐靜春簾。", "問侯何所學，凈几飄風籤。", "儼雅菑川公，高節齊晉瞻。", "橫流滔天來，挺身卧西崦。", "何以贈陳侯，孟光書滿奩。", "名曰事言補，其辭清以恬。", "豈但資稗官，五經之韜鈐。", "從來名世士，必有淵源漸。", "侯識民蓍龜，侯材國梅鹽。", "誠令以德舉，遐陬詎能淹。"]'),
('0cf0e82b-a61e-44a9-8257-debe80b88d06','和陶乞食','戴表元','宋','宋诗','song-poetry','','[]','今朝胡不樂，取書一哦之。',84,'全唐诗/poet.song.242000.json','["今朝胡不樂，取書一哦之。", "饑窮古不免，陶生良有辭。", "骨肉同天倫，僮僕緣食來。", "如何長年中，萬事付酒杯。", "脫身得一飽，激烈陳歌詩。", "不如魯侯仁，借貸英雄材。", "嗟余亦有作，欲向誰同貽。"]'),
('58e1f80f-398a-4dc0-a626-be9b0c1c9b6b','君莫誇少年一首贈余光遠','戴表元','宋','宋诗','song-poetry','','[]','君莫誇少年，與我憊者疏。',288,'全唐诗/poet.song.242000.json','["君莫誇少年，與我憊者疏。", "我亦嘗少年，少年君不如。", "談諧今已忘，猶有少年餘。", "東南山水國，早得飛長裾。", "春園虎丘樹，夏檻玉泉魚。", "吳妍與楚豔，過眼日千車。", "當此秋風凄，遊子易欷歔。", "我時未更事，意氣益發舒。", "出門有佳侶，遇勝不得虛。", "惟憂日晷短，當去亦躊躇。", "官曹人所厭，高士不肯居。", "平生縱觀處，最在客南徐。", "姻黨四面集，綵衣擁安輿。", "停觥待淮蟹，醇甘逮僮胥。", "道路無此願，此願勝鄉閭。", "自從秣陵歸，鬰鬰不再攄。", "三間風雨屋，僻其荒林墟。", "非君好事者，誰能至吾廬。", "今來建溪上，逢君屢相於。", "行藏且勿問，人世有乘除。", "舊狂我已悔，新銳君當袪。", "男兒不用世，資身在犂鋤。", "臨風贈君別，勸君惜居諸。", "勸君重桑梓，勸君重名譽。"]'),
('9fd45685-006f-424e-b00a-18b951279637','老樹','戴表元','宋','宋诗','song-poetry','','[]','老樹老且枯，數柯枝綴之。',96,'全唐诗/poet.song.242000.json','["老樹老且枯，數柯枝綴之。", "蟲來食其葉，藤來纏其皮。", "幸然根本堅，未至甚離披。", "風霜既無損，雨露猶見私。", "如何烏鳥輩，同巢自傾危。", "鬭擊翼似斧，啄傷嘴如錐。", "樹色歲時減，樹力日夜衰。", "回頭試一顧，但可相扶持。"]'),
('d950fb7a-bf48-4657-969c-cfd633f74c17','伯收東岡麥','戴表元','宋','宋诗','song-poetry','','[]','伯收東岡麥，仲移西塍秧。',72,'全唐诗/poet.song.242000.json','["伯收東岡麥，仲移西塍秧。", "四季各有役，餬口走皇皇。", "豈不惜冠履，兼嘗業縑緗。", "憐爾衣食微，及茲筋力强。", "古來經術士，什九起耕桑。", "窮通自天命，謹勿事胥商。"]'),
('1dfbf0c1-2ed0-4528-9f2d-480103686a46','邀陳氏子飯歸似銅山珣老','戴表元','宋','宋诗','song-poetry','','[]','飯子山下麥，羹以山上笋。',60,'全唐诗/poet.song.242000.json','["飯子山下麥，羹以山上笋。", "笋堅煩齒牙，麥糲哽喉吻。", "相邀豈云厚，竟去良不忍。", "林園隠趣出，魚稻秋事近。", "短歌訊而翁，贈子以一哂。"]'),
('d2d909fa-c045-4038-a0e8-b0154406c469','饑旱','戴表元','宋','宋诗','song-poetry','','[]','旱風爍我膚，饑火煎我腸。',144,'全唐诗/poet.song.242000.json','["旱風爍我膚，饑火煎我腸。", "春夏猶自可，入秋始難當。", "簪珥陡頓盡，衾裯纖細將。", "奪從女奴手，併入米客囊。", "但冀喘息延，敢憂生理妨。", "山州古磽瘠，歲計仰蘇杭。", "發地流玉粒，浮天駕牙檣。", "如何水後郡，翻糴浙東糧。", "行路急促促，人情沸皇皇。", "焦枯望一雨，禬禱願千方。", "雲氣亦偃蹇，魃妖轉炎揚。", "浮生想有屬，沈憂聊暫忘。"]'),
('ea8d477c-fb1c-4192-a447-9b93217b9a62','余居之西偏有小室名嗇庵詩以識之','戴表元','宋','宋诗','song-poetry','','[]','嗇語養氣海，嗇食養脾土。',84,'全唐诗/poet.song.242000.json','["嗇語養氣海，嗇食養脾土。", "嗇慮養心神，嗇勞養筋膂。", "衰年百事袪，寄息此環堵。", "危如突圍將，鈍似滯風賈。", "顛仆冀賒延，空羸待償補。", "夸虛道蟊賊，逞獲命斤斧。", "收君詅癡符，佩我養生主。"]'),
('943ecc0e-8d6c-4700-9f05-3137ca6665d3','鄰峰','戴表元','宋','宋诗','song-poetry','','[]','霜嚴火炬青，月澹兩峰白。',108,'全唐诗/poet.song.242000.json','["霜嚴火炬青，月澹兩峰白。", "堂堂夜行誰，鄰峰販醝客。", "販醝事且止，歸農收又薄。", "技擊習鞭撾，鮮肥憤烹炙。", "外雖刑憲拘，內實饑困迫。", "鹿窮有狂奔，虎斃猶恐擲。", "如何隴上豪，坐作溝中瘠。", "世無卓魯化，名在跖蹻籍。", "感歎重徊徨，羈危轉驚赤。"]'),
('c017aba5-968d-4564-a871-bc517ba428ee','春日城南聞禽鳥聲喧甚爲賦二十二韻','戴表元','宋','宋诗','song-poetry','','[]','今日春氣至，新禽各啁嘲。',264,'全唐诗/poet.song.242000.json','["今日春氣至，新禽各啁嘲。", "豈無好唇舌，入耳何怓怓。", "雊鵒最多端，能以巧自殽。", "黄頭亦翾給，微吭和且調。", "無計頗滑熟，烏鴉與鷦鷯。", "自餘不知名，喧呼雜竽簫。", "黑衣猥雄黠，晝動固非梟。", "均爲樂其性，幸此風日朝。", "城南六七曲，荒園繞榛茅。", "我來感物變，何異在山郊。", "惟聞黄鸝至，不聞叫交交。", "當由戀幽谷，畏寒還避囂。", "群英蓋壤內，小大一逍遥。", "得氣不足悅，觸情遂相遼。", "乘墉少年兒，挾彈欲見邀。", "所規不滿掬，翻令污厨庖。", "鷹鶻勢險薄，爪長尤善捎。", "同群自戕擊，此禍極無聊。", "深藏務遠晦，尚懼形色招。", "危機布平陸，况乃縱輕僄。", "悲憐復譬釋，當鳴詎爲妖。", "但懷道傍樹，信美非其巢。"]'),
('96e0cf52-916b-4f89-96f3-429cc2ebfecc','林貴父投老謁銓有贈','戴表元','宋','宋诗','song-poetry','','[]','天寒道路長，行子難爲容。',120,'全唐诗/poet.song.242000.json','["天寒道路長，行子難爲容。", "况復迫衰暮，視近步憧憧。", "干世悔古學，費時慚惰農。", "誰知凍雪巷，忽視戟髯翁。", "袖有排闥書，談如發硎鋒。", "聽之不能竭，浩氣生奇胸。", "從來庠序師，專以處龍鍾。", "才高得教誘，祿休尚遭逢。", "此職今不少，有求豈難從。", "去去善自愛，春禽語晴墉。"]'),
('13b1f9b7-9140-4b96-903a-4871082cb260','陳晦父赴銓十三韻','戴表元','宋','宋诗','song-poetry','','[]','古人取遠士，得一以爲豪。',156,'全唐诗/poet.song.242000.json','["古人取遠士，得一以爲豪。", "江左貢千百，選掄今始勞。", "占對混童廝，趨蹌偕吏曹。", "以茲寓繩準，棄髓索皮毛。", "遂乃考卷業，成文喧誦號。", "其次嚴保舉，虛牘相籠叨。", "富儒坐可得，貧儒走滔滔。", "有司見其然，厭賤如蓬蒿。", "誰知真儒者，百黜寧不遭。", "陳生青紫門，佐書越江皋。", "秩滿在選中，家寒無所操。", "虞翻顯憑易，買臣進緣騷。", "吳士例則然，且毋衒名高。"]'),
('d25cd60e-d210-4ed5-88d8-bd6fde113ca3','次韻答鹽官傅秀才','戴表元','宋','宋诗','song-poetry','','[]','欲有險於穽，千金身陡沉。',84,'全唐诗/poet.song.242000.json','["欲有險於穽，千金身陡沉。", "爭名急饑渴，對面九關深。", "誰知海城畔，山水發清音。", "蟾蜍泄喜慍，籧篨閲晴陰。", "意到得所指，不作寒鳶吟。", "斯人定不惡，我輩許同襟。", "去去復去去，白鷗未遐心。"]'),
('3d1b6044-2c25-4af9-af82-54eb5a0b25ea','南巖留宿分韻落字','戴表元','宋','宋诗','song-poetry','','[]','遊觀值暄秋，飲狎得嘉客。',84,'全唐诗/poet.song.242000.json','["遊觀值暄秋，飲狎得嘉客。", "嵌巖復在眼，徘徊忘還郭。", "款款坐向疲，喧喧笑多謔。", "短簷近見出，竇乳時聞落。", "防闇燎蒸薪，驚虛摇鼓鐸。", "僮憨榻露處，僧馴茗頻瀹。", "竟隠諒未能，羨彼高棲雀。"]'),
('c50a3c1f-b841-4b21-9014-7c292d3e4516','朱使君家諸郎將別十一韻','戴表元','宋','宋诗','song-poetry','','[]','東南典藩材，朱戶賢第一。',132,'全唐诗/poet.song.242000.json','["東南典藩材，朱戶賢第一。", "天生好兒郎，玉笋森六七。", "俱能弄文翰，那教踰戶室。", "伯也秀英英，珊瑚映初日。", "翁仲最似古，鼎鼐熊彪質。", "叔季相和鳴，笙入鐘磬出。", "人言有陰德，我愛少權術。", "公退亦見容，老衰時自失。", "官期忽在眼，別語常促膝。", "江湖芥舟小，歲月翎箭疾。", "善保清明心，臨岐莫輕怵。"]'),
('ba11a9db-8f94-4ef5-9296-f94159342fbd','掩篋','戴表元','宋','宋诗','song-poetry','','[]','十客九不解，一解值吾仇。',48,'全唐诗/poet.song.242000.json','["十客九不解，一解值吾仇。", "譬如巧蛾眉，同鏡見之羞。", "結交恨不廣，難在相綢繆。", "掩篋謝年少，所藏非所求。"]'),
('c85b6f61-547b-48c1-9bd9-c801df2a18de','次和焦治中雲洞紀遊十四韻','戴表元','宋','宋诗','song-poetry','','[]','是身虛空中，如雲本無有。',168,'全唐诗/poet.song.242000.json','["是身虛空中，如雲本無有。", "遊行又其寄，縱樂安得久。", "嵌巖大磈質，鑱削奇鬼手。", "棟宇起何年，名稱出誰口。", "憶昔扳藤蔓，淩空訝雞狗。", "疏疏石生窾，剡剡室懸斗。", "乘峻開棧梯，緣明掛窗牖。", "豈無題壁堂，多逢斫畬叟。", "賢侯韋平家，雅韻王謝友。", "驪珠百四十，模寫已八九。", "坐我南樓牀，澆我北海酒。", "人生主客意，如此豈云偶。", "風花命浮沉，木雁天可否。", "悠然付一噓，山靈倘回首。"]'),
('d9cd4db9-4fb5-4205-b40c-9ca68d1d2a48','信府同知黄侯名其讀書之室曰廣居','戴表元','宋','宋诗','song-poetry','','[]','隘夫護藩畛，得少便有餘。',120,'全唐诗/poet.song.242000.json','["隘夫護藩畛，得少便有餘。", "達士心曠然，清明如太虛。", "海岳陳鼎俎，羲駕走軒車。", "唯諾無不行，尚懷豚與魚。", "嗟茲山城氓，憎長逮其胥。", "好語朝索茅，怒攻晝攘裾。", "侯來未數月，眉頭笑舒舒。", "退食掃一室，焚香展群書。", "舉頭窗楹間，有榜揭廣居。", "力行守仁義，鄒公不欺余。"]'),
('02eb58da-f06b-4e12-80c2-748661a33d53','丙午二月十五日以府檄出宿了岩','戴表元','宋','宋诗','song-poetry','','[]','衰年慕棲息，役役殊未休。',84,'全唐诗/poet.song.242000.json','["衰年慕棲息，役役殊未休。", "天明發東郭，日晏泊西州。", "豈其千金軀，爲此一餐謀。", "宿麥青已鬰，穉桑黄亦稠。", "欣然一會意，所愧非吾丘。", "悔日諒不遠，誓言良未酬。", "揮手謝還往，伊嚘自伊嚘。"]'),
('b12d5fad-5005-46e8-91cb-977392c80d15','送官歸作','戴表元','宋','宋诗','song-poetry','','[]','生世悔識字，祝身如野農。',48,'全唐诗/poet.song.242000.json','["生世悔識字，祝身如野農。", "勤勞養尊老，膳味日可重。", "晨芻熟新黍，耕林有過從。", "行吟聆松籟，此樂踰歌鍾。"]'),
('c9b4eb64-0021-4e78-8407-d7352d37520f','七陽字','戴表元','宋','宋诗','song-poetry','','[]','雁雁西北來，亦復東南翔。',48,'全唐诗/poet.song.242000.json','["雁雁西北來，亦復東南翔。", "動物各有時，吾當謹行藏。", "厚□違嚴風，密袂禦凜霜。", "陶然茅簷下，一篋生春陽。"]'),
('8c0db84f-241d-4295-8bb2-307e3ed58074','班溪','戴表元','宋','宋诗','song-poetry','','[]','我愛班溪班，班班爲誰好。',84,'全唐诗/poet.song.242000.json','["我愛班溪班，班班爲誰好。", "於時九秋晚，霜葉紅不埽。", "石摇未歸雲，水映欲衰草。", "累累牛羊隊，洒洒魚龍道。", "崇丘尚多菜，殘村幾經潦。", "故物一若斯，今我胡不老。", "過從幸相狎，聊坐暢懷抱。"]'),
('87de752b-eb9c-40e6-b222-7a9cdeeea7a3','宿福海寺','戴表元','宋','宋诗','song-poetry','','[]','斲巖蒼龍角，汲流紫雲根。',72,'全唐诗/poet.song.242000.json','["斲巖蒼龍角，汲流紫雲根。", "道人不絕俗，自然無耳喧。", "屋脊掛修嶺，一日過千轅。", "此中但高卧，松風有清言。", "聽之亦無有，風定松在門。", "炊成我欲去，獨鶴鳴朝暾。"]'),
('31c97304-6110-4405-8587-20a43e1566c2','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其一','戴表元','宋','宋诗','song-poetry','','[]','驕雲散飛雨，隨風爲有無。',48,'全唐诗/poet.song.242000.json','["驕雲散飛雨，隨風爲有無。", "老農終歲日，望施在須臾。", "平生官田粟，長此禮義軀。", "置之且勿戚，一飽任妻孥。"]'),
('95e2cf96-6e9c-4580-a4db-1ceefe869589','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其二','戴表元','宋','宋诗','song-poetry','','[]','青青澤中蒲，九夏氣凄寒。',48,'全唐诗/poet.song.242000.json','["青青澤中蒲，九夏氣凄寒。", "翾翾翠碧羽，照影蒼溪間。", "巢由薄天下，俗士營一官。", "小大各有適，自全良獨難。"]'),
('7ffa1501-888e-4686-b65a-2678eeabb1e3','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其三','戴表元','宋','宋诗','song-poetry','','[]','窮居無公憂，私此長夏日。',48,'全唐诗/poet.song.242000.json','["窮居無公憂，私此長夏日。", "蚊蠅如俗子，正爾相妬嫉。", "麾驅非吾任，遁避亦無術。", "惟當俟其定，靜坐萬慮一。"]'),
('83fc7848-6990-44eb-944f-c5a8a7d569d1','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其四','戴表元','宋','宋诗','song-poetry','','[]','流螢出草莽，空飛亂星辰。',48,'全唐诗/poet.song.242000.json','["流螢出草莽，空飛亂星辰。", "蜻蜓水蟲質，一變能輕身。", "物情羨速化，過眼異新陳。", "嗟嗟白屋士，吾方保吾真。"]'),
('8ce91fb2-8b4d-49c7-b597-9bd8e5e0a8c8','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其五','戴表元','宋','宋诗','song-poetry','','[]','當暑苦炎暍，日數秋風生。',48,'全唐诗/poet.song.242000.json','["當暑苦炎暍，日數秋風生。", "窮憂在衣褐，霜露亦可驚。", "徘徊念年少，歲月去已輕。", "歲月可奈何，學道恐無成。"]'),
('ef5eb97b-4815-48a2-a5f1-b3d064336b92','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其六','戴表元','宋','宋诗','song-poetry','','[]','自古皆有隠，陶生隠於酒。',48,'全唐诗/poet.song.242000.json','["自古皆有隠，陶生隠於酒。", "炎氛四面集，一窟在北牖。", "世人羨桃源，桃源復何有。", "惟容醉鄉徒，百世得相友。"]'),
('af9f504b-c201-4c62-9246-eceb54f538bd','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其七','戴表元','宋','宋诗','song-poetry','','[]','永日豈無饑，盜粟非所擬。',48,'全唐诗/poet.song.242000.json','["永日豈無饑，盜粟非所擬。", "暍行豈無勞，惡木非所止。", "君家碧梧軒，蓮荷泛芳沚。", "我來息凉陰，嘉賓薦君子。"]'),
('5d0ac73b-77a8-444f-91f9-f423034c11d1','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其八','戴表元','宋','宋诗','song-poetry','','[]','幽蟲聒午枕，掩抑聲千萬。',48,'全唐诗/poet.song.242000.json','["幽蟲聒午枕，掩抑聲千萬。", "風前以虛鳴，蟋蟀最多怨。", "我靜乃得聞，一一來自獻。", "憧憧道傍子，與爾故相遠。"]'),
('521668dc-6c57-4542-9b2b-5c960431fe84','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其九','戴表元','宋','宋诗','song-poetry','','[]','炎方有朱鳥，璀璀顔色異。',48,'全唐诗/poet.song.243000.json','["炎方有朱鳥，璀璀顔色異。", "土人目爲鳳，信爾可安致。", "生雛固當奇，千歲會一至。", "紛紛鴻燕期，寂寂非我事。"]'),
('2e74de34-a915-4bef-916c-73299cbb20db','六月十三日壽陳子徽太博十首以無官一身輕有子萬事足爲韻  其一○','戴表元','宋','宋诗','song-poetry','','[]','朝遊剡山巔，暮戲剡山足。',48,'全唐诗/poet.song.243000.json','["朝遊剡山巔，暮戲剡山足。", "英英丹霞洞，不受塵土辱。", "飛仙復何許，諸子如立鵠。", "酌君滄浪泉，和君紫芝曲。"]'),
('ae6ce346-dedf-40cf-ac7f-1ade335e3ab9','陳茂陽書監赴史氏塾','戴表元','宋','宋诗','song-poetry','','[]','青天碎浮雲，飄落隨長風。',108,'全唐诗/poet.song.243000.json','["青天碎浮雲，飄落隨長風。", "當年江海心，聚散豈謂同。", "我髮春霰白，君顔秋樹紅。", "各將飛騰具，坐受窮困攻。", "懷書更何罪，暴客歲不容。", "數夕稍振發，共語凉天中。", "天明換顔色，囊瓢赴群童。", "此事本下策，改道無所從。", "猶勝古俠士，儈牛市廧東。"]'),
('8890a7eb-66a5-4271-8072-15b53b72a4d8','春風','戴表元','宋','宋诗','song-poetry','','[]','春風吹愁端，散漫不可收。',96,'全唐诗/poet.song.243000.json','["春風吹愁端，散漫不可收。", "不如古溪水，祇望鄉江流。", "新花紅爍爍，舊花滿山白。", "昔日金張門，狼藉餘廢宅。", "回頭語春風，莫向新花叢。", "我見朱顔人，多金亦成翁。", "多金不足惜，丹砂亦無益。", "更種明年花，春風多相識。"]'),
('2833756d-97cf-4c36-b5c5-925d400e8717','八月十五夜雨中微有月色','戴表元','宋','宋诗','song-poetry','','[]','雨色今夜別，映門白鮮鮮。',84,'全唐诗/poet.song.243000.json','["雨色今夜別，映門白鮮鮮。", "隃知萬古月，自在最高天。", "天高無陰晴，月亦無虧圓。", "中間隔雲霧，頃刻變態千。", "惟當自作樂，上界豈我憐。", "接竹風撼郭，倒尊水號川。", "狂歌眺渺莽，恐有浮槎仙。"]'),
('42d2a461-4dbf-4f96-a46c-29f5da814311','九日與兒輩遊中溪','戴表元','宋','宋诗','song-poetry','','[]','悠悠循澗行，磊磊據石坐。',84,'全唐诗/poet.song.243000.json','["悠悠循澗行，磊磊據石坐。", "林垂短長雲，山綴丹碧顆。", "蓼花最無數，照水嬌妸娜。", "何知是節序，風日自清妥。", "群童競時新，藕果間蔬蓏。", "欣然爲之醉，烏帽危不墮。", "此日山中懷，孟翁不如我。"]'),
('c841553b-6aa9-4823-8eb8-3563fb5912be','閬風舒先生客居棠溪袁仲素家見示竹簾詩戲作問答二首  其一','戴表元','宋','宋诗','song-poetry','','[]','剡竹吾問君，班班爲誰設。',84,'全唐诗/poet.song.243000.json','["剡竹吾問君，班班爲誰設。", "一登君子堂，逈與凡界絕。", "陂龍鱗故鮮，湘娥淚猶熱。", "既能露文章，匠手安得輟。", "所憐無可娛，如伴枯禪滅。", "千金散紅裙，一鏡垂白髮。", "定非夏侯衣，高堂挂秋月。"]'),
('f9099c66-d00c-4920-a5eb-e4d2397450cd','閬風舒先生客居棠溪袁仲素家見示竹簾詩戲作問答二首  其二','戴表元','宋','宋诗','song-poetry','','[]','何物非可憐，聿向翁戶設。',84,'全唐诗/poet.song.243000.json','["何物非可憐，聿向翁戶設。", "翁好詩更佳，蕭然得三絕。", "他家少年叢，徒爾歌舞熱。", "正如閲優場，未久意先輟。", "翁今一室老，高卧百念滅。", "湯爐松林風，紙帳梅花雪。", "時時有佳客，文字送日月。"]'),
('df7535ee-5162-4320-ad49-ab33d42c0324','古詩十五韻送胡天放西遊','戴表元','宋','宋诗','song-poetry','','[]','有鐵莫妄鎔，鎔作俠士椎。',180,'全唐诗/poet.song.243000.json','["有鐵莫妄鎔，鎔作俠士椎。", "有帛莫妄縫，縫作山人衣。", "君看天放翁，氣貌絕清羸。", "濩落七尺身，仁義充膚肌。", "無家救人窮，無田恤人饑。", "江湖三十秋，白頭轉嶇崎。", "餘情尚灑灑，不吐酸寒辭。", "事慕古豪傑，諸兒那得知。", "或云有仙骨，深中愈難窺。", "趫騰華佗戲，偃蹇梁鴻噫。", "世態貴反覆，口語瀾翻飛。", "夫子顧之笑，百觸不發機。", "寧當待溝壑，西山古誰悲。", "佩君珊瑚鈎，酌以玻璃巵。", "相知豈云無，去去勿復疑。"]'),
('5022638f-b445-4008-88c6-7976bfa6026d','舟中望紫巖','戴表元','宋','宋诗','song-poetry','','[]','近山如畫牆，遠山如帚長。',96,'全唐诗/poet.song.243000.json','["近山如畫牆，遠山如帚長。", "我從雲中來，回頭白茫茫。", "惜去乃爾覺，常時自相忘。", "相忘豈不佳，遣此春懷傷。", "飄灑從何來，衣巾徑微凉。", "初疑雨氣集，冉冉遊塵黄。", "無歸亦自可，信美非吾鄉。", "登舟望東雲，猶向帆端翔。"]'),
('3c061426-83cd-441a-81c9-1443afa7cc71','次韻答二袁','戴表元','宋','宋诗','song-poetry','','[]','相逢何草草，不念別日長。',96,'全唐诗/poet.song.243000.json','["相逢何草草，不念別日長。", "別我我在山，別君海茫茫。", "慰別有難易，我老不易忘。", "今此春雲篇，來別已悲傷。", "春雲雖多態，與世無炎凉。", "朝出山路白，暮歸海天黄。", "人生不免別，與君非異鄉。", "我詩不如雲，春雲解飛翔。"]'),
('c1233793-a5fc-4616-987e-5170804d363a','感物二首  其一','戴表元','宋','宋诗','song-poetry','','[]','騄驥今失群，亦自矜趫騰。',72,'全唐诗/poet.song.243000.json','["騄驥今失群，亦自矜趫騰。", "俛仰歲時久，帖然困蚊蠅。", "豪鯨逸其穴，天水成滄溟。", "豈無魚鼈交，望望爲所憎。", "物理有翕張，達人同廢興。", "幸無怵迫憂，聊復曲吾肱。"]'),
('973ebc2a-e1a6-41f4-8793-a73336fb65fa','感物二首  其二','戴表元','宋','宋诗','song-poetry','','[]','魚目出泥沙，空村百金珍。',72,'全唐诗/poet.song.243000.json','["魚目出泥沙，空村百金珍。", "豫章值擁輳，細細供蒸薪。", "論材何必多，適用即能神。", "託交何必深，寡求永相親。", "鮑叔拙羈魯，張生窮厄陳。", "茫然扳援際，豈意出風塵。"]'),
('ef5d212f-7d8a-4bb6-934c-eb9238ee761a','八月十六張園玩月得一字','戴表元','宋','宋诗','song-poetry','','[]','明河盪殘雲，青海收晚日。',192,'全唐诗/poet.song.243000.json','["明河盪殘雲，青海收晚日。", "婆娑林端月，爲我良久出。", "洗杯問勞苦，天女笑肸肸。", "月行虛空中，萬古無損失。", "且可娛今宵，勿復思昨日。", "歌情天水遥，坐影入樹密。", "嗔醒有微酒，徼詩或呼筆。", "仲容歡入林，懷祖嬌在膝。", "初猶整裘褐，久乃忘冠櫛。", "趨鏘翻弈盤，笑傲驚帳室。", "寧來共喧呶，不許私暇逸。", "蚩蚩復擾擾，醉態不可一。", "情知此月下，此樂世無匹。", "月光本天性，清瑩本其質。", "動定極渟涵，聲沈轉蕭瑟。", "匆忙寄醉語，悟遲已難述。"]'),
('c5bf8134-b581-4fb8-8216-ed0400fa99e8','送鄉友林耕道往信州因寄李明通','戴表元','宋','宋诗','song-poetry','','[]','盧公全盛時，桃李何紛紛。',168,'全唐诗/poet.song.243000.json','["盧公全盛時，桃李何紛紛。", "冠蓋蔽白日，談笑起青雲。", "林翁我鄉曲，同業又同門。", "如何三十年，白頭始相聞。", "全家作楚鬼，隻影窮江源。", "起手問曲折，口澀不肯言。", "寧非衣食牽，猶頼齒頰存。", "歎此皆有數，吾書已云云。", "下盡浮世塵，上通先天根。", "事來即順受，不得勞悲欣。", "我老耕破硯，百錢混人群。", "聽之如飲醇，油油至微醺。", "所恨各有役，東帆復西轅。", "平生李元禮，歸爲致寒暄。"]'),
('37931aa0-b8c9-4e5f-b29d-e5e5de48aeb8','鹿頂山朝暉軒爲東玉師賦','戴表元','宋','宋诗','song-poetry','','[]','金雞警神關，燭龍轉嚴車。',72,'全唐诗/poet.song.243000.json','["金雞警神關，燭龍轉嚴車。", "陰蒙欲銷散，巖谷開噓呀。", "忽然蒼蘿顛，湧出紅蓮華。", "天暉初照爍，六合無藏遮。", "而我靈臺中，善根始萌芽。", "珍重慎消息，外物如塵沙。"]'),
('aa6396d2-9ad7-44b9-b5ea-0366008aab5d','鄰友陳養直請賦山心樓','戴表元','宋','宋诗','song-poetry','','[]','諸峰何盤盤，四起如帷牆。',108,'全唐诗/poet.song.243000.json','["諸峰何盤盤，四起如帷牆。", "試問客主誰，茲樓山中央。", "面勢既環合，結構欲飛翔。", "我來名山心，一笑借胡牀。", "左手南風絃，右手北斗漿。", "山靈亦我笑，夜夢車兩廂。", "一坐三十秋，林篁鬰相望。", "花鳥天語默，烟雲野行藏。", "開通勿障蔽，百世敢遺忘。"]'),
('4be910df-ae53-4f87-be26-2b4b8cfcd191','刈園詩爲竺秀才作','戴表元','宋','宋诗','song-poetry','','[]','朝從園中去，暮從園中歸。',96,'全唐诗/poet.song.243000.json','["朝從園中去，暮從園中歸。", "園中何所有，雜草青離離。", "刈少猶未覺，刈多還漸稀。", "豈憂筐筥頻，要使牛羊肥。", "但放刈手緩，勿傷蘭與葵。", "葵高葉難護，蘭弱根易萎。", "惟彼惡草種，刈盡轉蕃滋。", "此理不可詰，此語令人思。"]'),
('c2827748-b35a-4289-bcd5-20eb9f8b603c','送陳養晦赴松陽校官','戴表元','宋','宋诗','song-poetry','','[]','書生不用世，什九隠儒官。',96,'全唐诗/poet.song.243000.json','["書生不用世，什九隠儒官。", "抱璞豈不佳，居貧良獨難。", "陳子剡中秀，盛年早彈冠。", "嘗搴丹丘雲，亦窺滄海瀾。", "仙真願喜笑，魚龍從盤桓。", "天風一吹激，却步赤松關。", "諒子太宇定，悠然置悲歡。", "但令懷居輩，極目勞追扳。"]'),
('fa181acd-0fbb-4510-9e7e-9e9a3cd2c90c','秋蟲歎','戴表元','宋','宋诗','song-poetry','','[]','夏蟲聲漸微，秋蟲聲漸繁。',84,'全唐诗/poet.song.243000.json','["夏蟲聲漸微，秋蟲聲漸繁。", "微物何所知，時至不得閒。", "嗟我鏡中髮，亦復就凋殘。", "凄然雜憂患，霜風埽茅菅。", "反不如彼蟲，自得草莽間。", "所以達生士，逃名在空山。", "客居雖云樂，不如早知還。"]'),
('4f05052a-e676-41f2-813b-eea807e0ac2e','聽琴行贈沈秀才','戴表元','宋','宋诗','song-poetry','','[]','君不見江南琴師海與聰，誰與傳者夢溪公。',200,'全唐诗/poet.song.243000.json','["君不見江南琴師海與聰，誰與傳者夢溪公。", "又不見醉翁詩中沈夫子，聽水作琴琴譜起。", "祇今人間何處無琴師，問渠端由渠未知。", "錢塘東風萬人裏，沈家還見奇男兒。", "沈家家住鴛湖曲，夜理漁絲朝采菊。", "菊苦難餐魚又寒，彈出歌聲寄凄獨。", "近來携琴東海行，清音應滑如流鶑。", "湖園日暖百花歎，彈徹滿樹春風生。", "我不識琴識琴理，爲君悲酸爲君喜。", "相逢正值酒錢空，徉狂攘臂紅塵市。", "琵琶阮咸休羨渠，相知豈須頻曳裾。", "醉毛死久髯徐去，洗手空山修樂書。"]'),
('7be958dc-8e92-4334-82ce-0ebec037b85c','赤泥嶺行','戴表元','宋','宋诗','song-poetry','','[]','種桑三年寒得衣，養犢作牛堪挽犂。',115,'全唐诗/poet.song.243000.json','["種桑三年寒得衣，養犢作牛堪挽犂。", "生男祇解戀鄉土，五日溪船催父歸。", "行前倉庚後杜宇，去家漸近聞剡語。", "恨身不作田舍兒，騎竹摶沙繞牆戶。", "人生衣飯取裁足，阿奴碌碌猶類福。", "獻書覓舉真下策，年少奔馳頭已白。", "君不見燕山萬里客更難，赤泥嶺上春風寒。"]'),
('0706df6e-2446-44aa-bad4-f116c3cc21e2','建溪精舍得本字','戴表元','宋','宋诗','song-poetry','','[]','四山翛翛風日暖，白髮看花惜春晚。',160,'全唐诗/poet.song.243000.json','["四山翛翛風日暖，白髮看花惜春晚。", "當時衰草牧羊坡，今日池臺紅霧滿。", "最憐幽篁手所植，兒戲成業亦千本。", "舊遊聚散萬事拙，客夢悲歡百年短。", "荒凉處處經戰馬，寒食家家澆祭碗。", "隃知地下不識醉，祇合生前尋酒伴。", "蒼苔白石堪枕籍，野鳥清溪自絃管。", "同遊飄揚正捷步，老我摧頹甘負眼。", "風牀溽暑新候濁，江樹飛雲故人遠。", "出城少事幸縱恣，賭令爭歡君莫懶。"]'),
('4b3bc373-c9ba-4936-8254-45e61ca42ff6','夜寒行','戴表元','宋','宋诗','song-poetry','','[]','昨日天寒不成醉，今日天寒不成寐。',128,'全唐诗/poet.song.243000.json','["昨日天寒不成醉，今日天寒不成寐。", "醉遲得酒可强歡，寐少愁多頻發喟。", "紫竿葦炬閙荒城，役夫遥作鸛鴨鳴。", "擁衾高枕未云苦，熟聽但覺令人驚。", "烏孫黄鵠飛不返，遼城白骨填未滿。", "朔風蕭蕭吹成旗，居人何如去人遠。", "丈夫無成霜滿須，沙場萬里星河疏。", "南牆詩翁窮據爐，北窗少年猶讀書。"]'),
('cdb589f3-86d9-4f0d-aa64-932fd480ff6d','騎馬行答贈吳中張子潜鄉貢','戴表元','宋','宋诗','song-poetry','','[]','君不見天上續絃膠，又不見海外切玉刀。',130,'全唐诗/poet.song.243000.json','["君不見天上續絃膠，又不見海外切玉刀。", "傍人錯愕心自快，痕迹過眼無秋毫。", "吳江先生淮海客，長篇大章歌落托。", "白袍只作東土音，黑頭曾射南宮策。", "霜清水落芙蓉開，酒酣獨上吳王臺。", "緘書右望寄飛鳥，乘風忽擬穿蓬萊。", "人生相逢不在早，賈生太少顔生老。", "興來亦欲向西遊，約君騎馬閶門道。"]'),
('305248f5-3961-4e26-b8b8-ea8150d161be','自信上歸遊石門訪故人毛儀卿鎮卿兄弟作長句贈之','戴表元','宋','宋诗','song-poetry','','[]','山開未開白雲梯，人行不行青麥溪。',80,'全唐诗/poet.song.243000.json','["山開未開白雲梯，人行不行青麥溪。", "五年清夢隔蟻穴，千里飛塵深馬蹄。", "重來交遊亦笑樂，但覺几杖煩提携。", "門閒霜葉無數積，風定水禽時一啼。", "藥草春暄夜更長，木蘭花下聽天雞。"]'),
('5b27c385-27ad-4ea1-99e1-83ce1f4d2747','昨日行','戴表元','宋','宋诗','song-poetry','','[]','種樹莫種垂楊枝，結交莫結輕薄兒。',67,'全唐诗/poet.song.243000.json','["種樹莫種垂楊枝，結交莫結輕薄兒。", "楊枝不耐秋風吹，薄交易結還易離。", "君不見昨日書來兩相憶，今日相逢不相識。", "不如楊柳猶可久，一度春風一回首。"]'),
('f38c669a-1a57-4541-8e16-f3632feb2206','招子昂飲歌','戴表元','宋','宋诗','song-poetry','','[]','與君相逢難草草，與君相逢苦不早。',224,'全唐诗/poet.song.243000.json','["與君相逢難草草，與君相逢苦不早。", "人生何處小泥塗，此日飄零武林道。", "武林城中馬如雲，閉屋狂歌人不聞。", "狂歌自笑君亦笑，依然狂絕不如君。", "君歌豈是真狂者，青衫少日春瀟灑。", "至今俊筆五花紋，最惜青眸十步下。", "虛名何用等灰塵，不如世上蓬蒿人。", "黄金偏趨不貧室，白髮難老無愁身。", "風雨無情亦如此，凄凄但聒窮人耳。", "不見朱樓高到天，鳳簫龍管連朝起。", "連朝笙管可奈何，我歌且止須君歌。", "青天白雪望不極，坐見綠水生層波。", "我生胡爲被狂惱，江頭魚肥新酒好。", "從今作樂拚醉倒，與君相逢難草草。"]'),
('5f8da01a-e05a-4cfe-af68-5309e9e2cce0','雁南飛','戴表元','宋','宋诗','song-poetry','','[]','雁南飛，飛且鳴。',220,'全唐诗/poet.song.243000.json','["雁南飛，飛且鳴。", "我不愛爾絕漢排雲之健翼，愛爾秋來意氣各有適。", "江湖萬里同風聲，風聲萬里秋蕭索，山鄉田荒水鄉薄。", "不應專爲稻粱來，得飽自住今亦樂。", "群飛嘹唳奈爾何，青天茫茫無網羅。", "誰知世有苦心者，夜半聞聲悲轉多。", "雁南飛，勸爾飛時莫近征婦舍，手觸邊衣添淚下。", "更莫飛近貧士屋，絃絕樽空怨悽獨。", "雁南飛，飛且止，世事驚人例如此。", "我昔扁舟五湖水，年年見爾秋風裏。", "如今未斷少年情，一度雁來心一驚。", "今年雁來明年去，明年去去江南路。", "欲將書寄去邊人，明年認作書回處。"]'),
('20bb727e-321d-4a1c-a811-55149579fada','剡氏饑','戴表元','宋','宋诗','song-poetry','','[]','剡氏饑，山前山後尋蕨萁。',62,'全唐诗/poet.song.243000.json','["剡氏饑，山前山後尋蕨萁。", "斸萁得粉不滿掬，皮膚皴裂十指禿。", "皮皴指禿不敢辭，阿翁三日不供糜。", "不如拋家去作挽船士，却得家人請官米。"]'),
('1a95095c-c2f7-40d8-98ac-04d9ccfd6541','俞光遠父子歸馬嶴兼託問訊故舊','戴表元','宋','宋诗','song-poetry','','[]','君不見深山野馬生龍駒，又不見荒林老鷹鳩作雛。',246,'全唐诗/poet.song.243000.json','["君不見深山野馬生龍駒，又不見荒林老鷹鳩作雛。", "男兒似種世所少，俞郎三世成清儒。", "祇今道路滿塵土，大袖已覺妨奔趨。", "提携逐食何足羨，羨子有策寧親軀。", "蠲符晝行雞犬靜，餐錢下歲鮭魚須。", "機神有餘自靜重，蔚蔚老氣生眉鬚。", "高堂百客森冠裾，四座指點看明珠。", "誰能對此心不動，歸來轉覺群兒愚。", "峽南雲深山氣冷，今歲亦聞愁旱枯。", "但憐四壁愈憔悴，傍人解笑吾人迂。", "書來隔宿發夢寐，便買舴艋隨僮奴。", "山籬語喧聽楖栗，晚閣妝罷懸蜘蛛。", "暫違相見喜定劇，勝似朝夕趨庭隅。", "因子此去傳區區，先從賢翁到吾徒。", "劉郎癯絕今更癯，香岩老人安穩無。"]'),
('cc6d58c9-0d09-4e0b-b5dd-f252859e21a4','採藤行','戴表元','宋','宋诗','song-poetry','','[]','君不見四明山下寒無糧，九月種麥五月嘗。',163,'全唐诗/poet.song.243000.json','["君不見四明山下寒無糧，九月種麥五月嘗。", "一春辛苦無別業，日日採藤行遠岡。", "山深無虎行不畏，老少分山若相避。", "忽然遇藤隨意斫，手觸藤花落如蝟。", "藤多力困一顰呻，對面聞聲不見人。", "日昃將來各休息，妻兒懶拂竈中塵。", "須臾叩門來海賈，大藤換糧論斛數。", "小藤輸市亦值錢，糴得官粳甜勝乳。", "明朝滿意作晨炊，飽飯入山須晚歸。", "南村種麥空早熟，逐日扃門忍饑哭。"]'),
('134c3d67-7ef0-4277-8dfe-61d3798719a3','杖錫虎','戴表元','宋','宋诗','song-poetry','','[]','杖錫山中深，與世絕往還。',306,'全唐诗/poet.song.243000.json','["杖錫山中深，與世絕往還。", "從來稱是仙聖窟，虎暴不得奸其間。", "今年山神大失職，虎來山前搏人食。", "傳聞此義我亦怪，歷問更爲居者惜。", "杖錫山中民，獷健疏農耕。", "老稚爲樵壯爲獵，朝朝暮暮山中行。", "山獐野雉收當糧，天寒果熟霜狸香。", "腰弓度壠矢插房，黄茅覆溪機半張。", "鳥啼犬奔風箭急，機鳴未發且前立。", "平生聞虎不識面，顛倒窮途忽相及。", "驚呼頓迅聲漸微，妻兒駭呀不即歸。", "循蹤走至設機處，但有血漬斕斑衣。", "嗚呼哀哉乎，此民良足悲。", "嗚呼嗟哉乎，此事不足疑。", "吾聞以毒殃物者，物亦以毒殃其身，我不敢以爾爲仁。", "以餌鈎物者，物亦鈎爾以爲餌，我不敢以爾爲智。", "杖錫山，山絕深，無虎不必古，有虎不必今。", "天生此物居山林，有虎無虎視爾心。", "但令爾心無干戈，虎居深山奈爾何。"]'),
('043d9467-3358-42ce-b146-5c11faa0eaa7','少年行贈袁養直','戴表元','宋','宋诗','song-poetry','','[]','我昔如君初冠時，見君垂角兒童嬉。',128,'全唐诗/poet.song.243000.json','["我昔如君初冠時，見君垂角兒童嬉。", "君今長大一如我，但少頭上斑斑絲。", "誦書如流日千紙，更出清言洗紈綺。", "明珠在側真自失，挾冊茫洋吾老矣。", "人言四十當著書，春風半負黄公壚。", "僮奴哂笑妻子駡，一字不給饑寒軀。", "儒學無成農已惰，履窮始悔知無奈。", "人生少年還易過，請君努力無如我。"]'),
('e5caef69-e758-4aea-9d52-af25ff70c81e','義蜂行','戴表元','宋','宋诗','song-poetry','','[]','山翁愛蜂如愛花，山蜂營蜜如營家。',384,'全唐诗/poet.song.243000.json','["山翁愛蜂如愛花，山蜂營蜜如營家。", "蜂營蜜成蜂自食，翁亦藉蜜裨生涯。", "每當山蜂採花出，翁爲守關司徼遮。", "朝朝暮暮與蜂狎，頗識蜂群分等差。", "一蜂最大正中處，千百以次分來衙。", "叢屯雜聚本無算，勢若有制不敢譁。", "東園春晴草木媚，漫天蔽野飛橫斜。", "須臾駢翼致雋永，戢戢不翅輸牛車。", "似聞蜜成有所獻，儔類不得先摩牙。", "重防覆衛自嚴密，雖有毒螫何由加。", "一朝大蜂出不戒，舂容靚飾修且姱。", "蜻蜓忽來伺其怠，搏擊少墜遭蝦蟆。", "群蜂倉皇迷所適，謁走欲死聲呀呀。", "求之不得久乃定，復結一聚猶如麻。", "我來訪翁親目睹，搏髀不覺長咨嗟。", "翁言蜂種幸蕃盛，衆以義聚猶堪嘉。", "烏衣槐安傳自古，蠻觸分據兩角蝸。", "雖云彷彿存國族，徒以紀異其辭夸。", "博勞舅婦恨翼短，鱉靈異姓爭荒遐。", "豈如茲蜂互推舉，一體同氣無疵瑕。", "我憐翁言私誚責，扶傷早愧隋侯蛇。", "况伊二毒俱下類，瑣細不足勞鞭撾。", "前尤往悔俱勿論，事會倚仗來尚賒。", "新房才成蜂未壯，舊房委棄墜泥沙。"]'),
('ff979747-276f-465d-9bf3-ffb330096e65','雪後况湖歌','戴表元','宋','宋诗','song-poetry','','[]','君不見明州城中日月湖，縈藍繚白如畫圖。',179,'全唐诗/poet.song.243000.json','["君不見明州城中日月湖，縈藍繚白如畫圖。", "良時樂遊古亦有，何人破雪浮官厨。", "金猊暖壓紅氍毹，紫貂醉拂青珊瑚。", "麈尾高懸前唾壺，使君霜髯雙臉朱。", "同時僚客總豪秀，陸池閬苑羅仙儒。", "名談鋒湊初不惡，安得玉人歌縷珠。", "似聞州民喜公出，終日繞岸狂歡呼。", "淫弦濁管何足道，入耳得此成真娛。", "城尖數峰大糢糊，山郭何路通樵蘇。", "年年臘前得三白，樂歲仍然多餓夫。", "定知新年稍安樂，風流使君江左無。"]'),
('4184b268-eb68-4511-86d5-1ef58842aefe','山苕行','戴表元','宋','宋诗','song-poetry','','[]','苕花如雲色如雪，萬壠千溪看不絕。',96,'全唐诗/poet.song.243000.json','["苕花如雲色如雪，萬壠千溪看不絕。", "風吹日炙自鮮明，棄在空雲誰愛悅。", "遭逢偶入山人手，縛作蓬菘掃塵帚。", "髯疏髮落已蕭然，時對西風一回首。", "人間貴賤不須論，此物古來從至尊。", "猶勝長拋霜露裏，秋蟲野燐愁枯根。"]'),
('ea6c00d4-4479-4541-be40-f3e514b52106','啄木行贈凈珇上人','戴表元','宋','宋诗','song-poetry','','[]','東園嘹嘹還剝剝，有鳥晨饑啄霜木。',64,'全唐诗/poet.song.243000.json','["東園嘹嘹還剝剝，有鳥晨饑啄霜木。", "天寒蟲豸得幾何，爪觜披猖良爲腹。", "華堂蝙蝠添毛衣，飛蚊凈盡何處歸。", "海山野鶴亦有饑，饑絕不向人前飛。"]'),
('d5def20d-6ce3-46ea-b3f7-6b6efa2aaee1','又坐隠辭','戴表元','宋','宋诗','song-poetry','','[]','快馬疾馳，不如徒步。',170,'全唐诗/poet.song.243000.json','["快馬疾馳，不如徒步。", "多金善賈，不如躬耕。", "日食八珍，不如强飯。", "封侯萬里，不如還鄉。", "我觀古來丈夫子，何用桑弧蓬矢射四方。", "蘇秦生爲六印役，主父死願五鼎烹。", "不如諸葛草間談管樂，陶潜醉裏傲羲皇。", "南面之尊何如於據梧之賤，環轍之智無預於荷蓧之狂。", "高岡峻谷久亦變，青天白日晝夜行茫茫。", "胡爲憂愁浪自苦，百年齒髮誰得長堅强。", "不如掩關掃跡成坐隠，清齋永日一爐香。"]'),
('20b9beca-938a-453a-80eb-89fe0e8cf4bd','賦意未暢復拾前韻之餘者作廣坐隠辭','戴表元','宋','宋诗','song-poetry','','[]','我作坐隠辭，客來問我坐隠方。',358,'全唐诗/poet.song.243000.json','["我作坐隠辭，客來問我坐隠方。", "開門進客還復坐，爲客歷落言其詳。", "隠朝市，我不能衝塵冒暑走遑遑。", "隠江湖，我不能披蓑戴笠操舟航。", "隠山林，山林白晝行虎狼。", "隠田里，田里赤立無資糧。", "窮觀六合內，投隠幾無鄉。", "是以古來人，失路多猖狂。", "或隠伶官俠客，或隠藥肆僧房。", "或爲君平隠賣卜，或稱陶朱隠行商。", "雖能逃世網，於事未爲良。", "况我難携一身隠，二親白髮垂高堂。", "神仙拔宅古亦有，無翼不得高飛颺。", "不然少自屈，歸去隠耕桑。", "隨傭竭作既無一夫力，買田築室又乏千金裝。", "僮奴揶揄親友棄，往往人厄非天殃。", "悲來俯仰尋隠處，欲親書冊依杯觴。", "引酒未一酌，狂風鬰律衝肝腸。", "讀書未一卷，噫嗚感慨淚浪浪。", "酒能觸人生憤激，書能覽古知興亡。", "非徒不足充隠具，反緣二物來自戕。", "覆杯掩卷且默坐，氣定始覺如平常。", "因思世上百千事，是非榮辱俱可忘。", "楊朱墨翟悲泣兩無益，伯夷叔齊浪死埋首陽。"]'),
('e1deeb9b-5140-42f3-a693-71adb2116b89','行婦怨次李編校韻','戴表元','宋','宋诗','song-poetry','','[]','赤城巖邑今窮邊，路傍死者相枕眠。',166,'全唐诗/poet.song.243000.json','["赤城巖邑今窮邊，路傍死者相枕眠。", "惟餘婦女收不殺，馬上娉婷多少年。", "蓬頭垢面誰氏子，放聲獨哭哀聞天。", "傳聞門閥甚輝赫，誰家避匿山南巔。", "蒼黄失身遭惡辱，鳥畜羊縻驅入燕。", "平居鄰牆不識面，豈料萬里從征鞭。", "酸風吹蒿白日短，天地闊遠誰當憐。", "君不見居延塞下明妃曲，惆悵令人三過讀。", "又不見蔡琰十八胡笳詞，慚貌千年有餘戮。", "偷生何必婦人身，男兒無成同碌碌。"]'),
('9c502175-f7a3-4eb2-b918-9a650aa0d711','飛花行贈馬衢州','戴表元','宋','宋诗','song-poetry','','[]','山上風花山下飛，花飛欲盡山翁歸。',128,'全唐诗/poet.song.243000.json','["山上風花山下飛，花飛欲盡山翁歸。", "歸來亦自忘行跡，但覺滿地紅依依。", "餘花更惜隨春去，溪上遊人山下路。", "戀家漁父斷來蹤，難老劉郎記前度。", "花開花落春風前，我昔與翁同少年。", "祇今鶴去但華表，何處鳥啼悲杜鵑。", "遊人自遊春自暮，從翁問花花不語。", "且當向花日日醉，醉倒花前學花舞。"]'),
('9fc96d41-34d7-44ee-8e25-ae39abcb5b2f','織錦迴文','戴表元','宋','宋诗','song-poetry','','[]','君不見秦州城中雙蔕花，春風吹散著流沙。',67,'全唐诗/poet.song.243000.json','["君不見秦州城中雙蔕花，春風吹散著流沙。", "流沙千縈復萬轉，織入綵機歌不斷。", "歌不斷，可奈何，人生富貴憂患多。", "不如窮山饁田婦，白頭不識遷移苦。"]'),
('de4800fe-4230-407b-8bbd-b7e1e4caf833','石湖范至能嘗作姑惡詞以爲婦怨非天下之爲婦者所願聞故作續姑惡詞以廣之','戴表元','宋','宋诗','song-poetry','','[]','姑惡姑不惡，人言姑惡人豈知，爲姑作婦百不辭。',82,'全唐诗/poet.song.243000.json','["姑惡姑不惡，人言姑惡人豈知，爲姑作婦百不辭。", "婦在姑尚可，婦死姑方悲。", "恐傷姑意不敢違，化作異物鳴無時。", "姑不惡，姑不惡，怨姑還當被姑責。", "但願生身復作婦，死別不如生見樂。"]'),
('608750ce-6f45-4ae2-b7c8-74ac88bca6c8','余博士家貓相乳歌','戴表元','宋','宋诗','song-poetry','','[]','上饒余宗鐘鼎家，孫枝十世猶清華。',240,'全唐诗/poet.song.243000.json','["上饒余宗鐘鼎家，孫枝十世猶清華。", "南昌博士最賢者，膝下燁燁開緋牙。", "我行其庭值供頓，食指半千聲不譁。", "女帨男鞶况修謹，冠立童趨知等差。", "江南族聚盛亦有，如此禮法嘻可嘉。", "長公公退忽語我，瑞貓之篇題滿車。", "二雌同時各生子，一雌病僵如卧瓜。", "一雌端來代其乳，顧睨懇惻呼嚶啞。", "子衆身疲乳亦竭，病母起將新乳加。", "天寒繡褥更枕藉，日暖花磚群戲拏。", "我憐二貓有至性，欲脫毛尾升笄珈。", "北平將門粱肉窟，此事尚得昌黎誇。", "公家儒化鬰積久，義感宜可馴豚猳。", "願公盡力持閫範，彌補始終無闕瑕。", "不見古來歌舞地，祇餘猿鶴與蟲沙。"]'),
('17b43c00-1598-4a4f-a702-33cea2b08ddf','贈天台潘山人','戴表元','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','老潘雙眸如紺珠，带以秋陽朝露之清腴。',252,'全唐诗/poet.song.243000.json','["老潘雙眸如紺珠，带以秋陽朝露之清腴。", "山形水態出沒千百變，經君指顧不得藏錙銖。", "我昔少年好狂走，風餐雨沐逐逐忘朝晡。", "至今卧遊想共處，但覺雲濤烟瘴千里行須臾。", "匡廬春風鍾阜雲，彭浪之磯大小飛來孤。", "秦淮震澤洞庭野，峨眉縹緲南接五嶺東蒼梧。", "歸來把鋤剡山下，有時一竿釣月賀家湖。", "籠鷹櫪馬困羈束，每逢風鳴草驚動號呼。", "聞君談診到骨髓，褰衣振迅恨不六翮生形軀。", "尋牛卜龍古所有，君家祖孫三葉傳青烏。", "人言河流可移山可鑿，秦皇漢武已類愚公愚。", "相留徘徊山南山北一百里，勝處忽然開酒壺。", "問渠劉伶一童一鍤欲何用，且可從我日日醉倒黄公壚。"]'),
('d09ac70a-9b8c-4ca4-81d6-615d5e532be7','范文正公黄素小楷昌黎伯夷頌蓋宋皇祐三年十一月在青社所書以遺京西轉運使蘇公舜元者也後二百四十年大興李侯戡得此本於燕及南來守吳乃文正公鄉里即訪公子孫以畀之范氏喜而索詩爲贈','戴表元','宋','宋诗','song-poetry','','[]','有耳不聽下里巴人，有手不寫劇秦美新。',164,'全唐诗/poet.song.243000.json','["有耳不聽下里巴人，有手不寫劇秦美新。", "天生靈物寄我體，可惜穢棄同埃塵。", "清風百世希文老，一字流傳今是寶。", "誰知堂堂伯夷頌，曾借春暉發枯槁。", "韓子也復英雄姿，冰寒斗峻餘文辭。", "吹噓自起北海隠，膾炙聊慰西山饑。", "天荒地老精靈在，處處江湖紅散彩。", "青離孔氏忽自歸，今遇龔侯如有待。", "世情愛古兼愛奇，書奴滿眼非吾師。", "請君焚香盥手拜此帖，歸洗人間兒女癡。"]'),
('06467ae5-2377-4be9-9309-ed2a8f919451','送程敬叔教諭赴建平','戴表元','宋','宋诗','song-poetry','','[]','爾之王父東諸侯，朱門行馬高修修。',192,'全唐诗/poet.song.243000.json','["爾之王父東諸侯，朱門行馬高修修。", "嚴君家學又繼美，年少鄉書推上游。", "我生苦晚百無益，猶及步趨陳太丘。", "飄零不死見三世，爾復預此能言流。", "風神清羸談炙轂，生理蕭條書汗牛。", "今年別我忽遠役，天馬放靶難停留。", "問渠何官縣博士，橫山之西江東陬。", "此邦固是吳楚會，風淳土朴衣冠稠。", "亦聞岩谷多古跡，最喜道途稀使騶。", "公堂講罷看山坐，香鼎茶鐺相勸酬。", "熱官千騎豈不好，白日公庭愁督郵。", "飲水茹藥善自愛，歲晚相期釣滄洲。"]'),
('ce4aa446-ad52-4017-bb59-305c8f58e68f','題陳貴白畬齋','戴表元','宋','宋诗','song-poetry','','[]','海山作農農較苦，累級開畬燒宿莽。',64,'全唐诗/poet.song.243000.json','["海山作農農較苦，累級開畬燒宿莽。", "畬成得粟不償勞，歲晚空瓶誤饑鼠。", "不如陳郎腹果然，日日閉門耕紙田。", "餘糧尚許餉遠客，植來時和南風篇。"]'),
('4742476b-63ed-4e28-bced-40e4572244eb','余既題畬齋有聞紙田之說而笑者復作長篇','戴表元','宋','宋诗','song-poetry','','[]','學農無年尤可待，學儒無成祇益餒。',240,'全唐诗/poet.song.243000.json','["學農無年尤可待，學儒無成祇益餒。", "羨君終歲作書癡，聚室嗷嗷窮不悔。", "客來問計何所出，一飽自懸饘粥外。", "平生據案畎畝心，汗簡爲犂筆爲耒。", "蘗芽百氏草避耨，膏澤群經泉赴澮。", "日高洛誦烏鳥悅，夜半吳吟風雨會。", "世間粱穀何足道，開卷穰穰心欲醉。", "旅熏辟蠹防雀鼠，更繕巾箱築倉廥。", "古言樂歲生禮義，先見儒門消鄙悖。", "租符且免里正索，子本時容書客儈。", "東鄰有田多牛翁，日執牙籌親細碎。", "囷糧竟作誰腹飽，騎吏驚惶汗流背。", "此時畬齋談無事，峨冠正與周孔對。", "禮義適口即爲味，牛心菊苗皆可膾。", "我詩君意兩自知，且勿譊譊語兒輩。"]'),
('902324e8-d490-41b1-b353-5b9fb343055a','剡箋送任叔實','戴表元','宋','宋诗','song-poetry','','[]','剡溪春水碧鱗鱗，剡水野藤如亂雲。',128,'全唐诗/poet.song.243000.json','["剡溪春水碧鱗鱗，剡水野藤如亂雲。", "剡人伐藤就溪洗，匠出素箋黄土紋。", "大箋敷腴便竿牘，小箋輕盈日千束。", "我昔少年貪著纂，累笥連箱輸不足。", "年來棄置百事休，引腕就書如畏囚。", "有時得箋不自愛，杜曲蠻歌相獻酬。", "世人貴賤隨人好，西家棄物東家寶。", "退筆成山何足道，爲我攻修太玄草。"]'),
('e73c85ad-c0ee-4dfc-8a83-7f74a23f4ed7','次韻和郭祐之雙桔堂趙母壽詩','戴表元','宋','宋诗','song-poetry','','[]','嚴親不待高官秩，一刻歡娛勝千日。',64,'全唐诗/poet.song.243000.json','["嚴親不待高官秩，一刻歡娛勝千日。", "趙郎宦薄母八旬，自採芳甘充俎實。", "堂前酣酣雙桔紅，童兒見客笑滿容。", "有田得耕我亦去，繡衣御史語生風。"]'),
('42a44e9a-f97c-47a5-9cad-34e041f079d5','醉歌贈袁茂才','戴表元','宋','宋诗','song-poetry','','[]','君休呫囁語，我欲顛狂歌。',154,'全唐诗/poet.song.243000.json','["君休呫囁語，我欲顛狂歌。", "君語雖工不可多，我歌顛狂如我何。", "君不見蘇季子，腰橫六印車如水，奇禍一朝生口齒。", "又不見朱買臣，朱綬煌煌不庇身，不如會稽喑啞人。", "南山山頭北山下，亦有騎牛唱歌者。", "行人不訶官不問，歌罷牛歸卧牛舍。", "我歌屬君君爲歌，桃花醉面春風和。", "君歌不成春亦老，虛客江城車馬道。", "明日酒醒應絕倒，剡源溪上看芳草。"]'),
('8052ef27-e543-4d18-9fb9-aa783e147010','題范道士來鶴亭','戴表元','宋','宋诗','song-poetry','','[]','仙客已騎黄鶴去，道人自愛白鷗閒。',64,'全唐诗/poet.song.243000.json','["仙客已騎黄鶴去，道人自愛白鷗閒。", "白鷗萬里猶可狎，黄鶴已去何由還。", "借君剛風七龍轡，返此靈物三神山。", "天空海闊望不極，回首正落樊籠間。"]'),
('1edd865d-6b5a-4769-8827-f31a1a58fbc0','題李伯時畫五馬圖','戴表元','宋','宋诗','song-poetry','','[]','嗚呼良馬不世出，今人但尋李侯筆。',128,'全唐诗/poet.song.243000.json','["嗚呼良馬不世出，今人但尋李侯筆。", "五龍忽墮白雲鄉，海角孤臣看自失。", "太平天子開明堂，前驅麒麟後鸞凰。", "當時此馬來萬里，想見顧盼生風霜。", "龍眼老仙亦如此，揮毫談笑群公裏。", "官閒祿飽少塵埃，霧閣雲窗天上起。", "風流轉眼餘山河，人間荆棘何其多。", "臨風卷圖三太息，此馬今存知奈何。"]'),
('5c24c4fa-63b9-454f-9c8e-9c5ae9d42f5f','孫使君飛蓬亭','戴表元','宋','宋诗','song-poetry','','[]','江南澤國多烟水，年少輕身作遊子。',200,'全唐诗/poet.song.243000.json','["江南澤國多烟水，年少輕身作遊子。", "適來衰懶畏奔馳，忽見飛蓬平地起。", "飛蓬主人人中仙，曾乘千斛凌風船。", "船頭畫鼓催行酒，船尾紅妝歌采蓮。", "收篙卷綸今尚樂，却悔從前風浪惡。", "青雲裘褐一鷗身，白髮山林五湖客。", "我來花霧紅霏霏，此蓬如山何處飛。", "但當共坐索酩酊，溪塘過雨春魚肥。", "君不見鴟夷名成滄海去，富貴畏人如脫兔。", "又不見羊裘釣客桐江上，一出張皇動星象。", "何如飛蓬主人亭上飲，醒與客論酣即寢。", "寢酣忽作江湖夢，風雨漂摇蓬不動。"]'),
('9bd2d2d7-ef87-449b-bf98-91d100e08113','題峴山圖','戴表元','宋','宋诗','song-poetry','','[]','山頭種石懸蒼雲，山下急流風卷紋。',131,'全唐诗/poet.song.243000.json','["山頭種石懸蒼雲，山下急流風卷紋。", "何年荒碑當嶺立，龜趺圭首猶鱗皴。", "神龍驅毫鬼輸墨，羊公精神荆楚色。", "想當意匠經營初，已盡東南烟霧迹。", "從來登覽非真遊，襄人正樂吳人愁。", "尊前鄒湛亦不惡，江山千古同悠悠。", "君不見征南後來人姓杜，自喜作碑心更苦。", "祇留陳迹笑癡迷，行客何曾淚如雨。"]'),
('0f10e0ec-76a3-41fb-873d-523488a4e1c7','看花曲','戴表元','宋','宋诗','song-poetry','','[]','種花郎君愛花好，看花兒女笑花老。',166,'全唐诗/poet.song.243000.json','["種花郎君愛花好，看花兒女笑花老。", "牆東花開閙喧喧，馬蹄蹴醉牆西草。", "遊人賤草只看花，明日重來還可嗟。", "但見萋迷青覆地，千紅萬紫成泥沙。", "君不聞明妃當年辭漢宮，黄雲塞下白楊風。", "一朝邊亭靜烽火，詔書自議麒麟功。", "又不聞馬嵬山前玉環血，歲歲春風吹不滅。", "詞人正賞浯溪碑，千秋妖恨無人說。", "紅顔誤人何足憐，花開花謝春風前。", "猶勝凄凉後庭樹，離歌未斷江南暮。"]'),
('c00b2069-4244-4ee3-bf4c-dd9eb42d1295','東門行二首  其一','戴表元','宋','宋诗','song-poetry','','[]','春風顛狂卷地起，吹動江城寒劫灰。',64,'全唐诗/poet.song.243000.json','["春風顛狂卷地起，吹動江城寒劫灰。", "江城千家丹碧窟，過眼不復餘樓臺。", "九輈燭龍竟爲爾，六尺海鴟安在哉。", "平原無人金谷散，惆悵東門歸去來。"]'),
('64ccb911-a2bc-49ac-ad7c-0af47292e7a7','東門行二首  其二','戴表元','宋','宋诗','song-poetry','','[]','松枝可餐不可久，蕨萁可舂難入手。',64,'全唐诗/poet.song.243000.json','["松枝可餐不可久，蕨萁可舂難入手。", "書生身業值無年，翰墨千囷不充口。", "烟州何客釣寒魚，江郭誰門倚殘柳。", "琴臺歌管無處尋，惆悵東風幾回首。"]'),
('c59f287a-9c36-455f-8d78-b0e72a1bf718','江行雜書','戴表元','宋','宋诗','song-poetry','','[]','荒城日暮秋江長，䆉䅉野熟秋風香。',240,'全唐诗/poet.song.243000.json','["荒城日暮秋江長，䆉䅉野熟秋風香。", "青天茫茫不知處，扁舟卧入菰蒲鄉。", "波深浪靜魚鴨樂，遥林墮影同飛揚。", "平生見畫無此本，便欲默寫懸高堂。", "須臾雷雨漲深墨，漁戶悉閉收牛羊。", "篙人軟語似憐我，拗蓬蓋頭編蒿牀。", "此時殘怒尚什七，瀟灑幸爲清蚊蝱。", "無人靜覺物性出，蚯蚓草蟲歌晚凉。", "銅山乳竇青最遠，羞縮不似來時妝。", "但餘田鳥如匹練，雙雙飛點暗烟黄。", "山川一日幾變態，人事百年安可常。", "停舟起問魚酒戶，此地幾年成戰場。", "虹梁羽化新起廢，白骨無數埋前岡。", "惆悵令人百憂起，飲客正酣歌發狂。", "坐中悲樂誰竟是，歸來玉兔摇滄浪。"]'),
('617d6431-ae00-4045-bc42-5f7188fe90bb','吳姬曲五首  其一','戴表元','宋','宋诗','song-poetry','','[]','吳姬來，吳船蕩漾湖花開。',44,'全唐诗/poet.song.243000.json','["吳姬來，吳船蕩漾湖花開。", "隔堤迎笑欲飛舉，不用少年多槳催。", "問君青春得幾許，看取架上紅玫瑰。"]'),
('3f94a1d3-91e7-4424-9342-92d94d32d526','吳姬曲五首  其二','戴表元','宋','宋诗','song-poetry','','[]','吳姬歌，歌聲宛宛歌情多。',44,'全唐诗/poet.song.243000.json','["吳姬歌，歌聲宛宛歌情多。", "當尊一闋且呼酒，酒遍餘聲無奈何。", "春風顛狂亦如我，坐見花外摇湖波。"]'),
('6215703d-dab6-431d-b775-9733871bbe33','吳姬曲五首  其三','戴表元','宋','宋诗','song-poetry','','[]','吳姬舞，朝看成雲暮看雨。',44,'全唐诗/poet.song.243000.json','["吳姬舞，朝看成雲暮看雨。", "偶然欲笑一回眸，錦段金錢落如土。", "誰家學取野鴛鴦，終日癡迷弄沙浦。"]'),
('6f7a6a52-76a0-4b19-8864-3085e440c609','吳姬曲五首  其四','戴表元','宋','宋诗','song-poetry','','[]','吳姬醉，濃花爛蕊春憔悴。',44,'全唐诗/poet.song.243000.json','["吳姬醉，濃花爛蕊春憔悴。", "當筵賭令諱空拳，忘却拈三并數四。", "坐中癡客儘偷看，翠軃雲翹欹不墜。"]'),
('2517a971-c6fe-4a37-bfcc-ef6fa3525a46','吳姬曲五首  其五','戴表元','宋','宋诗','song-poetry','','[]','吳姬歸，潮光燭影紅輝輝。',44,'全唐诗/poet.song.243000.json','["吳姬歸，潮光燭影紅輝輝。", "中心有語不敢吐，安得作月生汝衣。", "明朝花下更須醉，放取後園鶑燕飛。"]'),
('0a542d22-9cbf-412c-8fb6-00f6f1d216e2','達觀亭歌爲建康徐氏作','戴表元','宋','宋诗','song-poetry','','[]','天風颯爽巖曦開，雲溪縈環芳樹來。',160,'全唐诗/poet.song.243000.json','["天風颯爽巖曦開，雲溪縈環芳樹來。", "林棲島處眼未識，何人擇勝誅荒萊。", "仙跡著人清辟易，徐郎襟懷趙郎筆。", "經營須通山鬼意，開鑿曾煩祖龍力。", "高亭一區尤絕塵，滄浪捧足芙蓉雲。", "憑危醉歌敞花氣，九衢塵土何紛紛。", "客來問名名達觀，對此心情轉蕭散。", "想見千秋爭戰場，只把雲霞眼中換。", "浮名絆人茲可憐，飛鴉落日釣窗前。", "何時真脫塵纓去，我自網魚君刺船。"]'),
('5aa47002-a871-40cc-8d18-0d1d24b63a89','春愁曲次劉正仲韻','戴表元','宋','宋诗','song-poetry','','[]','山翁隠居雁蒼谷，春樹年年爲翁綠。',256,'全唐诗/poet.song.243000.json','["山翁隠居雁蒼谷，春樹年年爲翁綠。", "耕休坐樹作勞歌，山光水影相徵逐。", "歌成無人祗自娛，行人頗怪歌聲殊。", "循蹤歷歷見井舍，恐是避秦來此居。", "花烟溟濛亂晴雨，山前倉庚後杜宇。", "客來不喜亦不驚，但道寒暄無俗語。", "山中今歲是何年，黄旗徵樹裝樓船。", "淺村已盡到深谷，逢人未說先凄然。", "憂來宛轉歌不已，我樹非材端後死。", "五陵當日蓊如雲，如今何處悲風起。", "山南老農亦不憂，機淺不爲妻子謀。", "日高飯飽牛背坐，日晚放牛溪上遊。", "人生逐名被名誤，十年車馬長安路。", "長安路絕雲霧昏，歸來棄筆尋農具。", "舊遊年少難與隨，夢境一笑難重追。", "惟有剡源窮掌固，相思望斷西天垂。"]'),
('ecf52f8a-e409-4513-83aa-8e5c1fa392b6','正仲復有倒和春愁曲之作依次奉答','戴表元','宋','宋诗','song-poetry','','[]','漸老之日來垂垂，已去之日不可追。',256,'全唐诗/poet.song.243000.json','["漸老之日來垂垂，已去之日不可追。", "傷春畏老兩作惡，世事嘗與愁人隨。", "忽得君家遣愁具，行歌日日春溪路。", "不知愁緒逐詩來，更惜芳顔被春誤。", "王孫草暗誰重遊，曲江痛哭窮參謀。", "燕騎琵琶渭城酒，居人不覺行人愁。", "行人欲歸痿念起，白髮逢春心未死。", "水流花落無處尋，燕去鴻來何日已。", "溪村此日更蕭然，强笑爲君呼酒船。", "黄雞喚日不待曉，蟠桃一熟三千年。", "草間管樂真浪語，鳥雀應門蓬柱宇。", "祗餘平世畎畝心，夜半吳吟泣風雨。", "高人與虎能同居，壯士斷蛇應不殊。", "年高漸欲置憂患，每頼君語相調娛。", "昔日劉郎悲放逐，看花惆悵春無綠。", "何如今日春愁曲，爛醉徉狂白雲谷。"]'),
('8ef6ab7b-7ef2-4614-882f-3fd22bb2d047','題趙子昂畫馬','戴表元','宋','宋诗','song-poetry','','[]','趙子奇才似天馬，頃刻飛龍生筆下。',144,'全唐诗/poet.song.243000.json','["趙子奇才似天馬，頃刻飛龍生筆下。", "畫成撫卷復長歌，坐客喧喧不停寫。", "蹄勢經鞭秋跌蕩，鬃毛出跣風蕭灑。", "似嫌文繡減天真，盡脫鞍韉轡輕把。", "青袍洗足巧眉睫，馱坐奚官亦閑雅。", "我來一見驚欲拜，曾識鸞和趨廟社。", "千金朽骨古猶惜，况此難分毛色假。", "瑶池路斷伯樂盡，日暮嘶鳴氣喑啞。", "爲君昂首一慰意，猶勝無逢老岩野。"]'),
('9afcd8c7-d30a-414d-86fe-74f0d4ce955b','南山下行','戴表元','宋','宋诗','song-poetry','','[]','南山高，北山高，行人山下聞叫號。',160,'全唐诗/poet.song.243000.json','["南山高，北山高，行人山下聞叫號。", "旁山死者何姓氏，纍纍骸骨橫林皋。", "鳥喧犬噪沙草白，酸風十里吹腥臊。", "中有一人稱甲族，蔽膝尚著長孺袍。", "不知嬰觸爲何罪，但惜貴賤同所遭。", "妻求抱尸諸子哭，魂氣滅沒埋蓬蒿。", "人言殺身由貨寶，山村豈得皆權豪。", "一言不酬兵在頸，性命轉眼輕鴻毛。", "龍爭虎鬬尚未决，六合一穽何所逃。", "振衣坐石望太白，寒林夜籟聲溞溞。"]'),
('74d25f5e-3be8-4494-b996-db83de5757c9','相逢行贈文伯純同年','戴表元','宋','宋诗','song-poetry','','[]','昔日相逢面如雪，今日相逢面如鐵。',128,'全唐诗/poet.song.243000.json','["昔日相逢面如雪，今日相逢面如鐵。", "人生年少得幾時，動作風塵十年別。", "十年別久未爲惡，頻見亦無年少樂。", "寒棲夜雨金瑣夢，故園春風白袍客。", "雕鞍駿馬紛紛來，西城亂花春漸開。", "與君追逐覺老醜，一笑且醉高陽杯。", "相逢得醉今日好，醉眼相思還易老。", "只圖留君日日醉，醉裏忘却江南道。"]'),
('d538b1c0-ce2a-4da3-88b5-c4d5d9734b12','壽陳貴白','戴表元','宋','宋诗','song-poetry','','[]','祝君以陸地千蹄牛，君言不如扁舟江海狎浮鷗。',246,'全唐诗/poet.song.243000.json','["祝君以陸地千蹄牛，君言不如扁舟江海狎浮鷗。", "祝君以通侯尺二組，君言不如草屋三間卧風雨。", "富貴何人不解頤，君視二物如兒嬉。", "我今贈君亦無物，但有聱牙佶倔村田詩。", "我歌詩，君進酒，客主讙譁起相壽。", "尋常此日費千金，京洛奔馳今白首。", "江風颯颯吹黄塵，對面樓臺不見人。", "與君漂泊爲何事，一笑幸是山林身。", "寡語薄味，足以養氣。", "少求簡出，足以養體。", "奇章鍾乳本斧斤，胡廣菊潭堪唾涕。", "君不見南方屭贔五色龜，窮年引息不嫌饑。", "又不見曲轅擁腫百圍木，匠石捐棄反爲福。", "蝸封蟻壤何足論，歸來未廢蓬蒿園。", "我更搜詩君釀酒，通家德公有賢婦。"]'),
('cdc3c908-d14b-4f27-aa28-b673c0b39ad9','春溪惡寄孫常川','戴表元','宋','宋诗','song-poetry','','[]','春溪惡，日日春風吹過客。',163,'全唐诗/poet.song.243000.json','["春溪惡，日日春風吹過客。", "千車萬轍不相嫌，一客歌來吹倒却。", "旁人借問客爲誰，咸淳朝士今布衣，聲名欲隠人自知。", "君不聞孫興公，逃亂走入黎州峰。", "子孫百世居峰下，往往翰墨餘仙風。", "鶉衣藿食何足恥，頭白河清吾亦俟。", "向來南面五馬車，只飲西山一盂水。", "青牛處處迷行蹤，白鶴歸來餘故宮。", "道逢樵客知去遠，遲君不來三日晚。", "溪水猶能作吳語，似續君家遂初賦。"]'),
('41d25771-837c-482b-a80d-ef0814e83df8','碧桃花歌爲王丞作','戴表元','宋','宋诗','song-poetry','','[]','君不見孔家藏書屋，屋壞猶聞起絲竹。',180,'全唐诗/poet.song.243000.json','["君不見孔家藏書屋，屋壞猶聞起絲竹。", "又不見鄭家註書老，書带後來垂作草。", "如今王家萬卷文字林，桃花一樹春沈沈。", "花成不勞主人種，花落更同山客吟。", "從來春花重萼不綴實，此花可玩實可食。", "我擬天公出奇物，來壽主人并餉客。", "春前待花花下狂，春後待實林下嘗。", "定知此桃不作尋常草木味，祗作舊時文字香。", "王夫子，多釀酒。", "春風亭館何處無，天錫名花祗翁有。", "從翁乞醉三萬日，仍令醉後花從筆間出。"]'),
('81108837-59a1-46d1-9d81-b7310459d51d','王丞分惠碧桃樹再賦奉謝','戴表元','宋','宋诗','song-poetry','','[]','水星之精天上遊，春風歲歲蒼龍頭。',194,'全唐诗/poet.song.243000.json','["水星之精天上遊，春風歲歲蒼龍頭。", "偶然根葉著下土，散作人間百花樹。", "莫疑君家此花無種生，定是天上蒼龍精。", "白玉之趺青玉簇，開花既奇成又速。", "三年方駭大如林，五年已見高踰屋。", "我來吟作書林花，烟塵萬捲重抽芽。", "君家原有孝義種，自來青州丞相家。", "爲君出芝草，芝草那能千日好。", "爲君結琥珀，琥珀恐爲貪者獲。", "不如此花混在春花叢，歲歲與君同春風。", "春風同賞復同吟，願與主人同好心。", "更令此花分作千百本，處處種成君子林。"]'),
('7a4835ad-b0d1-412c-9929-8b623edcde4b','贈趙子實','戴表元','宋','宋诗','song-poetry','','[]','北風吹沙溪倒飛，白日未落山中歸。',128,'全唐诗/poet.song.243000.json','["北風吹沙溪倒飛，白日未落山中歸。", "千邀萬覓不相就，誰信有人穿翠微。", "幅巾大带長襦袍，韋篋錦囊鮮綵毫。", "名門發身合燕頷，一經傳家真鳳毛。", "坐車侯嬴吾不讓，白社寒林氣清放。", "驂麟翳鶴誰不能，要識神光牛背上。", "蓬萊山，丹霞谷，天仙留書三萬軸。", "聞君暫去還復來，許君細和滄浪曲。"]'),
('b9967930-8067-45bf-912e-4ad5b562c7db','積雨小齋喜袁太初舒叔恭兩生至','戴表元','宋','宋诗','song-poetry','','[]','春山日日寒風雨，一日天晴花欲舞。',224,'全唐诗/poet.song.243000.json','["春山日日寒風雨，一日天晴花欲舞。", "林暄洞屋散窯烟，水活溪巖落冰乳。", "嗟余鬰鬰無所適，方對青山一開戶。", "蒼袍紫帢兩少年，健足齊扳氣如虎。", "名區入眼疑未快，忽肯捫蘿到茲土。", "霜蔬處處稀尚摘，臘酒家家寒未煮。", "相看氣味太村野，自喜談諧少城府。", "舒郎十八白眉長，四海龍門有明父。", "袁郎皎潔巧步趨，出語珠圓吾所許。", "人言風骨須晚秀，早慧譊譊天謾與。", "吾評此論殊未公，峻詆曾經孔文舉。", "歌成高軒已年倍，賦解鳴蟬容客覩。", "吾山雖窮有靈跡，雪瀑丹崖相媚嫵。", "留君待作大雷吟，莫學癡兒生吳語。"]'),
('fd4a43f1-4a25-4758-b516-0bbab72893ac','謝李仲賓墨竹','戴表元','宋','宋诗','song-poetry','','[]','君不見李侯筆端如渭川，頃刻匹紙生琅玕。',131,'全唐诗/poet.song.243000.json','["君不見李侯筆端如渭川，頃刻匹紙生琅玕。", "霜柯雪幹鐵石色，忽作小山烟雨寒。", "問君何從得此本，湖州嫌濃眉州軟。", "風軒月檻一相逢，妙處不與人意遠。", "人言學畫先學影，此君風骨青雲並。", "林深有路鳥聲真，日高無人山氣靜。", "平生見此我不疏，逢侯得畫兩有餘。", "從今洗眼空山底，更讀人間瀟灑書。"]'),
('4a7d1001-2512-4f57-b632-9082c1022941','題王敬仲野亭','戴表元','宋','宋诗','song-poetry','','[]','王家野亭蒼翠邊，秋山萬疊相鉤連。',160,'全唐诗/poet.song.243000.json','["王家野亭蒼翠邊，秋山萬疊相鉤連。", "披衣曉霽伴雲坐，散髮夜凉須月眠。", "主人清豪亦好客，常有車蓋來翩翩。", "門閒無煩鶴通謁，酒散有時風掃筵。", "問君生涯幾何許，笑指渺漠滄洲烟。", "朱門千礎扃嬋娟，豪絃急管爭喧妍。", "何曾一日能免俗，稍來對談心爽然。", "古人去遠吾不識，今日汩沒難爲賢。", "長公高談少公和，魯山伯鸞相後先。", "名成但恐累隠趣，莫遣妙語人間傳。"]'),
('1ac41ef8-37e5-4adf-bf36-46ed88496473','贈彈琴衡山蕭道士','戴表元','宋','宋诗','song-poetry','','["\u8861\u5c71"]','寂寂歷歷不足聽，聽久亦復難爲情。',64,'全唐诗/poet.song.243000.json','["寂寂歷歷不足聽，聽久亦復難爲情。", "名嗔勢忿大如屋，袖手對此須臾平。", "一拊再拊玄鶴舞，三四拊之凄風生。", "天寒歲晚行路遠，湘水日夜東南傾。"]'),
('af93a28d-f9dc-4e1c-93de-8ef0a8921cb0','登新嶺','戴表元','宋','宋诗','song-poetry','','[]','犖犖确确白石溪，綿綿茫茫青草鞵。',96,'全唐诗/poet.song.243000.json','["犖犖确确白石溪，綿綿茫茫青草鞵。", "四山陰雪濕灰色，六月杜鵑深樹啼。", "田廬經漂有高下，麻豆滿塢無東西。", "隔岩飛流送人語，對面喧風吹馬蹄。", "祗今莫辭楖栗杖，與子更上巑岏梯。", "登高意遠會有極，回首烟海令人迷。"]'),
('bd28ddc8-821c-4444-860c-04ada48c99f4','送葉伯幾赴奉化錄','戴表元','宋','宋诗','song-poetry','','[]','君不見東海獰龍子，學飛便逐風雲起。',114,'全唐诗/poet.song.243000.json','["君不見東海獰龍子，學飛便逐風雲起。", "又不見西域豪馬駒，墮地一日能馳驅。", "葉家翁季亦如此，一經接武成師儒。", "毛錐如風腹如笥，快書疾讀三千字。", "頗聞曾下仲舉榻，不爲頻通禰衡刺。", "臺書翩翩江上來，吾州自古多賢才。", "裹琴携硯速相就，爲子歸掃山中萊。"]'),
('41e241a0-ec14-4fa4-b7f7-5a5a65a828b2','歲晚次韻答李在明','戴表元','宋','宋诗','song-poetry','','[]','墨鄉守墨不作惡，歲晚左就醉鄉公。',32,'全唐诗/poet.song.243000.json','["墨鄉守墨不作惡，歲晚左就醉鄉公。", "何人吾伊驚夜半，大雪北窗歌國風。"]'),
('1e69cda0-27b3-4be4-9bdd-46ac1c499f65','仇山圖','戴表元','宋','宋诗','song-poetry','','[]','仇山山下仇山人，白頭宦學走風塵。',66,'全唐诗/poet.song.243000.json','["仇山山下仇山人，白頭宦學走風塵。", "問渠家在山何處，雲氣漫漫不知路。", "詩人作事例多癡，逢山且畫且題詩。", "不如鄰翁不識詩與畫，一生耕釣仇山下。"]'),
('3352ef61-7046-4258-8d06-d046215dde48','三次韻寄戴祖禹','戴表元','宋','宋诗','song-poetry','','[]','同分剡溪派，自喜小王書。',48,'全唐诗/poet.song.243000.json','["同分剡溪派，自喜小王書。", "野服調驍馬，濃香薰蠹魚。", "歲時趨闕里，早晚上公車。", "與我真兄弟，風流但不如。"]'),
('60ad2f41-c5bb-48bd-8b19-bf72e47aabcd','苕溪','戴表元','宋','宋诗','song-poetry','','[]','六月苕溪路，人看似若耶。',48,'全唐诗/poet.song.243000.json','["六月苕溪路，人看似若耶。", "漁罾掛棕樹，酒舫出荷花。", "碧水千塍共，青山一道斜。", "人間無限事，不厭是桑麻。"]'),
('b43553ca-6e87-4b5e-8c82-16bba4bf71c1','道桐川欲訪梅右司不知其處','戴表元','宋','宋诗','song-poetry','','[]','桐川瀟灑處，面面碧芙蓉。',48,'全唐诗/poet.song.243000.json','["桐川瀟灑處，面面碧芙蓉。", "峻塔當關獨，清溪抱郭重。", "市多吳客語，祠有漢時封。", "欲覓梅仙去，知藏第幾峰。"]'),
('5e225449-f500-4426-ac1b-34cc8cd1ed93','故總幹潘伯可從大挽詞二首  其一','戴表元','宋','宋诗','song-poetry','','[]','落落知難久，堂堂竟不還。',48,'全唐诗/poet.song.243000.json','["落落知難久，堂堂竟不還。", "江湖官七品，風雨屋三間。", "已矣烏頭白，嘻乎豹管斑。", "兒曹莫輕脫，英爽在空山。"]'),
('666e0248-3e52-402c-9be7-051fe8e42138','故總幹潘伯可從大挽詞二首  其二','戴表元','宋','宋诗','song-poetry','','[]','得死何須哭，偷生正可疑。',48,'全唐诗/poet.song.243000.json','["得死何須哭，偷生正可疑。", "倉皇歸印日，慷慨却金時。", "規矩諸郎有，襟懷我輩知。", "平生郭有道，消得蔡公碑。"]'),
('3ee9f7f5-0b0a-4151-a96d-c978bb8e2c5e','和鄧善之秋興二首  其一','戴表元','宋','宋诗','song-poetry','','[]','鬢髮日夜老，神仙那可求。',48,'全唐诗/poet.song.243000.json','["鬢髮日夜老，神仙那可求。", "楊雄識字苦，玄晏著書愁。", "碧酒紅蓮夜，朱絃白雁秋。", "論心得少暇，同上最高樓。"]'),
('146c088c-a7fe-42bc-ad00-e967dfae57ba','和鄧善之秋興二首  其二','戴表元','宋','宋诗','song-poetry','','[]','鶴化城猶在，龍移井未枯。',48,'全唐诗/poet.song.243000.json','["鶴化城猶在，龍移井未枯。", "百年吾道半，六合此身孤。", "西山栽花屋，東風賣酒壚。", "徉狂覓耆舊，處處土音殊。"]'),
('cfed1d4d-d5c8-44ba-adee-a57f4f3cb3d7','渡長泖投小蒸邵教授宿','戴表元','宋','宋诗','song-poetry','','[]','清曉浮雙槳，黄昏值一餐。',48,'全唐诗/poet.song.243000.json','["清曉浮雙槳，黄昏值一餐。", "風鳴長泖浪，雲掩小蒸村。", "饞極知鱸美，驚還覺雁喧。", "同袍恩有愛，燈火細溫存。"]'),
('af3db224-45f1-41d0-b1cc-904b5c05493e','客遊','戴表元','宋','宋诗','song-poetry','','[]','客遊吳楚地，最好是秋天。',48,'全唐诗/poet.song.243000.json','["客遊吳楚地，最好是秋天。", "三泖團臍蟹，雙溪縮項鯿。", "桂林雲頂寺，蘆蕩月中船。", "酒醒□□雁，猶勝聽杜鵑。"]'),
('a32ce52b-e737-4d77-af06-6de6ae5b3da0','自宣州至湖州風雪中十日始達','戴表元','宋','宋诗','song-poetry','','[]','江湖老未休，十日走三州。',48,'全唐诗/poet.song.243000.json','["江湖老未休，十日走三州。", "南雪馬沒耳，北風船打頭。", "窮猶携筆硯，寒欲貰衣裘。", "漸喜家鄉近，兒童浙語稠。"]'),
('70d527bc-de35-45ad-9294-c3fd6c75948a','十二月二十三日華亭小泊','戴表元','宋','宋诗','song-poetry','','[]','一一歌遊處，今年又寂寥。',48,'全唐诗/poet.song.243000.json','["一一歌遊處，今年又寂寥。", "雞聲生塢樹，蜃氣雜江潮。", "斑白尋遺老，丹青詫麗譙。", "衰懷緣子女，不憚往來遊。"]'),
('0fa643da-f2e6-40cd-899c-316918daa1ec','次韻答應德茂雪後遠寄','戴表元','宋','宋诗','song-poetry','','[]','山中不來久，何處度殘年。',48,'全唐诗/poet.song.243000.json','["山中不來久，何處度殘年。", "人悶如中酒，村荒似禁烟。", "將茶冰箸煮，移枕雪蓬眠。", "更肯狂歌否，春風雙玉船。"]'),
('14d8a8d8-fb2c-465d-a02d-038d77cb3dc3','贈上饒道雲仲','戴表元','宋','宋诗','song-poetry','','[]','江上青雲客，天邊白馬生。',48,'全唐诗/poet.song.243000.json','["江上青雲客，天邊白馬生。", "百年文物似，一席笑談傾。", "問舊能枚舉，論財比芥輕。", "徘徊亦自好，可便濯塵纓。"]'),
('36c9b38e-985b-408e-96bb-afac040cf85c','送鄉同舍黄君賞謁陳提學','戴表元','宋','宋诗','song-poetry','','[]','六館賦聲在，五陵遊伴稀。',48,'全唐诗/poet.song.243000.json','["六館賦聲在，五陵遊伴稀。", "如何趨仕版，猶自著儒衣。", "春晚鶑羞語，城寒花慢飛。", "江湖陳仲舉，相見肯空歸。"]'),
('8517ed4c-6e79-407b-a041-a2a1f83d78d3','六月朔日再會再次韻與胡氏謙避暑','戴表元','宋','宋诗','song-poetry','','[]','臺屋深難暑，湖林近易風。',48,'全唐诗/poet.song.243000.json','["臺屋深難暑，湖林近易風。", "高歌送長日，醉眼睨凉空。", "雀舌纖纖碧，雞頭淡淡紅。", "行藏數子別，談笑一樽同。"]'),
('e916c801-1f51-49b8-b311-ec67bc875523','次韻蔚上人見寄','戴表元','宋','宋诗','song-poetry','','[]','流落誰相憶，山林蔚講師。',48,'全唐诗/poet.song.243000.json','["流落誰相憶，山林蔚講師。", "玄機魂夢接，詩力鬢毛知。", "舟去須尋處，書來不記時。", "君看東海月，今夜亦追隨。"]'),
('e47b3be5-5af8-4d98-8e8d-183ff4bf8386','道衡書寄求詩','戴表元','宋','宋诗','song-poetry','','[]','烈士蹈東海，公仍歸白雲。',48,'全唐诗/poet.song.243000.json','["烈士蹈東海，公仍歸白雲。", "龍藏誰顧蛻，鶴去不隨群。", "道貌青難寫，香風遠自聞。", "人間塵垢子，羞讀徑山文。"]'),
('5d75eb2d-aaff-48e5-909b-46ab80789473','次韻蔚講師新春之贈','戴表元','宋','宋诗','song-poetry','','[]','每見輒自失，春風雙鬢斑。',48,'全唐诗/poet.song.243000.json','["每見輒自失，春風雙鬢斑。", "詩囊貧裏富，藥市閙中閒。", "甃路通湖寺，敞樓當郡山。", "清緣事事足，聽此屢開顔。"]'),
('9ae7fa7e-1064-4e3e-af40-d6f675e42528','史昭甫招陳宗魯之長興','戴表元','宋','宋诗','song-poetry','','[]','之子滄浪去，三吳西更西。',48,'全唐诗/poet.song.243000.json','["之子滄浪去，三吳西更西。", "白鹽蓴菜膾，紅酒稻花雞。", "地少驚雲滿，天空見日低。", "錦囊看爛熳，佳客醉留題。"]'),
('fe4a9162-5de7-45c3-939d-c78436c27657','風雨行湖山村','戴表元','宋','宋诗','song-poetry','','[]','風雨湖山暮，屠村又鮑村。',48,'全唐诗/poet.song.243000.json','["風雨湖山暮，屠村又鮑村。", "鳥巡漁退艇，犬認獵歸門。", "天作蠻雲暗，溪憑剡漲喧。", "十年燈火伴，草次共魚餐。"]'),
('f8ccf625-841b-4de5-adbc-5ccd3c0651d6','詠蠶','戴表元','宋','宋诗','song-poetry','','[]','物亦有仁者，蠶功不可量。',48,'全唐诗/poet.song.243000.json','["物亦有仁者，蠶功不可量。", "將身甘鼎鑊，與世作衣裳。", "過棧蒼雲濕，登山白雪香。", "未知龍種似，猶與馬群妨。"]'),
('0ba9a104-9aed-4c46-9c4d-9c103cb38bca','桕坑','戴表元','宋','宋诗','song-poetry','','[]','西去疑無路，誰知是剡津。',48,'全唐诗/poet.song.243000.json','["西去疑無路，誰知是剡津。", "行多收桕客，住有掘苓人。", "寺隠山前古，村經水後貧。", "時時百里外，來此祭田神。"]'),
('0c3b85e3-d536-4fcb-8edb-810ebcdedbbb','證道寺','戴表元','宋','宋诗','song-poetry','','[]','彎環青徑斜，自是野僧家。',48,'全唐诗/poet.song.243000.json','["彎環青徑斜，自是野僧家。", "滿澗瀉巖液，插天排石牙。", "爐寒餘柏子，架靜落藤花。", "記得逃兵日，門多貴客車。"]'),
('7508b7d9-d8d4-44ad-a6c2-391e2b9bb335','喜王丞病較','戴表元','宋','宋诗','song-poetry','','[]','途窮已難忍，那許病經時。',48,'全唐诗/poet.song.243000.json','["途窮已難忍，那許病經時。", "學到自無鬼，命强客有醫。", "飯爲扶壽本，書是解煩資。", "便作天台約，山行未覺衰。"]'),
('530686fb-1561-4231-b3f9-afe8a3921b7f','丁亥歲除前二日書事','戴表元','宋','宋诗','song-poetry','','[]','索索寒搜客，沉沉雨洗年。',48,'全唐诗/poet.song.243000.json','["索索寒搜客，沉沉雨洗年。", "殘林生獵迹，歸鳥避窯烟。", "節物杯漿外，溪山鬢影前。", "行藏都未定，筆硯底能捐。"]'),
('9b698da1-0255-4eb3-a9f7-c4daed612e60','寄雪竇同長老','戴表元','宋','宋诗','song-poetry','','[]','高高山頂寺，更有最高人。',48,'全唐诗/poet.song.243000.json','["高高山頂寺，更有最高人。", "定起松鳴屋，吟圓月上身。", "雲藏三伏熱，水散百溪津。", "曾乞蘭花供，無書又過春。"]'),
('c54c3b5d-3536-4088-840a-05afaba2164b','鄞城火後見光遠','戴表元','宋','宋诗','song-poetry','','[]','火後丘墟市，兵前風雨春。',48,'全唐诗/poet.song.243000.json','["火後丘墟市，兵前風雨春。", "那知携手地，俱是皺眉人。", "海柳吟猶弱，山鶑聽未真。", "明朝各分路，何處避風塵。"]'),
('8f077c90-82aa-4c40-aed1-94e440f3d42c','客言劉樗翁事','戴表元','宋','宋诗','song-poetry','','[]','俗薄名難盛，人窮迹易危。',48,'全唐诗/poet.song.243000.json','["俗薄名難盛，人窮迹易危。", "從來天下士，不計里中兒。", "隠玉看虹氣，堅松任蠹枝。", "相知不相識，况又不相知。"]'),
('426386fe-9aaf-4c26-b089-e9933814927e','蔣堯仁監簿挽詩二首  其一','戴表元','宋','宋诗','song-poetry','','[]','家廠宣和後，官名德祐前。',48,'全唐诗/poet.song.243000.json','["家廠宣和後，官名德祐前。", "不圖諸老盡，竟得一身全。", "月旦懸虛鑒，巾箱有秘篇。", "堂堂何可得，誰乞畫圖傳。"]'),
('cce38b6e-16b0-4c55-8f28-c9272b74995a','蔣堯仁監簿挽詩二首  其二','戴表元','宋','宋诗','song-poetry','','[]','照席鬚眉古，傾筵咳唾清。',48,'全唐诗/poet.song.243000.json','["照席鬚眉古，傾筵咳唾清。", "緋魚前進士，刀筆老儒生。", "政熟元無譜，書高別有評。", "百年茲士少，諸彥自偏名。"]'),
('d5cab73a-da6f-48d5-8a4b-c3aa8a230e0b','四十','戴表元','宋','宋诗','song-poetry','','[]','四十不解事，真成無用人。',48,'全唐诗/poet.song.243000.json','["四十不解事，真成無用人。", "交遊青草盡，途路白雲新。", "漸覺名妨靜，難將學濟貧。", "堂堂楚龔傳，猶有隠流嗔。"]'),
('8340526a-bdd8-431a-8a78-6d5b4ce16674','夜坐','戴表元','宋','宋诗','song-poetry','','[]','愁鬢丁年白，寒燈丙夜青。',48,'全唐诗/poet.song.243000.json','["愁鬢丁年白，寒燈丙夜青。", "不眠驚戍鼓，久客厭郵鈴。", "洶洶城噴海，疏疏屋滿星。", "十年窮父子，相守慰飄零。"]'),
('559b52bc-b79a-48de-a7aa-08dee4a05fb6','晦亭','戴表元','宋','宋诗','song-poetry','','[]','東海窮詩客，西風古驛亭。',48,'全唐诗/poet.song.243000.json','["東海窮詩客，西風古驛亭。", "髮從殘歲白，山入故鄉青。", "世事徒三窟，兒童且一經。", "丁寧速賒酒，煮栗試沙瓶。"]'),
('864c78c6-3e61-4e7d-ab15-974470f778d5','孫常州挽詩','戴表元','宋','宋诗','song-poetry','','[]','白髮何人在，青山此老歸。',48,'全唐诗/poet.song.243000.json','["白髮何人在，青山此老歸。", "殉携貧日硯，斂着賜餘衣。", "文物鷗興滅，園林鶴是非。", "諸公莫惆悵，英爽世間稀。"]'),
('25a620dd-6d82-4393-8e6e-90baf609bf91','嚴提舉挽詩','戴表元','宋','宋诗','song-poetry','','[]','判得身煨燼，歌銘尚爾爲。',48,'全唐诗/poet.song.243000.json','["判得身煨燼，歌銘尚爾爲。", "可憐蟬脫蛻，還許豹留皮。", "剡水歸來棹，柯山看斷棋。", "平生觸心處，臨卷費相思。"]'),
('8be2eb50-20ba-4f54-aef4-f8e61051bef3','霪雨溪漲抵郭可畏','戴表元','宋','宋诗','song-poetry','','[]','黑雨連三日，黄流迸一川。',48,'全唐诗/poet.song.243000.json','["黑雨連三日，黄流迸一川。", "盡漫騎馬路，祗有釣魚船。", "城郭功如此，江湖興豈然。", "兒曹却輕捷，來往似飛鳶。"]'),
('33661e75-8e8f-409b-8b8b-a3d495c020e4','夷齊','戴表元','宋','宋诗','song-poetry','','[]','夷齊棄封國，虞芮讓閒田。',48,'全唐诗/poet.song.243000.json','["夷齊棄封國，虞芮讓閒田。", "如何後世士，尺寸事爭喧。", "鄰居有愧恥，况復兄弟間。", "掩卷三歎息，古風何時還。"]'),
('1090efb8-4f7e-476b-a53b-279b8e6f1f49','贈針醫范秀才','戴表元','宋','宋诗','song-poetry','','[]','不但針經熟，言談語語真。',48,'全唐诗/poet.song.243000.json','["不但針經熟，言談語語真。", "鍊形如鐵佛，信手合銅人。", "秘攝魚千里，空飛鶴當輪。", "功成倘相挾，平地脫風塵。"]'),
('95f7f52d-e460-4e9f-bcfb-2a26f4054214','遊登袋寺寺出茶筍甚佳獨無杜鵑  其一','戴表元','宋','宋诗','song-poetry','','[]','苦雨忽相貸，名山難久孤。',48,'全唐诗/poet.song.243000.json','["苦雨忽相貸，名山難久孤。", "春泉新雀舌，野苑嫩龍鬚。", "土宇錢王日，風烟釋氏徒。", "行人逢不問，松吹自傳呼。"]'),
('442a619b-8ec2-4bc2-b86d-5cc9e49616a0','遊登袋寺寺出茶筍甚佳獨無杜鵑  其二','戴表元','宋','宋诗','song-poetry','','[]','路絕猶人跡，山空惟水聲。',48,'全唐诗/poet.song.243000.json','["路絕猶人跡，山空惟水聲。", "如何芳樹裏，不著杜鵑鳴。", "筍市層層出，苗田寸寸耕。", "緇流太清朴，亭榭不標名。"]'),
('175c1f8d-0118-4a64-a27c-0db9f312de4a','偶得巾樣問老匠云正古漉酒巾也','戴表元','宋','宋诗','song-poetry','','[]','漉酒陶元亮，名傳尚有巾。',48,'全唐诗/poet.song.243000.json','["漉酒陶元亮，名傳尚有巾。", "方成執鞭志，更著捧心人。", "待菊須簪髮，臨流擬祓塵。", "乃翁真處士，吾黨祗閒民。"]'),
('5eb128b5-3c21-4912-b1ed-224f937de55c','又作散愁','戴表元','宋','宋诗','song-poetry','','[]','說窮人不信，欲說更何爲。',48,'全唐诗/poet.song.243000.json','["說窮人不信，欲說更何爲。", "日永書腸覺，霜濃病骨知。", "□家兵潰後，交絕廩空時。", "頭白風塵境，消磨尚有詩。"]'),
('bf8bc992-ac11-45b0-88f4-4c62fb92fa7f','太學冬至日同齋朋友先以兄弟敘拜訖遍詣諸齋行禮出遂置酒湖上衣冠談笑之樂至今栩栩在念間也因至日去近二十九和爲正仲道之','戴表元','宋','宋诗','song-poetry','','[]','畫閣東爐早，黄簾曉燭遲。',48,'全唐诗/poet.song.243000.json','["畫閣東爐早，黄簾曉燭遲。", "名函僮僕滿，齒拜弟兄疑。", "歌酒神仙舫，衣冠宰相碑。", "如今窮海上，逆旅話襟期。"]'),
('d846408e-cb5b-4612-8c02-1f5e0dbbcf71','舊里火後多有築宅者太平客戶也','戴表元','宋','宋诗','song-poetry','','[]','人說離鄉賤，歸鄉更莫論。',48,'全唐诗/poet.song.243000.json','["人說離鄉賤，歸鄉更莫論。", "許詢家莫幹，杜甫客東屯。", "廢井微蹤出，新鄰雜語喧。", "平生江海意，歲晚白榆村。"]'),
('287d93cc-75f1-4d93-8536-51fdaba76756','食淡','戴表元','宋','宋诗','song-poetry','','[]','世亂謀生拙，村深食淡能。',48,'全唐诗/poet.song.243000.json','["世亂謀生拙，村深食淡能。", "沙蔬羹白煮，山稻飯紅蒸。", "暑豉方傳友，寒糟共學僧。", "庖厨尚如此，未歎室生冰。"]'),
('3d21735b-ab94-4845-b44e-f5d989f1a21e','寄謝王侍御','戴表元','宋','宋诗','song-poetry','','[]','雲氣蓬萊閣，霜威獬豸冠。',48,'全唐诗/poet.song.243000.json','["雲氣蓬萊閣，霜威獬豸冠。", "躭書真柱下，執法更臺端。", "步驟三台近，聲名七郡寒。", "誰知階級禮，許爲腐儒寬。"]'),
('e0b38048-1010-47cf-b036-74fde5f91adf','久客且歸留別郭于昭憲掾','戴表元','宋','宋诗','song-poetry','','[]','久客令人厭，初春乍許寒。',48,'全唐诗/poet.song.243000.json','["久客令人厭，初春乍許寒。", "飛蓬妨覽鏡，脫粟愧加餐。", "坐有誇年酩，門誰住馬鞍。", "重來會相見，老性忍悲歡。"]'),
('f867d8e0-59dc-45d8-936c-a9f60166e429','趙壽父遊杭','戴表元','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東浙饑難住，西湖遠不多。',48,'全唐诗/poet.song.243000.json','["東浙饑難住，西湖遠不多。", "好辭松葉面，來聽竹枝歌。", "水屋花千繞，岩林錦一窠。", "秋深道途好，老子亦婆娑。"]'),
('65c92a18-1e68-4d12-bc61-feefe06a58e4','鄰友疫','戴表元','宋','宋诗','song-poetry','','[]','歲惡災妖熾，人窮性命輕。',48,'全唐诗/poet.song.243000.json','["歲惡災妖熾，人窮性命輕。", "如何赤髮鬼，亦及白眉生。", "忍楚嘗親藥，停哀寫子旌。", "鄉鄰拘俗忌，哭弔並無聲。"]'),
('c2f9013e-58a7-428e-8ba9-f206d3611caf','老態','戴表元','宋','宋诗','song-poetry','','[]','老態誰能脫，中年子自如。',48,'全唐诗/poet.song.243000.json','["老態誰能脫，中年子自如。", "丹胎三轉候，卦氣一周時。", "倦動身如客，平眠力勝醫。", "看書亦漸懶，意到或成詩。"]'),
('83326059-21ae-4213-84ce-c982e253ea94','頓寒懷單祥卿教諭','戴表元','宋','宋诗','song-poetry','','[]','霜花一夜白，風葉滿村黄。',48,'全唐诗/poet.song.243000.json','["霜花一夜白，風葉滿村黄。", "欲出歲華老，相思江水長。", "留枝遮鵲戶，存蜜補蜂糧。", "想見山行處，開窗新酒香。"]'),
('8c4c3adf-93f0-489b-bfa4-001b101dd1e3','蘇伯清席中領張仲賓所寄二詩兼聞陳無逸已從湘南官滿歸養喜而有答仍次來韻','戴表元','宋','宋诗','song-poetry','','[]','我愛張公子，清言氣不低。',48,'全唐诗/poet.song.243000.json','["我愛張公子，清言氣不低。", "湖溝隨市轉，亭樹與城齊。", "杯酒方花下，扁舟又水西。", "祗愁騎馬滑，難惜錦障泥。"]'),
('9e169a33-a5b8-404b-b417-d3deedf1abe0','次韻蘇教授立春書事','戴表元','宋','宋诗','song-poetry','','[]','病老空山客，寒紆積雪春。',48,'全唐诗/poet.song.243000.json','["病老空山客，寒紆積雪春。", "麥苗青有主，桃板粉成神。", "短策陶元亮，輕舟賀季真。", "征徭辛不及，游眺雜閒民。"]'),
('7c196e7b-f1a6-4f9e-9a25-6dcd5cc04b5c','讀閬風題林隠詩追和贈汪秀才','戴表元','宋','宋诗','song-poetry','','[]','山林一跡地，塵土二毛年。',48,'全唐诗/poet.song.243000.json','["山林一跡地，塵土二毛年。", "避世書爲屋，謀生藥當田。", "卉衣從俗製，疏供學僧煎。", "渺渺滄溟去，今誰魯仲連。"]'),
('944d2fe8-50ea-4a3c-8c2b-df9b4adda844','送謝教諭','戴表元','宋','宋诗','song-poetry','','[]','聞說龍泉縣，儒風最可人。',48,'全唐诗/poet.song.243000.json','["聞說龍泉縣，儒風最可人。", "墨池千澗縮，石室四山鄰。", "北學中連剡，南音漸带閩。", "峨冠作賓客，罄折不須頻。"]'),
('78e8691d-08d3-4c22-8ad1-cf113370e9a6','蝗來','戴表元','宋','宋诗','song-poetry','','[]','不曉蒼蒼者，生渠意若何。',48,'全唐诗/poet.song.243000.json','["不曉蒼蒼者，生渠意若何。", "移蹤青穗盡，眩眼黑花多。", "害慘陰機蜮，殃踰蟲毒蛾。", "秋霖幸痛快，一捲向滄波。"]'),
('705d8ba6-71c7-4ae2-aa0a-59479d0e83b5','丁丑歲初歸鄞城','戴表元','宋','宋诗','song-poetry','','[]','城郭三年別，風霜兩鬢新。',48,'全唐诗/poet.song.243000.json','["城郭三年別，風霜兩鬢新。", "窮多違意事，拙作背時人。", "雁蹟沙場信，龍腥瀚海塵。", "獨歌心未已，筆硯且相親。"]'),
('0b0fde07-42ea-48ec-ab2c-32a89d5e7d7f','夜坐示友','戴表元','宋','宋诗','song-poetry','','[]','夜久燭花落，凄聲生遠林。',48,'全唐诗/poet.song.243000.json','["夜久燭花落，凄聲生遠林。", "有懷嫌會淺，無事又秋深。", "黄葉歸田夢，白頭行路吟。", "山中亦可樂，不似此同襟。"]'),
('f39900ef-1b99-41e3-bf50-9f6f99a2564b','宿永固寺','戴表元','宋','宋诗','song-poetry','','[]','小寺如山艇，坐來風雨宵。',48,'全唐诗/poet.song.243000.json','["小寺如山艇，坐來風雨宵。", "榻分椶樹影，饌带菊花苗。", "親近談難褻，狐馴聽不妖。", "許由渾欠達，嫌到野中瓢。"]'),
('113b5b11-1557-4081-aff7-62fed0b60112','孫大監挽詩  其一','戴表元','宋','宋诗','song-poetry','','[]','禹穴收雲氣，滄江亦斷流。',48,'全唐诗/poet.song.243000.json','["禹穴收雲氣，滄江亦斷流。", "真成掃地盡，同作上天遊。", "銘誄看遺史，衣冠入隠丘。", "空餘平世眼，曾望李膺舟。"]'),
('e776a783-3411-4e54-90fd-061af588c903','孫大監挽詩  其二','戴表元','宋','宋诗','song-poetry','','[]','穆祖收英俊，斯人晚更成。',48,'全唐诗/poet.song.243000.json','["穆祖收英俊，斯人晚更成。", "白頭真老監，褐服舊諸生。", "仕國餘波遠，儒鄉巨棟傾。", "蒼蒼無處問，西望累吞聲。"]'),
('70ceabcf-2d02-4107-b6bc-96e346b1f8a9','風雨遊小大浦','戴表元','宋','宋诗','song-poetry','','[]','海塢秋風裏，無悰眼亦開。',48,'全唐诗/poet.song.243000.json','["海塢秋風裏，無悰眼亦開。", "潮衝烏嶼長，雨過象山來。", "畬父收牛種，漁丁拾蠯胎。", "乘桴吾豈敢，人說近蓬萊。"]'),
('bf89229d-e55a-4b0c-8ff4-672d88314c1a','方處士挽詩二首  其一','戴表元','宋','宋诗','song-poetry','','[]','不謂高名下，終全玉雪身。',48,'全唐诗/poet.song.243000.json','["不謂高名下，終全玉雪身。", "交猶及前輩，吾不似今人。", "別號行鳴雁，遺編感獲麟。", "斂儀應自定，只著古衣巾。"]'),
('35a2c2ab-8835-4cf6-a816-2855de848f39','方處士挽詩二首  其二','戴表元','宋','宋诗','song-poetry','','[]','不比他人死，何詩可挽君。',48,'全唐诗/poet.song.243000.json','["不比他人死，何詩可挽君。", "淵明元嬾仕，東野別攻文。", "滄海諸公淚，青山處士墳。", "相看莫浪哭，私謚有前聞。"]'),
('f96834c2-b3f3-49b0-b36d-a640a26fbfce','宿趙𡸯丞家','戴表元','宋','宋诗','song-poetry','','[]','溪山兵後縣，風雪旅中人。',48,'全唐诗/poet.song.243000.json','["溪山兵後縣，風雪旅中人。", "迫夜愁嚴鼓，衝寒託軟巾。", "摧藏名自在，疏率饌殽真。", "今代徐元直，高風自可親。"]'),
('fde50706-e7a6-4e2e-a0bb-2a5f965b2756','社日城南山作','戴表元','宋','宋诗','song-poetry','','[]','社日年年雨，江花處處春。',48,'全唐诗/poet.song.243000.json','["社日年年雨，江花處處春。", "漸成垂白老，不見踏青人。", "榆柳邊聲雜，龍蛇歲事新。", "端來近城郭，猶自厭風塵。"]'),
('83954b68-5c17-47f5-b2e5-b68631880f3f','趙君理約同途不至','戴表元','宋','宋诗','song-poetry','','[]','待子不來久，烟山看樹青。',48,'全唐诗/poet.song.243000.json','["待子不來久，烟山看樹青。", "爲吟天外句，更立水邊亭。", "雨暖催科斗，雲深長茯苓。", "鄰居亦有約，休待鬢星星。"]'),
('2d38086a-b0f0-4755-af56-99dfb97ac0b5','送雙溪汪和仲往象山見周使君兄弟','戴表元','宋','宋诗','song-poetry','','[]','五馬天邊外，雙鳬海上翁。',48,'全唐诗/poet.song.243000.json','["五馬天邊外，雙鳬海上翁。", "白頭真避地，黄卷舊趨風。", "歲月搜詩老，山林把酒同。", "漂零誰得去，羨子逐飛鴻。"]'),
('4df55ef1-5fa5-4244-8c7f-9e589a887406','聞應德茂先離棠溪有作','戴表元','宋','宋诗','song-poetry','','[]','落日蘆花雨，行人穀樹村。',48,'全唐诗/poet.song.243000.json','["落日蘆花雨，行人穀樹村。", "青山時問路，紅葉自知門。", "苜蓿窮詩味，芭蕉醉墨痕。", "端知棄城市，經席許頻溫。"]'),
('c9a92072-1160-4c5f-bc0a-37ca229b5e04','交秋不雨','戴表元','宋','宋诗','song-poetry','','[]','淤水飛成雨，焦田灌作秋。',48,'全唐诗/poet.song.243000.json','["淤水飛成雨，焦田灌作秋。", "江潮雙趼底，伏臘兩肩頭。", "蝦螺知何罪，蛟龍自不憂。", "吳兒有高廩，正蕩采菱舟。"]'),
('49b1283b-65f4-4701-9874-5cf15ff76de1','曉行','戴表元','宋','宋诗','song-poetry','','[]','漸漸路可識，紛紛山轉多。',48,'全唐诗/poet.song.243000.json','["漸漸路可識，紛紛山轉多。", "數雞啼遠塢，一鳥起滄波。", "藤杖濕雲石，筍鞋濃露莎。", "何人尚高卧，層構著烟蘿。"]'),
('06018785-7498-437b-b507-542cc545ff9b','同諸子行上畈山','戴表元','宋','宋诗','song-poetry','','[]','白石秋更潔，清溪寒自鳴。',48,'全唐诗/poet.song.243000.json','["白石秋更潔，清溪寒自鳴。", "牛羊爭道路，鳥雀聚柴荆。", "野果高低熟，山田早晚耕。", "吾歸任衰懶，兒輩託平生。"]'),
('d10f5e04-1cfd-4a03-ae03-5ef4ebadf5a5','晚投韓采岩','戴表元','宋','宋诗','song-poetry','','[]','冬日寒難暝，岩溪淺易冰。',48,'全唐诗/poet.song.243000.json','["冬日寒難暝，岩溪淺易冰。", "猨飛紅果嶂，人度白雲層。", "望屋多依竹，逢樵半采藤。", "艱難吾甚厭，何處學孫登。"]'),
('d7c43259-b5fd-40b0-bf27-5094dc32eb4e','下郝長塘小憩示陳養晦','戴表元','宋','宋诗','song-poetry','','[]','野水通田白，村山貼縣青。',48,'全唐诗/poet.song.243000.json','["野水通田白，村山貼縣青。", "兵荒猶古道，暑暍且長亭。", "稻地晴耕犢，瓜田晝撲螢。", "吾詩不寂寞，細諷與君聽。"]'),
('86c80236-efc2-4a0f-8562-c3dc0b85ce7e','此地','戴表元','宋','宋诗','song-poetry','','[]','又說風塵起，人來似水流。',48,'全唐诗/poet.song.243000.json','["又說風塵起，人來似水流。", "饑窮餘此地，嘯聚是何州。", "野白荒荒闊，雲橫莽莽浮。", "相逢問田父，未可賣耕牛。"]'),
('e0256e04-8408-4c80-ab6b-a069c935fefa','送徐生仁榮侍親遊山','戴表元','宋','宋诗','song-poetry','','[]','早識梁松拜，居成潘岳遊。',48,'全唐诗/poet.song.243000.json','["早識梁松拜，居成潘岳遊。", "一年歸雁雨，四月落花秋。", "溪味凉供酒，山聲晝入舟。", "歸來停新語，莫但作吳謳。"]'),
('8b9e830f-12fc-4622-9796-d75fa4628c20','簡王元剛併寄意王理得君玉','戴表元','宋','宋诗','song-poetry','','[]','見說頻相憶，新年已兩書。',48,'全唐诗/poet.song.243000.json','["見說頻相憶，新年已兩書。", "雪肥秦望草，春動鏡湖魚。", "繭紙堆成屋，烏蓬走當車。", "諸公有遊事，少待意如何。"]'),
('ee952f54-ddb2-41f4-bfd8-e7f2ed631d93','紫溪鄔義翁挽詩','戴表元','宋','宋诗','song-poetry','','[]','先君老交友，最是後凋人。',48,'全唐诗/poet.song.243000.json','["先君老交友，最是後凋人。", "開館日千屨，藏書山四鄰。", "門迎新印綬，壙掩古衣巾。", "會哭皆英俊，哀風暗海塵。"]'),
('e87c3f80-4d98-4bba-902d-6f3f05f5cb81','題陳秀才溪山佳趣','戴表元','宋','宋诗','song-poetry','','[]','城郭尋尋盡，溪山宛宛來。',48,'全唐诗/poet.song.243000.json','["城郭尋尋盡，溪山宛宛來。", "同誰遷蠟屐，爲子破蒼苔。", "書欲斕斑設，花須爛熳開。", "趙郎題墨妙，烟霧眼中開。"]'),
('c22316a9-325e-48bd-98ea-b88b16ae863a','東離湖州泊南潯','戴表元','宋','宋诗','song-poetry','','[]','張帆出東郭，沽酒問南潯。',48,'全唐诗/poet.song.243000.json','["張帆出東郭，沽酒問南潯。", "畫屋蘆花淨，紅橋柳樹深。", "魚艘寒滿港，橘市晝成林。", "吾道真迂闊，浮家尚越吟。"]'),
('473e8944-0cff-42a2-a745-613719d8a694','次韻答寄閬風舒先生','戴表元','宋','宋诗','song-poetry','','[]','聞說薌岩老，風情不減前。',48,'全唐诗/poet.song.243000.json','["聞說薌岩老，風情不減前。", "菊盤秋熟蟹，竹枕晚凉蟬。", "碑碣僧頻謁，詩囊客自編。", "梅花紫溪路，一別又三年。"]'),
('7bfe901d-1de0-45e1-96fc-416f7b6f6ef9','送陳養晦教諭之象山','戴表元','宋','宋诗','song-poetry','','[]','聞說橫經處，潭潭坐翠微。',48,'全唐诗/poet.song.243000.json','["聞說橫經處，潭潭坐翠微。", "開窗見日出，拂席有雲飛。", "藥市山山古，魚餐水水肥。", "新篇應爛熳，休遣遞筒稀。"]'),
('222faaed-cc1b-4ec9-9b67-f8b666f13598','趙孟⿰禾熏修職挽詩','戴表元','宋','宋诗','song-poetry','','[]','辨得從容死，知渠磊落人。',48,'全唐诗/poet.song.243000.json','["辨得從容死，知渠磊落人。", "風雲數世澤，玉雪百年身。", "譜牒圖經舊，園林墓道新。", "不知滄海上，更費幾沾巾。"]'),
('b8470d16-91fa-481f-9d38-4f22746cafd2','送羅學正赴歙','戴表元','宋','宋诗','song-poetry','','[]','文公湯沐邑，子去作儒官。',48,'全唐诗/poet.song.243000.json','["文公湯沐邑，子去作儒官。", "馬首千峰秀，鶑聲二月寒。", "山禽攢俸納，溪友借書看。", "近日科名闊，青雲上不難。"]'),
('51cf09ab-b7a4-4a0b-903d-0b86026da709','杜子問赴建康南軒祠長','戴表元','宋','宋诗','song-poetry','','[]','一席清溪上，深衣雪鬢翁。',48,'全唐诗/poet.song.243000.json','["一席清溪上，深衣雪鬢翁。", "揮犀談孔氏，釋菜禮宣公。", "堂饌淮鮮白，賓筵楚醴紅。", "花臺無恙否，回首幾春風。"]'),
('279d9049-4d94-454e-be53-193556e06392','己亥歲歸過泉口紫芝山傷謹講師','戴表元','宋','宋诗','song-poetry','','[]','行路夢猶在，入門人已非。',48,'全唐诗/poet.song.243000.json','["行路夢猶在，入門人已非。", "山青古佛頂，雲墨祖師衣。", "賭弈曾同拙，看真似欠肥。", "百年誰免此，只合早忘機。"]'),
('95682ed0-b465-479d-9428-d379f753fd44','三山鄭君挽詩','戴表元','宋','宋诗','song-poetry','','[]','近日經師少，人中又哭君。',48,'全唐诗/poet.song.243000.json','["近日經師少，人中又哭君。", "遺編空白屋，同列盡青雲。", "塵土千金産，湖山數尺墳。", "紛紛粱肉種，誰得致斯文。"]'),
('e3ab1082-f1f8-49a1-a4fa-a618540b3d17','送穹上人還里','戴表元','宋','宋诗','song-poetry','','[]','但得扁舟便，春風處處行。',48,'全唐诗/poet.song.243000.json','["但得扁舟便，春風處處行。", "定中三竺月，禪外五言城。", "海角雕胡飯，山畦玉版羹。", "清緣倘相就，談笑解塵纓。"]'),
('c6ad88e6-cf4e-4179-98ad-7795af834a0f','褚叔豪赴山陰和靖祠長','戴表元','宋','宋诗','song-poetry','','[]','此老真迂闊，白頭方出山。',48,'全唐诗/poet.song.243000.json','["此老真迂闊，白頭方出山。", "一燈河洛後，千礎剡湖間。", "講鼓驚雲動，書船載月閒。", "可無容席地，容我了躋攀。"]'),
('84bc3880-fa6a-4a95-9918-0ecdaa2ff5df','逢翁舜咨','戴表元','宋','宋诗','song-poetry','','[]','相逢渾不覺，祗似宛陵貧。',48,'全唐诗/poet.song.243000.json','["相逢渾不覺，祗似宛陵貧。", "裊裊花驕客，瀟瀟雨淨春。", "借書消茗困，索句寫梅真。", "此去青雲上，知君有幾人。"]'),
('b7bb809e-0e67-4ef7-b7b3-59bec470f524','舟過嚴州','戴表元','宋','宋诗','song-poetry','','[]','溪石茸茸出，水泉滃滃懸。',48,'全唐诗/poet.song.243000.json','["溪石茸茸出，水泉滃滃懸。", "銜杯仙洞頂，挂席客星邊。", "古岸魚爲市，窮鄉繭當田。", "生涯著處有，奔走愧華巔。"]'),
('f6ba2d41-fa95-4ac8-8a55-3d9f9b9ac178','招王奕世','戴表元','宋','宋诗','song-poetry','','[]','聞說銅山下，書屏四面開。',48,'全唐诗/poet.song.243000.json','["聞說銅山下，書屏四面開。", "就僧煮紫筍，共客席青苔。", "鐵畫年俱長，霜根頂未栽。", "何當端午暇，一別剡鄉來。"]'),
('3d87415c-fc45-4a43-88b6-8ac45daff63f','再招奕世','戴表元','宋','宋诗','song-poetry','','[]','雷晚還多雨，山寒只似春。',48,'全唐诗/poet.song.243000.json','["雷晚還多雨，山寒只似春。", "野榴開向客，籬笋長過人。", "一寸書看懶，三叉路走頻。", "王郎肯來否，談笑共南鄰。"]'),
('40d32608-2f44-4e2c-9a2a-fea89d7286e9','山中','戴表元','宋','宋诗','song-poetry','','[]','野水晴猶漲，春雷晚始鳴。',48,'全唐诗/poet.song.243000.json','["野水晴猶漲，春雷晚始鳴。", "地閑無堠邏，山遠有蠶耕。", "身世通寒暑，交遊半死生。", "方知一杯酒，真勝百年名。"]'),
('cd6fc22b-a5bd-45a5-b77a-6edb6e7a1908','七月初五夜養正堂示諸友','戴表元','宋','宋诗','song-poetry','','[]','客裏猶多事，秋來又一旬。',48,'全唐诗/poet.song.243000.json','["客裏猶多事，秋來又一旬。", "青天星斗淨，白露稻粱新。", "留落空存節，炎凉莫問人。", "儒堂得佳伴，吟諷動比鄰。"]'),
('3a90c663-fa1c-4343-a1af-a7cf05381933','袁提幹挽詩二首  其一','戴表元','宋','宋诗','song-poetry','','[]','短世誰無死，深山獨有歸。',48,'全唐诗/poet.song.243000.json','["短世誰無死，深山獨有歸。", "送車晴起霧，埋碣夜生輝。", "晦朔雞鳴在，江山鶴夢非。", "剛言仁者壽，近事例多違。"]'),
('1594c8a9-0dbc-4e81-a6b8-f086010d550b','袁提幹挽詩二首  其二','戴表元','宋','宋诗','song-poetry','','[]','我昔携家走，君曾掃榻招。',48,'全唐诗/poet.song.243000.json','["我昔携家走，君曾掃榻招。", "亂離心易感，生死義難消。", "雅魄歸泉壤，潜光出市朝。", "平生五字苦，寒淚灑山瓢。"]'),
('43915886-842c-4040-be7a-77e61652433e','單漕貢君範挽詩','戴表元','宋','宋诗','song-poetry','','[]','竟抱遺經死，斯人亦可哀。',48,'全唐诗/poet.song.243000.json','["竟抱遺經死，斯人亦可哀。", "傳家一夔足，涉世萬牛回。", "白屋身空脫，青山手自開。", "樵蘇且莫近，玉樹炯泉臺。"]'),
('38b46470-6965-45e2-a9e2-6b7a1988ecd2','久客鹿頂承張景山寄詩次韻奉答','戴表元','宋','宋诗','song-poetry','','[]','但得無拘束，身輕處處仙。',48,'全唐诗/poet.song.243000.json','["但得無拘束，身輕處處仙。", "清談煨芋夜，陳夢種花年。", "水竇羊腸折，山籬麂眼編。", "詩來正清絕，松下忽聞鵑。"]'),
('8f08f30b-bfa5-4eb7-8382-602577e67028','梅山','戴表元','宋','宋诗','song-poetry','','[]','梅尉功成後，安知不此來。',48,'全唐诗/poet.song.243000.json','["梅尉功成後，安知不此來。", "路逢耕者問，山寺化人開。", "樵隴低通海，茶村暖待雷。", "談玄亦可隠，不用墾蒿萊。"]'),
('96342aad-64d3-4fd0-8c39-be70aa78cad2','乙亥歲毗陵道中','戴表元','宋','宋诗','song-poetry','','[]','百年只有百清明，狼狽今年又避兵。',64,'全唐诗/poet.song.243000.json','["百年只有百清明，狼狽今年又避兵。", "烟火誰家寒食禁，簪裾那復麗人行。", "禾麻地廢生邊氣，草木春寒起戰聲。", "渺渺飛鴉天斷處，古來還是闔廬城。"]'),
('5a5278f5-f432-4089-9f6e-068abd4e677a','丙子除夜','戴表元','宋','宋诗','song-poetry','','[]','富貴如今似駭機，漂流未遣壯心違。',64,'全唐诗/poet.song.243000.json','["富貴如今似駭機，漂流未遣壯心違。", "鄉鄰有酒貧能醉，村落無醫病亦稀。", "客任低頭從狗竇，妻休掩面對牛衣。", "十年涉世渾如此，除却躬耕事事非。"]'),
('b5f4c442-666c-4846-a9d3-f278b30dc7b0','杭城風雨中簡子昂','戴表元','宋','宋诗','song-poetry','','[]','五月錢塘風雨秋，懷人頻倚面山樓。',64,'全唐诗/poet.song.243000.json','["五月錢塘風雨秋，懷人頻倚面山樓。", "雲收樹色遥成海，水學江聲暗入溝。", "一斗盡輸無事飲，千金不買辟寒裘。", "自憐寂寞無玄學，車馬門前過似流。"]'),
('a79bfbd5-45be-46f6-ba6d-20271f2636e5','東湖第三溪','戴表元','宋','宋诗','song-poetry','','[]','日晏霜濃十二月，林疏石瘦第三溪。',64,'全唐诗/poet.song.243000.json','["日晏霜濃十二月，林疏石瘦第三溪。", "雲沙有徑縈寒燒，松屋無人鳴晝雞。", "幾聚衣冠塊作土，當年歌舞醉如泥。", "早知涉世真成夢，不棄山田春雨犂。"]'),
('585f7517-d19d-4358-bb99-41505090b6d9','史亨父挽詩','戴表元','宋','宋诗','song-poetry','','[]','玉食嬋娟非壽資，清懷猶勝幾男兒。',64,'全唐诗/poet.song.243000.json','["玉食嬋娟非壽資，清懷猶勝幾男兒。", "壺觴竹寺尋秋月，燈火荷齋聽雨時。", "補衲有衣曾禮佛，吞舟無訣莫憑醫。", "平生瀟灑王文學，地下相逢且說詩。"]'),
('ba62fc69-33c5-443d-8d56-949e4ad8259d','吳兄文參議同登金陵鳳皇臺醉作','戴表元','宋','宋诗','song-poetry','','[]','百年訪古此徘徊，更上山椒掃草萊。',64,'全唐诗/poet.song.243000.json','["百年訪古此徘徊，更上山椒掃草萊。", "一臠地腴胡馬瞰，數圍天險化龍開。", "時聞營籍傳謠曲，誰見禪宮離劫灰。", "李白不生王謝歇，西風日落鳳皇臺。"]'),
('70287f66-fa9a-416d-84ce-a47d7d3c98fd','越城待旦','戴表元','宋','宋诗','song-poetry','','[]','策策虛樓竹隔明，悲來輾轉向誰傾。',64,'全唐诗/poet.song.243000.json','["策策虛樓竹隔明，悲來輾轉向誰傾。", "天寒胡雁出萬里，月落越雞啼四更。", "爲底朱顔成老色，看人青史上新名。", "清溪白石村村有，五尺烏犍託此生。"]'),
('4c7b94fd-03ec-4d9e-863f-816d193e57ea','林村寒食','戴表元','宋','宋诗','song-poetry','','[]','出門楊柳碧依依，木筆花開客未歸。',64,'全唐诗/poet.song.243000.json','["出門楊柳碧依依，木筆花開客未歸。", "市遠無餳供熟食，村深有紵試生衣。", "寒沙犬逐遊鞍吠，落日鴉銜祭肉飛。", "聞說舊時春賽罷，家家鼓笛醉成圍。"]'),
('309e080f-86eb-440a-a333-ab47819b81dc','寄天台舒閬風先生','戴表元','宋','宋诗','song-poetry','','[]','嶺雲盡處是台州，有箇詩翁住下頭。',64,'全唐诗/poet.song.243000.json','["嶺雲盡處是台州，有箇詩翁住下頭。", "不寄一書春又晚，相思百里水空流。", "新蹤凍合鶑雛谷，舊夢花迷燕子樓。", "聞說道旁烽燧急，定應重作峽中遊。"]'),
('aff4d862-deea-4a3c-8c99-620293f269de','火後','戴表元','宋','宋诗','song-poetry','','[]','當年歌酒留連處，火後來看一惘然。',64,'全唐诗/poet.song.243000.json','["當年歌酒留連處，火後來看一惘然。", "傍水幾家初飲馬，入春三月未聞鵑。", "炎凉世事殘城樹，歌哭人聲去客船。", "不是危腸拚醉得，顛狂無處著詩篇。"]'),
('d10c9c4c-dc23-455f-8347-74d10524a6d9','過應浩然先生墓','戴表元','宋','宋诗','song-poetry','','[]','人間萬卷龐眉老，眼見堂堂入草萊。',64,'全唐诗/poet.song.243000.json','["人間萬卷龐眉老，眼見堂堂入草萊。", "行客須當下馬過，故交誰復裹雞來。", "山花不語如聽講，溪水無情自薦哀。", "猶勝黄金買碑碣，百年名字已烟埃。"]'),
('28d4e701-2c39-4d78-b54c-43dbd2b07d6e','劉正仲至寶山不值主人而去次韻奉寄','戴表元','宋','宋诗','song-poetry','','[]','日日松間過□□，詩成忽在水雲西。',64,'全唐诗/poet.song.243000.json','["日日松間過□□，詩成忽在水雲西。", "何人夜榻愁聽雨，無數春船倒上溪。", "燕筍出時斑豹美，鳳花開處杜鵑啼。", "東歸更踏來時路，醉筆山廧取次題。"]'),
('2e8807bc-de60-418e-af6c-711a38f08c3d','遊陽明一洞天呈王理得諸君','戴表元','宋','宋诗','song-poetry','','[]','禹穴蒼茫不可探，人傳靈笈鎖烟嵐。',64,'全唐诗/poet.song.243000.json','["禹穴蒼茫不可探，人傳靈笈鎖烟嵐。", "初晴鶴點青邊嶂，欲雨龍移黑處潭。", "北斗齋壇天寂寂，東風仙洞草毿毿。", "堪憐尹叟非關吏，猶向江南逐老聃。"]'),
('8e3784c5-b3fd-461b-8889-af8e0c82f38a','送旨上人西湖并寄鄧善之','戴表元','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聞說西湖也自憐，君遊更傍早春天。',64,'全唐诗/poet.song.243000.json','["聞說西湖也自憐，君遊更傍早春天。", "六橋水暖初楊柳，三竺山深未杜鵑。", "舊壁草生尋舊刻，新岩茶熟試新泉。", "城中新友須相覓，西蜀遺儒解草玄。"]'),
('ccd4c3f7-5a20-4414-a69c-8f57e3dd7d3c','辛卯除夜','戴表元','宋','宋诗','song-poetry','','[]','臘月今年只今夕，春風明日是明年。',64,'全唐诗/poet.song.243000.json','["臘月今年只今夕，春風明日是明年。", "狂歌把酒屠蘇地，醉眼看梅霧淞天。", "碧玉千壺喧坐次，紅牙六博鬬飛錢。", "頭顱雪白心情在，聽說承平一惘然。"]'),
('58f40907-7795-4809-a9fd-94d7b79afea3','拜袁越公墓因遊定水寺有懷源老','戴表元','宋','宋诗','song-poetry','','[]','乃翁已作飛仙去，猶得潭潭好墓田。',64,'全唐诗/poet.song.243000.json','["乃翁已作飛仙去，猶得潭潭好墓田。", "老樹背風深拓地，野雲依海細分天。", "青峰曉接鳴鐘寺，玉井秋澄試茗泉。", "我與源公舊相識，遺言瀟灑有人傳。"]'),
('727000c8-209f-4053-916e-44f6b2e3166a','陪阮使君遊玉几','戴表元','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','花滿車茵酒滿船，亂雲堆裏訪枯禪。',64,'全唐诗/poet.song.243000.json','["花滿車茵酒滿船，亂雲堆裏訪枯禪。", "林深何處無芳草，人靜有時聞杜鵑。", "神屋畫飛青䃸磹，靈潭陰罩赤蛇蜒。", "居然悟得松風夢，回首廬山二十年。"]'),
('b81504b4-40f1-4555-bdc2-d1f54aa48134','雪竇飛雪亭和孫使君','戴表元','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬亦有千尋瀑，無此陵虛翠玉臺。',64,'全唐诗/poet.song.243000.json','["匡廬亦有千尋瀑，無此陵虛翠玉臺。", "身倚老松天上立，眼看飛鳥雪中來。", "山神禁肅難投唾，木落魂清得浣埃。", "見說下巖堪對望，道人臨壑剪蒿萊。"]'),
('85be0cee-81e8-4a01-bbf5-76f996aeab77','邑中滯雨示陳貴白','戴表元','宋','宋诗','song-poetry','','[]','猶及相逢鬢未華，故鄉春盡不須嗟。',64,'全唐诗/poet.song.243000.json','["猶及相逢鬢未華，故鄉春盡不須嗟。", "園林處處生新草，風雨年年送落花。", "高樹晝寒歸有鳥，小溪湍急走如蛇。", "方知傲世不在隠，高枕北窗聞打衙。"]'),
('91b6e00a-3fa1-4718-af6b-89c0a30119b0','十月朔旦寄貴白兄弟','戴表元','宋','宋诗','song-poetry','','[]','黄牛村前秋葉飛，青螺峰外海雲歸。',64,'全唐诗/poet.song.243000.json','["黄牛村前秋葉飛，青螺峰外海雲歸。", "故人相思雪滿鬢，客子獨行風舉衣。", "烏鵲定占誰屋喜，鱸魚知比去年肥。", "當時歌酒江湖上，百里音書今亦稀。"]'),
('48abecbe-b648-4dab-a5ee-93b3c0e3bb3b','次韻任起潜謀隠之作','戴表元','宋','宋诗','song-poetry','','[]','江邊秋日逢任子，大醉索詩吾欲狂。',64,'全唐诗/poet.song.243000.json','["江邊秋日逢任子，大醉索詩吾欲狂。", "爲問山資何次第，祗餘丹訣轉凄凉。", "黄金范蠡曾辭祿，白首虞翻未信方。", "千古浮雲共歸意，曉風城郭水花香。"]'),
('e240368b-497b-4022-a790-39c7b8287a67','晚秋遊中溪四首  其一','戴表元','宋','宋诗','song-poetry','','[]','淡竹岡前沙雁飛，小花尖下柘丸肥。',64,'全唐诗/poet.song.243000.json','["淡竹岡前沙雁飛，小花尖下柘丸肥。", "山雲不見雨自薄，天氣欲寒人正歸。", "招伴祗須新稻酒，臨風猶有舊苔磯。", "風流鬢髮莖莖在，怪石老松今是非。"]'),
('8c6a7deb-a7e4-4fc7-bc23-b0079af74c67','晚秋遊中溪四首  其二','戴表元','宋','宋诗','song-poetry','','[]','經秋溪水碧洄洄，無數曉山如鏡臺。',64,'全唐诗/poet.song.243000.json','["經秋溪水碧洄洄，無數曉山如鏡臺。", "紅葉流從龍奧出，白雲飛向石門來。", "亦逢紙戶曾相識，尚有樵蹤且莫回。", "端爲何人作風物，漫山漫谷野花開。"]'),
('17512eda-01d6-4c2a-8564-756b50996313','晚秋遊中溪四首  其三','戴表元','宋','宋诗','song-poetry','','[]','休折山中松桂枝，溪魚亦小莫垂絲。',64,'全唐诗/poet.song.243000.json','["休折山中松桂枝，溪魚亦小莫垂絲。", "沙田翻白收秔後，霜樹著紅嘗柿時。", "日落牛羊歸徑熟，天寒烏鳥向人慈。", "出雲數里成官路，問事如何總不知。"]'),
('6787ef48-78fb-42eb-bbb9-a375804243b6','晚秋遊中溪四首  其四','戴表元','宋','宋诗','song-poetry','','[]','樹淡雲濃又一坡，招邀處處是行窩。',64,'全唐诗/poet.song.243000.json','["樹淡雲濃又一坡，招邀處處是行窩。", "梯岩危似蟻緣木，架屋高如鵲結窠。", "水味野栽茭白瘦，山毛人摘芋紅多。", "行年四十不稱意，更欲客遊知奈何。"]'),
('05d1dc5e-2fb9-41bf-a8fd-2b26ae83fccd','春夜喜陳汝晦見過','戴表元','宋','宋诗','song-poetry','','[]','乃翁治獄多陰德，之子論文有古風。',64,'全唐诗/poet.song.243000.json','["乃翁治獄多陰德，之子論文有古風。", "尊俎祗容吾黨共，衣冠能得幾家同。", "書林有業何妨隠，徭籍無名莫怨窮。", "百歲相期今夕意，頼君咳唾起諸童。"]'),
('2ec255fd-b350-41fa-8a58-c11c4a945ffd','鄉君子肯堂董君分教貴溪作詩奉寄','戴表元','宋','宋诗','song-poetry','','[]','舟車赤日千餘里，筆硯清風二百年。',64,'全唐诗/poet.song.243000.json','["舟車赤日千餘里，筆硯清風二百年。", "開口人知宗洛派，舉頭身欲近閩天。", "絺袍凉擁松皮几，桂酒春浮藥玉船。", "猶有英髦卧空谷，閒將名字訪華顛。"]'),
('e4ef292e-ae7d-4b7d-b6d7-423258161330','次韻答陳叔高','戴表元','宋','宋诗','song-poetry','','[]','早種青蒲已滿溝，暮栽黄菊亦成丘。',64,'全唐诗/poet.song.243000.json','["早種青蒲已滿溝，暮栽黄菊亦成丘。", "不辭西日射牛背，尚勝北風吹馬頭。", "新雨客疏塵鎖几，故山秋淡樹藏樓。", "艱難終竟鄉情耐，準擬行窩處處留。"]'),
('cb300afe-2eb3-4f56-8f52-fd0e02e5e859','次韻寄陳達觀少府兼簡叔高','戴表元','宋','宋诗','song-poetry','','[]','懷人路絕雲歸海，避俗門深草蔽丘。',64,'全唐诗/poet.song.243000.json','["懷人路絕雲歸海，避俗門深草蔽丘。", "萬事漸消閒客夢，一生虛白少年頭。", "山螀叫緩從除架，淮雁來多莫上樓。", "近日鄰家有新釀，每逢詩伴得淹留。"]'),
('19b77f07-8db6-4147-9e49-99e3d6f59188','過清凉寺王參預墓下','戴表元','宋','宋诗','song-poetry','','[]','江左風流廊廟人，荒境拋與梵宮鄰。',64,'全唐诗/poet.song.243000.json','["江左風流廊廟人，荒境拋與梵宮鄰。", "多年羊虎猶眠石，敗壁貂蟬祇貯塵。", "萬古雲山同白骨，一庭花木目青春。", "永思陵下猶凄切，廢屋酸風吹野薪。"]'),
('3d3cba49-b689-43ca-91ed-70e8c2e6a33a','送僧無等遊華亭','戴表元','宋','宋诗','song-poetry','','[]','華亭是我曾遊處，記憶端然不作疏。',64,'全唐诗/poet.song.243000.json','["華亭是我曾遊處，記憶端然不作疏。", "地带三吳猶壯麗，人經二陸自詩書。", "輕身羨爾能隨鶴，薄味從來不爲魚。", "未卜西遊時遠近，道成相問定何如。"]'),
('edc1626c-9c70-43e3-a087-e725f9d68f42','送陳彥恂北上兼簡李奇卿學士','戴表元','宋','宋诗','song-poetry','','[]','天末翛翛起畫舲，驪歌清切也堪聽。',64,'全唐诗/poet.song.243000.json','["天末翛翛起畫舲，驪歌清切也堪聽。", "十年夜雨頭垂白，萬里春風草又青。", "莫戀皋比專魯席，終須豸角瑞堯庭。", "平生短李江南傑，今作文昌第幾星。"]'),
('c23c780c-5026-44ec-8b44-ab522493353e','於杭州九月送袁太初赴寧海教官','戴表元','宋','宋诗','song-poetry','','[]','憐君跋涉走風沙，九月江城飛雪花。',64,'全唐诗/poet.song.243000.json','["憐君跋涉走風沙，九月江城飛雪花。", "黄蝶終歸穿硯手，青藜曾照聚書家。", "吟圓坐石題山葉，講退登樓看海槎。", "年少交游渾好在，何時相伴訪烟霞。"]'),
('de6fa0e2-fa22-4ec5-b8be-15bba6a56214','次韻王監簿春前對雪之作','戴表元','宋','宋诗','song-poetry','','[]','情懷未厭日如年，幻境先看海變田。',64,'全唐诗/poet.song.243000.json','["情懷未厭日如年，幻境先看海變田。", "梁苑貴遊圖畫裏，山陰風致酒尊前。", "蝦鬚簾濕閒春曉，猊舌香濃凝午烟。", "肯信高人有高卧，磯頭新泊釣魚船。"]'),
('471be245-6c7a-44ef-a78b-a7f2ebdd1ae7','陳秀才問詩於余次韻贈之','戴表元','宋','宋诗','song-poetry','','[]','秋半說詩秋又闌，覓從忘處更哦看。',64,'全唐诗/poet.song.243000.json','["秋半說詩秋又闌，覓從忘處更哦看。", "不妨味熟心自悟，祗恐業成身轉寒。", "竅木野風天倡和，崩溪怪石鬼鎸刊。", "扳君更上最高頂，莫羨千金遊子鞍。"]'),
('31f9a40a-9f84-4eaa-8377-00a06b6eef0d','次韻答胡山甫兼簡汪日賓  其一','戴表元','宋','宋诗','song-poetry','','[]','白髮詩翁南峽居，肯來與子不相疏。',64,'全唐诗/poet.song.243000.json','["白髮詩翁南峽居，肯來與子不相疏。", "久知諸老難折簡，端爲此家多貯書。", "談吐清無涉俗處，容顔衰似避兵初。", "溪梁一別還經歲，接得新詩錦不如。"]'),
('2d48862d-3f45-4f1a-aeaa-3a81c35f9e11','次韻答胡山甫兼簡汪日賓  其二','戴表元','宋','宋诗','song-poetry','','[]','亂後交朋星散居，如君那得易親疏。',64,'全唐诗/poet.song.243000.json','["亂後交朋星散居，如君那得易親疏。", "耐多但有客滿座，忙絕不令兒廢書。", "萬里山河蓬鬢底，一春風雨杏花初。", "閒身共遜耽詩老，野服枯藤得自如。"]'),
('492de60e-e00e-4a8f-9965-a65f7adcdaaf','寄袁季厚','戴表元','宋','宋诗','song-poetry','','[]','莫笑衰顔老剡翁，凶年過徹賸頑窮。',64,'全唐诗/poet.song.243000.json','["莫笑衰顔老剡翁，凶年過徹賸頑窮。", "坐窗漸愛日南至，行路不愁天北風。", "清話客多無酒款，白頭交在有書通。", "聞知別野林泉美，一策一簦吾欲東。"]'),
('67129716-cc9c-4937-93b6-21ee1ba4ea84','挽舒君實','戴表元','宋','宋诗','song-poetry','','[]','玉比清癯鶴比羸，相看中路忽相遺。',64,'全唐诗/poet.song.243000.json','["玉比清癯鶴比羸，相看中路忽相遺。", "詩才萬斛難供歉，藥論千箱不起衰。", "定有意遊輕竹杖，猶餘手剪碎松枝。", "南山山下徘徊處，曾指佳城示阿宜。"]'),
('76b2c187-759d-48a7-8b9c-9643692e438f','感事','戴表元','宋','宋诗','song-poetry','','[]','死生契闊强兄弟，南北分張好友朋。',64,'全唐诗/poet.song.243000.json','["死生契闊强兄弟，南北分張好友朋。", "戰國幾人成漢鬼，劫灰今日信胡僧。", "翰林身後詩千首，工部丘前米五升。", "山路陰寒魚雁絕，舊遊何處寄椷藤。"]'),
('8ca53852-a94a-44a9-a66a-e5fd2a126417','夢覺','戴表元','宋','宋诗','song-poetry','','[]','夢覺依然一草寮，浮蹤已慣任飄摇。',64,'全唐诗/poet.song.243000.json','["夢覺依然一草寮，浮蹤已慣任飄摇。", "虛簷晴氣生朝露，遠樹寒聲過夜潮。", "白骨又驚山下滿，朱顔剛向客中消。", "時平不愛通侯印，且願深林作老樵。"]'),
('7becd16a-1bd0-42ba-87b3-3e71537aca6a','黎州山下有坡曰響地平黎州自孫興公經始至今有祠其上','戴表元','宋','宋诗','song-poetry','','[]','蒼茫一片莓苔地，隨意觸來還有聲。',64,'全唐诗/poet.song.243000.json','["蒼茫一片莓苔地，隨意觸來還有聲。", "定是戰坑餘箭戟，不然琴屋貯瓶罌。", "名真過客多能記，跡古居人不敢耕。", "孫叟有靈應索笑，賦成留此試鏦錚。"]'),
('38d7cae7-7280-49a9-9ba3-ab0ce09da96e','寄趙子昂濟南','戴表元','宋','宋诗','song-poetry','','[]','濟南官府最風流，聞是山東第一州。',64,'全唐诗/poet.song.243000.json','["濟南官府最風流，聞是山東第一州。", "戶版自多無訟獄，儒冠相應有賓游。", "秋風魚酒黄粱市，夜月笙歌畫舫舟。", "行樂使君詩筆俊，一篇肯寄剡溪頭。"]'),
('b734b7f4-d70e-40a7-b375-da98651ef915','陳無逸張仲實皆授徒城中相望遣悶小詩往問','戴表元','宋','宋诗','song-poetry','','[]','閒身不用苦咨嗟，隨分風流閲歲華。',64,'全唐诗/poet.song.243000.json','["閒身不用苦咨嗟，隨分風流閲歲華。", "白日垂簾同賣卜，清流岸幘勝趨衙。", "飛書漆槧詩無草，夾註高檠眼未花。", "更喜芳鄰連二妙，時時衿佩問東家。"]'),
('459a47da-77da-4fb5-a7c7-2d785b7ebf6d','蔚講師見示方使君唱酬詩次韻','戴表元','宋','宋诗','song-poetry','','[]','長汀江上別多時，白髮閒身天所遺。',64,'全唐诗/poet.song.243000.json','["長汀江上別多時，白髮閒身天所遺。", "避俗如仇翻好客，知窮爲祟却耽詩。", "鄉山雲淡龍移久，湖市春寒鶴下遲。", "過盡榴梅與甜笋，高侯還許放侯知。"]'),
('53d5a4ea-8c29-491a-a58a-0be53abb4428','次韻如晦木犀因寄其從父性之老同舍','戴表元','宋','宋诗','song-poetry','','[]','詩力如弓不易張，煩襟且覺對花凉。',64,'全唐诗/poet.song.243000.json','["詩力如弓不易張，煩襟且覺對花凉。", "玲瓏南雪晴秋樹，淅窣西風夜月香。", "消得玉人歌古淡，許誰金屋鬬清狂。", "風流更憶同袍老，一塢閒雲傍水鄉。"]'),
('95c23a30-201a-4f16-8c05-3339dd63f302','徐都目之官奉化','戴表元','宋','宋诗','song-poetry','','[]','小壘飛書定不難，十年清苦舊儒冠。',64,'全唐诗/poet.song.243000.json','["小壘飛書定不難，十年清苦舊儒冠。", "黄簾日轉山衙靜，彩筆春消海驛寒。", "坂馬易勞須緩騁，潮魚雖美莫多餐。", "人來肯寄平安不，茅屋三間伴剡灘。"]'),
('60cbb4fc-d75a-40e6-9c56-fc4ad6edb66a','次韻和蔚師鑑師春懷','戴表元','宋','宋诗','song-poetry','','[]','愁是雲陰喜是晴，春遊何處不關情。',64,'全唐诗/poet.song.243000.json','["愁是雲陰喜是晴，春遊何處不關情。", "黄雞亭館琴三弄，青果杯盤酒數行。", "滿砌雨添新笋密，隔牆風送落花輕。", "鑑湖湖上樵山老，破帽枯藜過一生。"]'),
('22a6de89-320f-4827-bc36-91906860d0ef','次韻王景晹寄軒','戴表元','宋','宋诗','song-poetry','','[]','江湖猶覺氣橫行，羽褐藤冠學養生。',64,'全唐诗/poet.song.243000.json','["江湖猶覺氣橫行，羽褐藤冠學養生。", "掣肘累輕天與福，欺心戒重鬼司盟。", "行收耕稼間勳業，別有吟哦好性情。", "祗恐蹊成似桃李，人來先識隠居名。"]'),
('35965134-0ab7-48d8-a265-06c47b856aa1','送柯以善自杭遊鄂','戴表元','宋','宋诗','song-poetry','','[]','江漢天風日夜清，君遊何處濯塵纓。',64,'全唐诗/poet.song.243000.json','["江漢天風日夜清，君遊何處濯塵纓。", "雲從鸚鵡洲前出，月在鳳皇山上明。", "已羨經籝吳士艷，行看詞筆楚人驚。", "殘蓀賸芷將何用，歸日分張與後生。"]'),
('34647213-a59a-414f-8633-6ec6fe5effd5','讀福建廉訪輔大使遺事','戴表元','宋','宋诗','song-poetry','','[]','臬官難稱是閩中，遺愛堂堂得比公。',64,'全唐诗/poet.song.243000.json','["臬官難稱是閩中，遺愛堂堂得比公。", "姓字丹青太史筆，歲時籩豆素王宮。", "一生薑桂那時辣，百死江湖必向東。", "從古仁賢有家世，名郎臺閣已生風。"]'),
('5c671a81-7aaf-462d-95be-62e11cdd36b6','客京口','戴表元','宋','宋诗','song-poetry','','[]','酒釅花穠鼓聒天，百年成此好山川。',64,'全唐诗/poet.song.243000.json','["酒釅花穠鼓聒天，百年成此好山川。", "黄烟暮接淮南火，白米秋攢浙右船。", "碑古猶多埋鶴寺，田高耕遍卧牛阡。", "陳蹤興廢何由問，只憶風流老米顛。"]'),
('39cbf34c-1219-45f0-a8aa-221a2fb68888','金陵贈友','戴表元','宋','宋诗','song-poetry','','[]','虎變龍阡此一時，春風得似舊城池。',64,'全唐诗/poet.song.243000.json','["虎變龍阡此一時，春風得似舊城池。", "宮閒軍賣偷來果，寺廢僧尋斷去碑。", "水水魚肥供白鮓，家家蠶熟衣紅絲。", "太平尚屬窮詩客，酒賤如泥醉不知。"]'),
('ab45c7ef-d76e-4ace-b7ee-3676059ca954','湖山村','戴表元','宋','宋诗','song-poetry','','[]','老去生涯學釣魚，溪山忽憶似湘湖。',64,'全唐诗/poet.song.243000.json','["老去生涯學釣魚，溪山忽憶似湘湖。", "風林四畔動竽瑟，烟雨一篙行畫圖。", "小市篝明沽郭索，平園柵樹備於菟。", "偶然得住何妨住，是處人間足畏途。"]'),
('43313914-b21a-4865-84ea-0b12402c0d14','己卯歲初葺剡居','戴表元','宋','宋诗','song-poetry','','[]','休言聲迹轉沉淪，百折江湖亂後身。',64,'全唐诗/poet.song.243000.json','["休言聲迹轉沉淪，百折江湖亂後身。", "窮未賣書留教子，饑寧食粥省求人。", "坐來齒避樵蘇長，往處蹤迷木石鄰。", "翻笑古來逃世者，標名先製隠衣巾。"]'),
('42ff5e30-f851-46d4-a863-b0bebefbec49','耕桑','戴表元','宋','宋诗','song-poetry','','[]','耕桑本是閒居事，學得耕桑事轉多。',64,'全唐诗/poet.song.243000.json','["耕桑本是閒居事，學得耕桑事轉多。", "失曬麥叢憂出蝶，遲繅蠶繭怕生蛾。", "調停寒暖春移苧，偵候陰晴夏插禾。", "衣飯爲誰忙不徹，醉來乘興作勞歌。"]'),
('b7cd5a32-60d2-49e6-9494-f2e09dd64ff1','秋盡','戴表元','宋','宋诗','song-poetry','','[]','秋盡空山無處尋，西風吹入鬢華深。',64,'全唐诗/poet.song.243000.json','["秋盡空山無處尋，西風吹入鬢華深。", "十年世事同紈扇，一夜交情到楮衾。", "骨警如醫知冷熱，詩多當曆記晴陰。", "無聊最苦梧桐樹，攪動江湖萬里心。"]'),
('9662fa29-25b6-4e9e-9d87-ac2950882429','王丞自鄞城歸又許入剡','戴表元','宋','宋诗','song-poetry','','[]','江城醉別太匆匆，風雪家園一笑同。',64,'全唐诗/poet.song.243000.json','["江城醉別太匆匆，風雪家園一笑同。", "儘健不妨天予老，絕清那許鬼欺窮。", "簡書異日關誰事，燈火寒鄉頼此翁。", "幾度丁寧雞黍約，掃關拂榻誤兒童。"]'),
('8a1521af-c544-4cae-bafe-54a311ee66fc','壬午清明','戴表元','宋','宋诗','song-poetry','','[]','節序愁中都忘却，見人插柳是清明。',64,'全唐诗/poet.song.243000.json','["節序愁中都忘却，見人插柳是清明。", "登陴戍出吹彈樂，上塚船歸語笑聲。", "解事濁醪相料理，當權團扇正施行。", "悲歡寒暑君休問，花鳥年年管送迎。"]'),
('c2678491-c980-4386-a845-18aee9380827','寒食','戴表元','宋','宋诗','song-poetry','','[]','寒食清明却過了，故鄉風物祗依然。',64,'全唐诗/poet.song.243000.json','["寒食清明却過了，故鄉風物祗依然。", "窮中有客分青飯，亂後誰墳掛白錢。", "落魄暖春爲麥地，陰沉溽雨近梅天。", "閒情正爾無歸宿，石鼎新芽手自煎。"]'),
('ed8e2c53-441a-42e7-a7c2-d523787af76a','無題','戴表元','宋','宋诗','song-poetry','','[]','板屋驟喧飛白蟻，紙窗欲雨暗蒼蠅。',64,'全唐诗/poet.song.243000.json','["板屋驟喧飛白蟻，紙窗欲雨暗蒼蠅。", "長勞井臼慚妻子，近絕音書惜友朋。", "夜半苦吟堪泣鬼，日高甘寢祗輸僧。", "意衰俗物何難敗，才薄天公却未憎。"]'),
('3a5c35c9-1070-40ac-a574-d30cd41a3307','奉題孫使君池館','戴表元','宋','宋诗','song-poetry','','[]','白髮使君經世材，儘閒猶解暢池臺。',64,'全唐诗/poet.song.243000.json','["白髮使君經世材，儘閒猶解暢池臺。", "雜花屏障四時有，明月鏡奩三面開。", "各坐山隨人意看，正吟風遞鳥聲來。", "當年時雨堂前夢，得似從容此一杯。"]'),
('c664f2b0-07c1-4a56-be59-fffdbbde1ef1','家西十里外茅洋小山中土塚纍然初不封樹鄉先生舒文靖公墓也','戴表元','宋','宋诗','song-poetry','','[]','莫輕數尺黄泥壤，埋却斯人後更無。',64,'全唐诗/poet.song.243000.json','["莫輕數尺黄泥壤，埋却斯人後更無。", "山上自難生毒草，樹間長見聚慈烏。", "樵耕可免憑鄉俗，灑埽能來是學徒。", "後有宣尼須痛惜，待將墓額寫嗚呼。"]'),
('95d2284d-2ad5-49fb-8423-fc1e745b8f7f','戊子歲晚贈應德茂','戴表元','宋','宋诗','song-poetry','','[]','江海悠悠雪欲飛，抱書空出又空歸。',64,'全唐诗/poet.song.243000.json','["江海悠悠雪欲飛，抱書空出又空歸。", "沙頭人滿鷗應笑，船上酒香魚正肥。", "塵土竟成誰計是，山林又悔一年非。", "平生萬卷應夫子，兩世知名窮布衣。"]'),
('eecb2a07-caf4-47a2-b795-e6fe756f3d9a','寶山寺寒食次韻和閬翁','戴表元','宋','宋诗','song-poetry','','[]','綠陰啼鳥春將老，古寺垂楊日未西。',64,'全唐诗/poet.song.243000.json','["綠陰啼鳥春將老，古寺垂楊日未西。", "客子欲歸風滿袖，桃花無語水流溪。", "有人蔬筍忘饑渴，何處松楸雜笑啼。", "準擬一時僧榻畔，詩翁題後更誰題。"]'),
('63b93a42-f546-476f-b754-fbbd49797dc8','戊子清明前陪王丞度新嶺','戴表元','宋','宋诗','song-poetry','','[]','一百五日熟食節，七十一曲下山坡。',64,'全唐诗/poet.song.243000.json','["一百五日熟食節，七十一曲下山坡。", "寒暄相逢舊人少，風雨欲盡新林多。", "青岩不辭掛春靄，白鳥何處生滄波。", "途泥同興不同調，我懶且休君更歌。"]'),
('45ba54f6-af1a-4a46-b63f-35475e90f3cc','同陳養晦兵後過邑','戴表元','宋','宋诗','song-poetry','','[]','搜山馬退餘春草，避世人歸起夏蠶。',64,'全唐诗/poet.song.243000.json','["搜山馬退餘春草，避世人歸起夏蠶。", "破屋烟沙飛颯颯，遺民鬚鬢雪毿毿。", "青山幾處楊梅塢，白酒誰家櫸柳潭。", "休學丁仙返遼左，聊同庾老賦江南。"]'),
('a3f8fe73-bc10-4c35-8027-7ec938c59ebf','送人遊霞嶼','戴表元','宋','宋诗','song-poetry','','[]','霞嶼風烟接渺溟，老仙萬鍤敞林扃。',64,'全唐诗/poet.song.243000.json','["霞嶼風烟接渺溟，老仙萬鍤敞林扃。", "峰前雁起湖雲凈，池面龍來海雨腥。", "閲世僧閒頭黑白，遊山客爽句丹青。", "何緣飛去清源國，雨夜翛翛著翅翎。"]'),
('e362c960-b1e8-4181-aa34-5e14c87a7f36','己丑正月六日袁季源家遭燬次韻書悶','戴表元','宋','宋诗','song-poetry','','[]','鄴侯家裏書千架，杜老尊前屋萬間。',64,'全唐诗/poet.song.243000.json','["鄴侯家裏書千架，杜老尊前屋萬間。", "此事吾堪慰流落，邇來天亦妬窮閒。", "反風待禱真虛語，噀雨無方自厚顔。", "間挈殘家過西塢，風流還許幾生還。"]'),
('7a012238-023b-47b8-8948-bc70e3ef9561','正仲今年鄞城之約不就因次韻慰悅之','戴表元','宋','宋诗','song-poetry','','[]','莫怪詩翁不出山，詩多那得是山間。',64,'全唐诗/poet.song.243000.json','["莫怪詩翁不出山，詩多那得是山間。", "清溪欲暖鶑啼樹，白日無人犬卧關。", "不惜野花簪素髮，時憑春酒轉朱顔。", "當年阮籍何曾達，直到途窮始哭還。"]'),
('c96954c3-802c-4c4e-8b0c-2a461fa220f1','送于知州','戴表元','宋','宋诗','song-poetry','','[]','居官難得是全名，于守年多政轉清。',64,'全唐诗/poet.song.243000.json','["居官難得是全名，于守年多政轉清。", "身爲素王扶墜戶，手提赤子出饑坑。", "使來公館文書簡，吏退私齋几硯橫。", "似此雍容好風度，天邊看著繡衣行。"]'),
('9dd61924-bdad-42bc-a513-015491d80489','壬午六月八日書懷','戴表元','宋','宋诗','song-poetry','','[]','懷人故國鱗鴻絕，避地春園草樹長。',64,'全唐诗/poet.song.243000.json','["懷人故國鱗鴻絕，避地春園草樹長。", "四壁空存醫俗具，千金難售賣獃方。", "共兒坐誦修吳語，有客行歌衒楚裝。", "昨夜見花摇作夢，南風吹海白茫茫。"]'),
('13aae076-a798-44b6-a580-0cda566f8ba2','杖錫寺','戴表元','宋','宋诗','song-poetry','','[]','仙草漫漫路不分，鍾魚那許外間聞。',64,'全唐诗/poet.song.243000.json','["仙草漫漫路不分，鍾魚那許外間聞。", "凉天九月已飛雪，晴日西山猶带雲。", "火後客誇新屋樣，兵前僧惜舊碑文。", "藤湖只去招提頂，見說滮田可種耘。"]'),
('a4703471-10d7-47fa-a3b4-1f1ff29b18a1','四明山中逢晴','戴表元','宋','宋诗','song-poetry','','[]','一岡一澗一縈隈，新歲新晴始此迴。',64,'全唐诗/poet.song.243000.json','["一岡一澗一縈隈，新歲新晴始此迴。", "莎坂南風寅蛤出，茅簷西日一禽來。", "人迷白路羊群石，水捲青天雪裏雷。", "猶是深山有寒食，梨花無數繞岩開。"]'),
('864dfeee-21b0-43ce-84c7-10cb1091a82e','魏文節公墓','戴表元','宋','宋诗','song-poetry','','[]','萬騎南來駐不留，衣冠客此鎮林丘。',64,'全唐诗/poet.song.243000.json','["萬騎南來駐不留，衣冠客此鎮林丘。", "寒岩碎裂從中起，亂水喧鳴竟獨流。", "故物今惟存寓馬，當年誰爲指眠牛。", "墳傍小寺終村俗，畫柱紗籠護冕旒。"]'),
('b5658d32-5d20-42f8-af2b-1ed35dcd3ffd','辛亥歲七夕醉陪諸公登西湖竹閣','戴表元','宋','宋诗','song-poetry','','["\u897f\u6e56"]','畫鷁凌風汗漫遊，雨聲飛出萬山頭。',64,'全唐诗/poet.song.243000.json','["畫鷁凌風汗漫遊，雨聲飛出萬山頭。", "江湖望闊邊城起，吳越音多客思柔。", "野樹有枝猶繫馬，官荷無葉不藏鷗。", "十年浪走紅塵道，今日臨城始識秋。"]'),
('9c806d2c-000e-4110-bd3c-4d2f87a858a6','蔡嶴食藕','戴表元','宋','宋诗','song-poetry','','[]','地逢平處亦縈迴，不是逃兵底肯來。',64,'全唐诗/poet.song.243000.json','["地逢平處亦縈迴，不是逃兵底肯來。", "坡上一祠猶姓蔡，山前當路盡通台。", "高岩童去收桐子，鄰縣人過問藕栽。", "忽見深衣老儒者，清時不信少遺材。"]'),
('992bb04b-c428-4508-a45c-89653c420cc1','辛巳歲六月三日書事','戴表元','宋','宋诗','song-poetry','','[]','急報傳來又不真，迎門翁稚笑聲頻。',64,'全唐诗/poet.song.243000.json','["急報傳來又不真，迎門翁稚笑聲頻。", "情懷經苦思平世，顔貌緣愁似老人。", "兵後尚多難料事，山中誰是自由身。", "沙瓶酒釅鮭蔬有，領取燈花一樹春。"]'),
('ecacede7-3a1c-4124-9099-d1bd02cd9847','耕休','戴表元','宋','宋诗','song-poetry','','[]','耕休何處散煩勞，東埭西梁信所遭。',64,'全唐诗/poet.song.243000.json','["耕休何處散煩勞，東埭西梁信所遭。", "溪水清清照魚影，山風細細落松毛。", "無名野草疑皆藥，有韻村謠例近騷。", "稽古祗堪農圃用，莫將車馬誤兒曹。"]'),
('b8cdbe7d-3832-4576-befd-731b58f8fe07','畬齋次韻','戴表元','宋','宋诗','song-poetry','','[]','貧賤知心老弟兄，祗疑相得似前生。',64,'全唐诗/poet.song.243000.json','["貧賤知心老弟兄，祗疑相得似前生。", "避窮無地猶貪學，負謗如天底用名。", "兵後脫身宜共惜，書中薄業尚堪耕。", "殷勤預約頻頻見，未見亦須頻寄聲。"]'),
('ff698cd7-e869-4492-9571-02b6266a8a6c','保福寺','戴表元','宋','宋诗','song-poetry','','[]','漫天蘿蔓斷追尋，猶有人嫌未苦深。',64,'全唐诗/poet.song.243000.json','["漫天蘿蔓斷追尋，猶有人嫌未苦深。", "屋古滲當風雨氣，僧馴化得虎狼心。", "松花晝暖蜂科蜜，梅子春殘鳥戀陰。", "不應初來便忘去，身閒處處是山林。"]'),
('cfd256da-e9cf-433b-b279-0ed99b70f199','張景忠學正之平江','戴表元','宋','宋诗','song-poetry','','[]','江南最好說蘇州，傍得閒官也自由。',64,'全唐诗/poet.song.243000.json','["江南最好說蘇州，傍得閒官也自由。", "市舍酒香春四坐，湖田租熟雪千舟。", "歌成爛熳烏絲寫，意到縈紆畫鷁游。", "我亦少年心性在，經從準擬作遨頭。"]'),
('9e71cac4-9815-42ce-bb40-8d45f5c66c48','鮮于伯機家釣臺石','戴表元','宋','宋诗','song-poetry','','[]','人間岩石亂紛紛，嚴子臺名最喜聞。',64,'全唐诗/poet.song.243000.json','["人間岩石亂紛紛，嚴子臺名最喜聞。", "何術縮渠千里脈，有人分得兩峰雲。", "天邊路遠星還動，江上潮回日又曛。", "解道泥途等軒冕，東西更有范希文。"]'),
('faf17b20-800e-48d2-9341-7e7263dd4677','辛丑歲十一月二十六日東歸舟中示三子','戴表元','宋','宋诗','song-poetry','','[]','節物悠悠不負公，江行三日雪花風。',64,'全唐诗/poet.song.243000.json','["節物悠悠不負公，江行三日雪花風。", "雲侵賀監山亭白，日在徐仙海島紅。", "自笑得雛如病鶴，也思結伴附歸鴻。", "何時辦得村田活，糲飯魚羹百指同。"]'),
('3382089b-c172-411e-bdb1-668f6a9233cc','歸自西關有作簡余率公鈔使','戴表元','宋','宋诗','song-poetry','','[]','白髮微官小祝同，也隨年少踏春風。',64,'全唐诗/poet.song.243000.json','["白髮微官小祝同，也隨年少踏春風。", "鄉心幾夜馬生角，世味一時龜脫筒。", "紅旆戍樓花整整，綠莎溪路水茸茸。", "歸來健羨余公子，卷帙如山一覽空。"]'),
('cbab6886-569a-4374-8f09-75f907ed44a4','貴溪董教諭回里','戴表元','宋','宋诗','song-poetry','','[]','八月暄暄似小春，鄞江歸客楚江濱。',64,'全唐诗/poet.song.243000.json','["八月暄暄似小春，鄞江歸客楚江濱。", "夢中鱸鱠紫蓴菜，畫裏紵袍烏角巾。", "不枉誇張別風土，有時吟嘯雜仙真。", "年高官滿身輕健，聊復婆娑亦可人。"]'),
('edad8469-62ac-4702-a5c6-cb93e888118f','陳無逸教諭赴攸州','戴表元','宋','宋诗','song-poetry','','[]','白露西風湘水清，蒼霞南岳晚天明。',64,'全唐诗/poet.song.243000.json','["白露西風湘水清，蒼霞南岳晚天明。", "離家休說三千里，行道新看第一程。", "橘味熟來思母遺，草名疑處教兒評。", "人生誰是安居者，早拾貂蟬映父兄。"]'),
('14f6480b-de99-44f8-a6c0-293860038606','周東鄉載酒冰溪上因遊岳祠醉作','戴表元','宋','宋诗','song-poetry','','[]','葫蘆城下草平沙，狼牙峰前溪吐花。',64,'全唐诗/poet.song.243000.json','["葫蘆城下草平沙，狼牙峰前溪吐花。", "晴日路塵清野馬，空林人語亂神鴉。", "饞思火甕生燒笋，渴愛山爐熟煮茶。", "投老遠遊何所惜，爲君歡坐岸烏紗。"]'),
('ec35bdb9-f41d-48cb-8b4b-a0f0f31e6f2f','次韻東魯省游石龜山','戴表元','宋','宋诗','song-poetry','','[]','一舸悠悠醉又醒，溪山無語意分明。',64,'全唐诗/poet.song.243000.json','["一舸悠悠醉又醒，溪山無語意分明。", "龜身何日化蒼石，鶴背有人遊紫清。", "百榼頒空看少俊，千金難買是春晴。", "筵端宋玉尤騷絕，游戲長歌復短行。"]'),
('676961dd-792f-4599-947a-c5ece18432e8','寄趙子昂','戴表元','宋','宋诗','song-poetry','','[]','溪上輕雲去若飛，花間密石靜相依。',64,'全唐诗/poet.song.243000.json','["溪上輕雲去若飛，花間密石靜相依。", "遲行自愛款段馬，雜坐誰嗔短後衣。", "江海於人元不薄，風流如此欲安歸。", "集賢學士吾兄弟，近日音書亦較稀。"]'),
('8538fccc-ed0d-4c8d-a852-b3dcc6cfd386','亡友內翰趙公晦叔哀詩','戴表元','宋','宋诗','song-poetry','','[]','振鷺庭中飣坐身，行藏空寄軟蒲輪。',64,'全唐诗/poet.song.243000.json','["振鷺庭中飣坐身，行藏空寄軟蒲輪。", "上來鬼泣荆山璞，獵罷人驚魯外麟。", "死肯扣閽排貴倖，貧猶傾橐施鄉親。", "平生一一明經術，雋永依然世澤新。"]'),
('dae349e9-de9a-4547-9756-22bcc504dcff','次韻答貴白','戴表元','宋','宋诗','song-poetry','','[]','斗粟千錢不易酬，海風吹斷寄詩郵。',64,'全唐诗/poet.song.243000.json','["斗粟千錢不易酬，海風吹斷寄詩郵。", "誰家盛設蟹黄餠，有客翻披狐白裘。", "春樹自隨冬樹老，官河長挾野河流。", "隔生兄弟何須說，來作城南十日遊。"]'),
('51a59352-d5f2-468d-a928-935c7887d9b7','清華堂','戴表元','宋','宋诗','song-poetry','','[]','人生隨分有清華，萬竹岡頭第一家。',64,'全唐诗/poet.song.243000.json','["人生隨分有清華，萬竹岡頭第一家。", "甃塹水溫初荇葉，粉牆風細欲梨花。", "衣冠蒼皓迎如畫，緗素朱黄積滿車。", "從此儒林添膾炙，老夫先借小詩誇。"]'),
('58f049dc-554a-45e0-aab2-0c627263c73a','陸君采都目入閩','戴表元','宋','宋诗','song-poetry','','[]','趨閩漸近解閩吟，公子來時夏欲深。',64,'全唐诗/poet.song.243000.json','["趨閩漸近解閩吟，公子來時夏欲深。", "捲地翠棚榕樹驛，漫天紅錦荔枝林。", "官庖雋永多珍膾，野語啁嘲有怪禽。", "風物自佳難逗遛，浙江歸棹待相尋。"]'),
('b6088fb6-3cec-4ab3-92bb-0c9be94be3ee','亞尹黄侯慮囚溫處婺三州','戴表元','宋','宋诗','song-poetry','','[]','金華瓌秀抵仙都，雁宕石門天下無。',64,'全唐诗/poet.song.243000.json','["金華瓌秀抵仙都，雁宕石門天下無。", "眼見朱幡出雲霧，手提丹筆洗焦枯。", "海魚味爽休多食，嶺馬程艱合緩驅。", "定有車前投贄者，幅巾麻褐是真儒。"]'),
('26ed3e07-60db-48b3-bb28-a9f9c5c5f1b3','簡湯及翁','戴表元','宋','宋诗','song-poetry','','[]','六十三翁尚美髯，今年添盡白毿毿。',64,'全唐诗/poet.song.243000.json','["六十三翁尚美髯，今年添盡白毿毿。", "心如晚路思家馬，身似春筐欲繭蠶。", "無事官曹容岸幘，有時書帙當清談。", "風情最苦湯公子，家世衣冠舊汝南。"]'),
('668fd52a-eac7-441e-94cc-816d17ce451c','舒子俊見過','戴表元','宋','宋诗','song-poetry','','[]','來往通家不厭頻，青山心性白雲身。',64,'全唐诗/poet.song.243000.json','["來往通家不厭頻，青山心性白雲身。", "陰林石溜風傳語，霜月溪梁水寫真。", "歲儉魚鮭難猝致，天寒烏鳥自相親。", "燎爐薪暖糟牀響，隨分歡留作好春。"]'),
('a1cd23c8-e7ca-445a-9b5a-330f8fbae7e1','以家事付諸兒惟不得姑蘇陸氏女子消息','戴表元','宋','宋诗','song-poetry','','[]','祇憐地僻少過從，更許年衰養惰慵。',64,'全唐诗/poet.song.243000.json','["祇憐地僻少過從，更許年衰養惰慵。", "行健有時尋近局，起遲嘗日到高舂。", "鹿皮冠野頻頻戴，鵝頂蔬粗款款供。", "兒女團欒俱在眼，獨憐無信過吳松。"]'),
('d3f6d7bc-e369-45e7-8a01-27d7494cdac6','江海','戴表元','宋','宋诗','song-poetry','','[]','江海三秋古鄮城，山林百拙剡溪生。',64,'全唐诗/poet.song.243000.json','["江海三秋古鄮城，山林百拙剡溪生。", "歸來鄉國方爲客，絕盡交遊更畏名。", "白帽管寧形態醜，黄金季布語言輕。", "荒齋竟日無人事，自作長歌寄好聲。"]'),
('7f2c3407-6b84-4842-b25a-2e1d70d3402a','兵後復還白岩山所舍作','戴表元','宋','宋诗','song-poetry','','[]','脫命歸來意恍然，餘生堪喜亦堪憐。',64,'全唐诗/poet.song.243000.json','["脫命歸來意恍然，餘生堪喜亦堪憐。", "財逢亂世真如土，人到窮途始信天。", "問訊比鄰晡爨後，呻吟兒女夜燈前。", "明朝又作安西計，飯後誰家沁雪田。"]'),
('8bbaf168-a817-443f-a969-84edfdd5236a','鄞塘田家','戴表元','宋','宋诗','song-poetry','','[]','經秋心事轉衰頹，客舍山村病眼開。',64,'全唐诗/poet.song.243000.json','["經秋心事轉衰頹，客舍山村病眼開。", "識路牛羊緣坂過，通家燕雀下簷來。", "饑從野榼分蔬飯，渴指鄰帘貰黍醅。", "世事百年誰較是，髯公鼻息晝如雷。"]'),
('a761fe95-3dcd-48ca-9f83-21042bf32ef9','江村遇九日','戴表元','宋','宋诗','song-poetry','','[]','去年九月江城角，尚得臨風把一杯。',64,'全唐诗/poet.song.243000.json','["去年九月江城角，尚得臨風把一杯。", "今歲併無黄菊看，誰家更遣白衣來。", "身猶是雁飛難泊，時不如潮去解回。", "還有南山會人意，晚舟相對碧崔嵬。"]'),
('2a73b887-922e-4c9f-9323-5c2342c8bf3f','再寄曹居士','戴表元','宋','宋诗','song-poetry','','[]','江海悠悠不爲名，年深識盡世間情。',64,'全唐诗/poet.song.243000.json','["江海悠悠不爲名，年深識盡世間情。", "於人有信惟潮候，去處無嗔是鵲聲。", "新欲收書添累重，舊曾學劍向財輕。", "如何此日投閑迹，又結精廬傍古城。"]'),
('897df8fd-b591-46e9-930e-c661e18d9a15','兵後見三江口木芙蓉盛開','戴表元','宋','宋诗','song-poetry','','[]','江上秋花無數生，紅紅白白照江明。',64,'全唐诗/poet.song.243000.json','["江上秋花無數生，紅紅白白照江明。", "當年茂苑看曾厭，今日荒村望急驚。", "泣雨羈臣愁去闕，歌風艷女惜傾城。", "蕭條欲別那拚得，移向東籬配菊英。"]'),
('aec7bf14-6102-417e-b794-cf45029b4181','遊西峰','戴表元','宋','宋诗','song-poetry','','[]','山迴水抱西峰寺，二十年前日日來。',64,'全唐诗/poet.song.243000.json','["山迴水抱西峰寺，二十年前日日來。", "一出居然負丘壑，深藏還此遠風埃。", "農樵識面逢多問，魚鳥知心見不猜。", "家世剡人須住剡，相尋未識百千回。"]'),
('181db447-29f4-4e2c-92ed-e07b400601a0','鮚𩸞唐鄉貢丈置酒悟空寺見款','戴表元','宋','宋诗','song-poetry','','[]','南宮通籍唐先輩，白髮天寒海上洲。',64,'全唐诗/poet.song.243000.json','["南宮通籍唐先輩，白髮天寒海上洲。", "五鼎已推華屋夢，一尊猶及少年遊。", "桃源有吏今安避，銅雀何人死亦休。", "祗羨龍鍾老禪伯，倚欄無語看沙鷗。"]'),
('01097b13-f9a1-46aa-8888-55333b3947cb','調貴白','戴表元','宋','宋诗','song-poetry','','[]','客裏光陰取次休，嫩寒一夜襲衣裘。',64,'全唐诗/poet.song.243000.json','["客裏光陰取次休，嫩寒一夜襲衣裘。", "不須多畏趙盾日，正好深悲宋玉秋。", "紅葉舊題猶在手，黄粱新夢又從頭。", "餘糧棲畝猶圍坐，此事輸君第幾籌。"]'),
('ba8d0bff-8e03-426c-87e2-946519b35fa0','白岩山','戴表元','宋','宋诗','song-poetry','','[]','漠漠溪風吹路塵，白岩山下幾窮身。',64,'全唐诗/poet.song.243000.json','["漠漠溪風吹路塵，白岩山下幾窮身。", "秋深竹色老於樹，晝靜鳥群喧勝人。", "何處人家藏剡錄，有時行客裹唐巾。", "平生笑殺禾翁子，剛爲乘車棄負薪。"]'),
('32749340-40bb-4277-9d44-f59b9a770a7e','班婕妤題扇圖','戴表元','宋','宋诗','song-poetry','','[]','時情任銷歇，閨思轉慇懃。',24,'全唐诗/poet.song.243000.json','["時情任銷歇，閨思轉慇懃。", "也勝山陰媼，揮毫託右軍。"]'),
('3188e5d1-2152-4fac-b0fd-0bbfcc82ca9b','子昂秋林行客圖','戴表元','宋','宋诗','song-poetry','','[]','石稜稜而白出，樹悄悄以紅披。',28,'全唐诗/poet.song.243000.json','["石稜稜而白出，樹悄悄以紅披。", "嗟縞衣之嘉客，方策蹇以何之。"]'),
('d8f81e45-214c-4795-8c31-ccfea9e1860c','五雜俎  其一','戴表元','宋','宋诗','song-poetry','','[]','五雜俎，金花綾。',24,'全唐诗/poet.song.243000.json','["五雜俎，金花綾。", "往復來，官路程。", "不獲已，始歸耕。"]'),
('005aca95-3913-4ece-911c-28a0ee69a646','五雜俎  其二','戴表元','宋','宋诗','song-poetry','','[]','五雜俎，斑斕衣。',24,'全唐诗/poet.song.243000.json','["五雜俎，斑斕衣。", "往復來，反哺兒。", "不獲已，爲人師。"]'),
('a443b85f-4c2d-4831-832d-6182c3c3a393','張騫乘槎圖','戴表元','宋','宋诗','song-poetry','','[]','數尺枯槎底易騎，海風吹浪白瀰瀰。',32,'全唐诗/poet.song.243000.json','["數尺枯槎底易騎，海風吹浪白瀰瀰。", "如今市上君平少，曾到天河也不知。"]'),
('516c21ba-dd0e-41df-9683-29bc85c6e360','呂氏六桂堂','戴表元','宋','宋诗','song-poetry','','[]','年少奔馳有底忙，棘闈蘭署夢茫茫。',32,'全唐诗/poet.song.243000.json','["年少奔馳有底忙，棘闈蘭署夢茫茫。", "白頭鞍馬風沙裏，聽說燕山六桂堂。"]'),
('b0cf3d26-69dd-4bdf-8e09-a208fced5171','周秀才惠貓','戴表元','宋','宋诗','song-poetry','','[]','貍兒輕捷豹兒斑，作勢擒生也不難。',32,'全唐诗/poet.song.243000.json','["貍兒輕捷豹兒斑，作勢擒生也不難。", "漸覺形神欲相賀，青奴黄嬭夜平安。"]'),
('b65dafa6-c28a-44c8-b210-f1239692ddcf','汪濟秀才飯牛稿','戴表元','宋','宋诗','song-poetry','','[]','冰雪玲瓏汪太中，吟詩十葉有家風。',32,'全唐诗/poet.song.243000.json','["冰雪玲瓏汪太中，吟詩十葉有家風。", "天寒日暮江東道，逢此顰呻牛口翁。"]'),
