('6f46ab61-9a1e-4b2a-81a3-08d72dfb3137','九日在邇索居無聊取滿城風雨近重陽爲韻賦七詩以自遣  其三','戴表元','宋','宋诗','song-poetry','','[]','秋氣一以深，四野嘶嚴風。',48,'全唐诗/poet.song.243000.json','["秋氣一以深，四野嘶嚴風。", "晨興視庭樹，今昨忽不同。", "超騰諒無術，俛仰此世中。", "作詩欲何爲，贈子以固窮。"]'),
('71943cb6-e5ea-42e6-957e-d04aeb843a12','九日在邇索居無聊取滿城風雨近重陽爲韻賦七詩以自遣  其四','戴表元','宋','宋诗','song-poetry','','[]','粲粲黄菊花，照我原上土。',48,'全唐诗/poet.song.243000.json','["粲粲黄菊花，照我原上土。", "拒霜亦多態，終日相媚嫵。", "春花豈不美，嗟此風露苦。", "正命何所尤，生遲後甘雨。"]'),
('dc0759b2-0359-4085-ae7e-d1c539d92845','九日在邇索居無聊取滿城風雨近重陽爲韻賦七詩以自遣  其五','戴表元','宋','宋诗','song-poetry','','[]','山雞鮮羽毛，野鶻健爪吻。',48,'全唐诗/poet.song.243000.json','["山雞鮮羽毛，野鶻健爪吻。", "秋高草木空，屏處亦可隠。", "一爲嗜欲牽，遂與籠檻近。", "作書報孔鵠，出入宜少謹。"]'),
('7cb07a18-a967-4fba-a0f0-02f181a59451','九日在邇索居無聊取滿城風雨近重陽爲韻賦七詩以自遣  其六','戴表元','宋','宋诗','song-poetry','','[]','生世悔識字，祝身如野農。',48,'全唐诗/poet.song.243000.json','["生世悔識字，祝身如野農。", "勤勞養尊老，膳味日可重。", "農篘熟新黍，耕休有過從。", "行吟答松籟，此樂踰歌鐘。"]'),
('93f17380-c6fc-485e-bfa7-b3bab9acc95a','九日在邇索居無聊取滿城風雨近重陽爲韻賦七詩以自遣  其七','戴表元','宋','宋诗','song-poetry','','[]','雁雁西北來，亦復東南翔。',48,'全唐诗/poet.song.243000.json','["雁雁西北來，亦復東南翔。", "動物各有時，吾當謹行藏。", "厚墐違嚴風，密袂禦凜霜。", "陶然茅檐下，一笑生春陽。"]'),
('109f35a2-d606-40d1-9476-86e913ff847f','寄陸子方','戴表元','宋','宋诗','song-poetry','','[]','清江一日走千艘，獨有閑仙不喜遨。',32,'全唐诗/poet.song.243000.json','["清江一日走千艘，獨有閑仙不喜遨。", "幾處白雲思暮合，數行紅樹又秋高。"]'),
('a7904be1-f719-43b9-8be8-1df574974582','送同年潘昌朝','戴表元','宋','宋诗','song-poetry','','[]','客路秋深又送迎，狂歌爛飲慰飄零。',64,'全唐诗/poet.song.243000.json','["客路秋深又送迎，狂歌爛飲慰飄零。", "風前數髮莖莖白，馬上看山段段青。", "古穴無丹生洞氣，高林有鶴避潮腥。", "明年更欲三茅去，擬借新牋道德經。"]'),
('d2863dd4-1ed1-4ee8-aaa8-b3ad0a7e9712','登崇寧閣','戴表元','宋','宋诗','song-poetry','','[]','衆香壇晝靜，游屐思頻來。',48,'全唐诗/poet.song.243000.json','["衆香壇晝靜，游屐思頻來。", "心轉談經處，塵空說法臺。", "葵花憑古碣，竹色上蒼苔。", "傑閣同禪院，懸河有辨才。"]'),
('7f0d08fa-643f-463c-9405-60e05f995ee2','法善院','戴表元','宋','宋诗','song-poetry','','[]','野火煙雲窟，春溪風日朝。',48,'全唐诗/poet.song.243000.json','["野火煙雲窟，春溪風日朝。", "花遲年有閏，樹密地無徭。", "山鼓通荒戍，庭碑認往朝。", "客言僧可隠，勝似隠農樵。"]'),
('97fe1ccf-3773-4b9c-972e-1e8a6679cb56','梨洲寺  其一','戴表元','宋','宋诗','song-poetry','','[]','不知何處起鐘聲，雲作樓臺霧作城。',64,'全唐诗/poet.song.243000.json','["不知何處起鐘聲，雲作樓臺霧作城。", "洲上稻肥初起墢，山中梨巨舊傳名。", "林疏野地惟多石，氣濕炎天亦少晴。", "東畔有潭聞險絕，巖前時現老龍精。"]'),
('10302c00-d82c-4087-ae04-b61123e93ebb','梨洲寺  其二','戴表元','宋','宋诗','song-poetry','','[]','一區雞犬白雲巔，亂後來看意惘然。',64,'全唐诗/poet.song.243000.json','["一區雞犬白雲巔，亂後來看意惘然。", "劫火尚餘唐殿宇，土風甯是晉山川。", "沿溪客散三州路，並寺僧耕百畝田。", "欲訪縱由題作句，矮碑祇在近時鎸。"]'),
('c32920c3-1622-4de2-b00e-75a20a5e6ae0','寶林院','戴表元','宋','宋诗','song-poetry','','[]','何處尋三窟，端來寄一壺。',48,'全唐诗/poet.song.243000.json','["何處尋三窟，端來寄一壺。", "巖根接滄海，雲杪挂浮圖。", "古壁碑漫滅，靈鰻事有無。", "昌公好相識，閒暇說江湖。"]'),
('493f94e3-498d-4574-9f44-058a4c1959f3','句  其一','戴表元','宋','宋诗','song-poetry','','[]','酣歌待約東鄰伴，潑面晴風漲酒瀾。',16,'全唐诗/poet.song.243000.json','["酣歌待約東鄰伴，潑面晴風漲酒瀾。"]'),
('cdcb569a-1d93-4282-be78-d58cd62a1a30','句  其二','戴表元','宋','宋诗','song-poetry','','[]','更有鄰牆全處士，醉吟能泛百杯寬。',16,'全唐诗/poet.song.243000.json','["更有鄰牆全處士，醉吟能泛百杯寬。"]'),
('d5c4d91b-2da9-4283-a0ca-2b398db7aac0','句','陳童登','宋','宋诗','song-poetry','','[]','秋風道上誰青眼，夜雨燈前自白頭。',16,'全唐诗/poet.song.243000.json','["秋風道上誰青眼，夜雨燈前自白頭。"]'),
('bbbb857a-72ea-4c0b-9536-c5c25bcb4f9c','漁父辭','陳普','宋','宋诗','song-poetry','','[]','神農作耒耜，伏羲爲網罟。',180,'全唐诗/poet.song.243000.json','["神農作耒耜，伏羲爲網罟。", "耒耜之利以教耕，網罟是乃取魚具。", "天啟生涯資生靈，八政以食首爲民。", "採山釣水利其利，國家租稅自此征。", "悠悠江海老漁父，孤舟沒齒居水滸。", "翠篷黄帽寄烟波，青篛綠蓑觸風雨。", "風雨舟中歷寒暑，月明夜宿荻花洲。", "潮落暮歸蘆葉渡，蘆葉渡頭有酒沽。", "賣魚買酒浮江湖，醉中身似孤舟樣，鞭脫不管桑大夫。", "江茫茫，月皓皓，江月江人容易老。", "月光長照江長流，中有白鷗閒似我。"]'),
('c63d38a5-2292-4b89-8fd1-14a57be74350','蠶婦辭','陳普','宋','宋诗','song-poetry','','[]','東鄰採桑婦，西鄰養蠶女，年年役役爲蠶苦。',184,'全唐诗/poet.song.243000.json','["東鄰採桑婦，西鄰養蠶女，年年役役爲蠶苦。", "桐花如雪麥如雲，鳴鳩醉椹叫春雨。", "踏踏登竹梯，山烟鎖春樹。", "不管烏臺濕紅霧，妾家有夫事犂鋤，妾家有子尚啼饑。", "春蠶滿筐尚望葉，兒啼索食夫已歸。", "前年養蠶不熟葉，私債未償眉暗蹙。", "去年養蠶絲已空，打門又被官稅促。", "今年養蠶嫁小姑，催粧要作紅羅襦。", "妾身依舊只裙布，寒燈補破聊庇軀。", "蠶兮蠶兮汝知否，安得繭成大如斗。", "妾生恨不逢成周，治世春風桑五畝。"]'),
('eafe040e-77ac-4861-b847-c951db1ccba0','青蛙辭','陳普','宋','宋诗','song-poetry','','[]','古祠一區環槐榆，飛鼪在瓦狐樹居。',384,'全唐诗/poet.song.243000.json','["古祠一區環槐榆，飛鼪在瓦狐樹居。", "鐵爐缺裂死灰冷，箕坐一寸青蟾蜍。", "平心定氣詳其來，頹垣古厠濁水渠。", "蛇驚鼠駭得敗壁，一躍乃是神王廬。", "丹青神鬼非其鄉，顧盼欲去聊躊躕。", "悾悾鄙夫見之走，爭持衮冕加猨狙。", "鳴鉦考鼓動井邑，毳衣襤襤驅大車。", "浮萍狎狎叱不開，遥瞻竊禮三欷歔。", "吾聞臧氏之子不智，山節藻棁居蔡祠鶢鶋。", "無端尊禮青蝦蟆，聖門譏誚豈只且。", "吾聞崇伯妖羽野，化爲黄龍游羽潴。", "厥子代之啟九道，變作玄熊形狤{犭居}。", "鬼神赫赫號威聖，當爲龍虎爲鯨魚。", "作雲澍雨興萬化，翻江倒海洗九區。", "咬囓妖狐咀封豕，眼光百步雙驪珠。", "當爲不爲爲蝦蟆，爬沙脚手何陋歟。", "吾聞狄公焚燒江南一千七百所，只留夏禹泰伯季札伍子胥。", "宋祖碭山負耒夫，吳楚淫祠爲之墟。", "輪囷大蟒鬰屈死，寸蟆何足汙其鈇。", "人心不正至斯極，無藥可以醫籧篨。", "只須正直如梁公，一日秉畀群疑祛。", "鬼車豕塗滿天下，收拾打併歸太虛。", "蝦蟆無知聽放去，荒溝野水樂有餘。"]'),
('42306898-5ba4-4d6e-bfa1-353792e98093','歸去來辭','陳普','宋','宋诗','song-poetry','','[]','歸去來兮，吾生復何之。',311,'全唐诗/poet.song.243000.json','["歸去來兮，吾生復何之。", "故園三徑在，桃李不成蹊。", "臺榭荒凉已無憂，階除寂寞人已希。", "胡飄飄而不返，將役役以奚爲。", "丈夫不自量，處世寧堪悲。", "省一朝之若是，悟百年之已非。", "飯山曾是餓唐甫，首陽曾是餓夷齊。", "名重天下何足比，利重天下何足奇。", "覺利名之不昧，知貧賤而勿悲。", "歸去來兮歸去來，長安縱好休徘徊。", "足巾屏之行李，拂藜杖之塵埃。", "杜宇知我意，聲聲苦相催。", "故園行樂處，滿地生蒼苔。", "歸去來兮，閩山之巔。", "山奇水秀，可以忘年。", "水渺茫而潔白，山排闥以爭前。", "昔年桃李，依舊成阡。", "石徑縈紆而藤蘿聳茂，茅茨幽迥而松菊爭妍。", "盤餐三百品，食足二頃田。", "吟且詠，樂且禪。", "飽而嬉，困而眠。", "心坦坦，腹平平。", "正是故園行樂處，誰知此樂樂悠然。", "東風起兮百草芊，綠楊飛絮杏花鮮。"]'),
('8891a104-7675-42d9-b5ac-02e14ad7a97b','歷代傳授歌','陳普','宋','宋诗','song-poetry','','[]','伏羲神農黄帝氏，名曰三皇居上世。',384,'全唐诗/poet.song.243000.json','["伏羲神農黄帝氏，名曰三皇居上世。", "少昊顓頊及高辛，唐虞堯舜爲五帝。", "夏商周兮曰三代，三王禹湯文武是。", "堯舜傳官禹傳家，天與人與非私畀。", "夏禹一傳啟以賢，少康興夏滅猿𤡬。", "十有七世至桀王，成湯放桀夏緒墜。", "殷湯應天而順人，興王地方七十里。", "太甲太戊及武丁，三宗有商爲專美。", "祖乙盤庚亦賢君，三十傳紂覆商祀。", "周興積累由后稷，公劉太王及王季。", "文王大勳武王集，伐紂牧野作牧誓。", "成王嗣位在幼沖，周公輔政天下治。", "成康措刑四十年，幾移周鼎幽與厲。", "夷王下堂王室卑，平王東遷春秋始。", "至于威烈春秋終，二百四十二年爾。", "魯衛晉鄭蔡燕曹，姬氏同姓皆兄弟。", "異姓齊楚秦宋陳，春秋列國侯十二。", "其間五霸相繼興，齊桓小白晉重耳。", "宋襄秦穆及楚莊，名曰尊王假仁義。", "戰國七雄莫如秦，韓趙魏燕齊楚起。", "秦滅六國吞二周，周祚至於赧王止。", "天王三十有七傳，八百餘年屬周紀。", "秦帝始皇太暴虐，位傳二世而已矣。", "漢室龍興滅秦項，高祖劉邦赤帝子。"]'),
('f33d84d9-96b9-43a2-a42d-4ce9bf2babee','和李太白把酒問明月歌','陳普','宋','宋诗','song-poetry','','[]','人生能幾月圓時，歌之舞之復蹈之。',143,'全唐诗/poet.song.243000.json','["人生能幾月圓時，歌之舞之復蹈之。", "月爲一人我成三，更遣青州從事相追隨。", "四人好在都無闕，相勸相酬到明發。", "此夜山河有主張，鎖碎繁星俱滅沒。", "采石已來五百春，當時青天爲宇四無鄰。", "上下通透皆冰玉，豈徒眉宇真天人。", "力士嗔人譬如刀割大江水，世間閒是閒非皆如此。", "君不見李白携月到夜郎，一洗瘴天盡入冰壺裏。"]'),
('571c6f69-786d-479c-80c2-a92ecd3aefb0','姚氏生男歌','陳普','宋','宋诗','song-poetry','','[]','開乾樞，轉地軸，喜氣鬰葱充閻閭。',180,'全唐诗/poet.song.243000.json','["開乾樞，轉地軸，喜氣鬰葱充閻閭。", "一點文星降天闕，女郎捧得掌中珠。", "破曉兒童忙報道，以璋作麞大筆書。", "纔過五日便呱泣，古稱英物竟不虛。", "山靈鍾秀産英傑，冰肌玉骨色清癯。", "孔釋果然親抱送，天上麒麟汗血駒。", "于公積德加厚地，袞袞公侯儘有餘。", "從今生一必生二，續作杜陵歌二雛。", "五桂爭秀椿未老，蘭孫競出新根株。", "矧彼開元衣鉢在，有例有樣非敢諛。", "當年秀發名登於桂籍，作個公卿豈肯卑微歟。"]'),
('a10903c9-3c7e-4d07-9dff-56dd3ed0a80f','勸學歌','陳普','宋','宋诗','song-poetry','','[]','太極肇判兩儀生，其中人爲萬物靈。',355,'全唐诗/poet.song.243000.json','["太極肇判兩儀生，其中人爲萬物靈。", "人亦天地一物耳，獨以道義超衆形。", "立爲三才中宇宙，發揮天地經人倫。", "茲事初非外爍伐，毫髮皆備七尺身。", "後生可畏如日出，千金之軀豈可輕。", "寸陰可惜莫虛擲，百年安得長青春。", "有力如虎當猛省，何况責望深父兄。", "不通六籍不是學，未了三才未是人。", "希聖必須志堯舜，希賢必用爲顔曾。", "義理彝倫精講究，禮樂制度須詳明。", "體用源流務透徹，血脈文理仍流行。", "會通兩盡始無礙，範圍未始離曲成。", "無塵胸次貯萬卷，拔山筆力扛千鈞。", "不用高枕卧丘壑，用之家齊國治天下平。", "不但匹夫匹婦皆獲所，草木魚鼈咸清寧。", "此皆後進本分事，不爲干利與求名。", "更須掃除謔浪傲惰態，打并嗜欲聲色情。", "一物一則同一敬，牢守孔孟張朱程。", "喫緊工夫决有效，令聞廣譽垂千齡。", "英雄氣概爲則是，一變至道非難能。", "君不見四十五十無聞不足觀，總是惰而不學昏昏貿貿枉生天地間。"]'),
('629b37d7-4d1a-4178-b7af-e4fc376ace31','送江西曾雪笠歌','陳普','宋','宋诗','song-poetry','','[]','幾人誇詠雪，不如柳一絕。',152,'全唐诗/poet.song.243000.json','["幾人誇詠雪，不如柳一絕。", "幾家說漁父，不如柳兩句。", "天陰歲晚寒江空，玉花四合爲鴻濛。", "一片清虛畫不得，孤舟一笠何精工。", "凌空厲闊不覺寒，兀坐不動身與竿。", "磯頭把竿凍猶立，老妻在中作袁安。", "此時意壯何分明，大無垠涯小無形。", "的如曾子見一貫，又似葉公初點睛。", "十年拋却吳松江，閩山六月念蔗漿。", "門門再拜冰玉樹，畀我一幅全瀟湘。"]'),
('95056328-e8b9-4bf3-8242-080df47594c3','不飲酒歌','陳普','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','人皆愛酒如金珠，我獨畏酒如毒荼。',172,'全唐诗/poet.song.243000.json','["人皆愛酒如金珠，我獨畏酒如毒荼。", "人皆愛飲醉不醒，我獨不飲常惺如。", "我若飲兮人不同，一飲三百斛，再飲三千鍾。", "我若醉兮人莫比，上以天爲冠，下以地爲履。", "有時醉登樓，倚闌一笑江山愁。", "有時醉吟詩，烟雲滿壁龍蛇飛。", "有時醉起舞，莫邪出匣金蓮吐。", "我欲氣兮斗可撞，我欲力兮鼎可扛。", "我欲志兮吞雲夢之八九，我欲歷兮眇天地之四方。", "天地生我性不飲，我若飲時安得有酒如長江。"]'),
('41c9d167-caea-442b-b57d-70c1a18e95ff','醉吟','陳普','宋','宋诗','song-poetry','','[]','天在地在我亦在，天改地改吾始改。',159,'全唐诗/poet.song.243000.json','["天在地在我亦在，天改地改吾始改。", "前身曾作孔子孟子爲人憎，也曾爲禹爲稷爲人愛。", "來來去去非貪癡，自去自來自不知。", "今生暫來作個咬嚙菜根漢，焉知再來不遇文王出彈時。", "四溟爲罍杓北斗，舉世攢眉我開口。", "眼前不見白衣人，風月自當青田酒。", "萬事不預非無功，順應爲用虛爲宗。", "幾度貧賤幾度英雄，幾度少年幾度翁。", "天吳紫鳳任顛倒，披襟引滿對秋風。"]'),
('0cf6162e-4255-4056-b617-81888c83965d','擬古  其一','陳普','宋','宋诗','song-poetry','','[]','秋聲金氣流，天空露瀼瀼。',120,'全唐诗/poet.song.243000.json','["秋聲金氣流，天空露瀼瀼。", "素波合流月，淫淫滿庭霜。", "遥夜一美人，寒閨自徬徨。", "暗塵集凌波，輕飈感鳴璫。", "天性賦貞清，動止中矩方。", "世無夔夔子，窈窕空英皇。", "抱璞如臨淵，日入不下堂。", "時操弄玉簫，空中來鳳凰。", "歲月如流星，髮變面欲黄。", "服玉固雪膚，絕意百兩將。"]'),
('92797f28-3fb1-4107-acf9-a3ca2f4d9db9','擬古  其二','陳普','宋','宋诗','song-poetry','','[]','瑶池出甘泉，玉臺蔭梧桐。',108,'全唐诗/poet.song.243000.json','["瑶池出甘泉，玉臺蔭梧桐。", "鳳巢梧桐上，下浴甘泉中。", "美人室其左，荷衣裳芙蓉。", "素手把青枝，嘻嘻笑春風。", "性情如赤子，聲氣似黄鍾。", "明珠媚深淵，魚鼈遊沖融。", "世事多參商，憂樂苦不同。", "榮枯與醜好，相待如駏蛩。", "深懷惕霜露，夙心常省躬。"]'),
('55435bcf-905f-44d8-889e-551dd0e62339','擬古  其三','陳普','宋','宋诗','song-poetry','','[]','秋夜永如年，四壁號寒蛩。',48,'全唐诗/poet.song.243000.json','["秋夜永如年，四壁號寒蛩。", "明月照樹葉，白露啼青桐。", "寒窗紫玉琴，時變羽凌宮。", "三彈不成調，百憂鬰攻中。"]'),
('7fa70ac1-62c4-496c-97bf-720e7f33a0ea','擬古  其四','陳普','宋','宋诗','song-poetry','','[]','人生不滿百，常懷千歲憂。',48,'全唐诗/poet.song.243000.json','["人生不滿百，常懷千歲憂。", "往事雲雨散，積意如山丘。", "聖人已爲土，土復成海流。", "曷爲夢寐中，常見孔與周。"]'),
('937fc49f-9db6-4901-b707-b3e3b414154a','擬古  其五','陳普','宋','宋诗','song-poetry','','[]','先我二百年，世道猶小康。',84,'全唐诗/poet.song.243000.json','["先我二百年，世道猶小康。", "鳴鑾下紫霄，群仙集柏梁。", "仙仙青霞衣，濟濟白霓裳。", "兢兢奉玄道，拳拳薦天漿。", "雞犬亦可仙，豈徒壽天王。", "茂陵無仙骨，上帝下巫陽。", "群仙返玉京，萬事爭蒼黄。"]'),
('fe6c1536-b005-49ee-9d57-3ae8e94a761c','擬古  其六','陳普','宋','宋诗','song-poetry','','[]','共工昔暴怒，觸折不周山。',144,'全唐诗/poet.song.243000.json','["共工昔暴怒，觸折不周山。", "此樞太室上，飄落三江間。", "樞紐一飛播，滿空悉顛翻。", "北斗墮其柄，文昌失厥官。", "彗星化爲跖，搏人以爲餐。", "天狗行地上，頭戴方山冠。", "武夷有巨人，方持釣魚竿。", "中宵投袂起，容貌何桓桓。", "欲扶紫薇坦，坐使天下安。", "復逢驩兜來，被髮據其關。", "拂衣返空翠，彈琴弄潺湲。", "煙霞別一天，回首謝髦蠻。"]'),
('14519ba2-9941-4e60-88d6-098e63de8bf5','擬古  其七','陳普','宋','宋诗','song-poetry','','[]','東方有樂國，開闢先柏皇。',96,'全唐诗/poet.song.243000.json','["東方有樂國，開闢先柏皇。", "鸞鳳爲雞鶩，麒麟爲犬羊。", "晨霞作朝食，太和爲酒漿。", "土無干戈禍，人各千年長。", "下視禹九州，有土皆戰場。", "白日虎狼行，青天蛟龍翔。", "我欲爲東遊，滄海渺無梁。", "何年夸娥氏，移置天中央。"]'),
('3cd9685c-9f12-4bca-81fb-c460c5ac883a','擬古  其八','陳普','宋','宋诗','song-poetry','','[]','同根一味草，時命嗟異遇。',60,'全唐诗/poet.song.243000.json','["同根一味草，時命嗟異遇。", "風月芳香合，兩地隔周楚。", "爾生麟趾家，朝夕沐玉露。", "我在雲夢林，百草相蒙妬。", "白璧終不緇，惸惸亦良苦。"]'),
('80fd24a5-bb09-41a3-9818-e6b056ae0a7d','次答熊去非七夕遇雨見候  其一','陳普','宋','宋诗','song-poetry','','[]','志士千載心，爛爛如斜河。',36,'全唐诗/poet.song.243000.json','["志士千載心，爛爛如斜河。", "道路坦且修，况復陰雨多。", "女騃不可說，牛癡無柰何。"]'),
('af20f48d-2a94-4f1c-8362-fa13a7162f10','次答熊去非七夕遇雨見候  其二','陳普','宋','宋诗','song-poetry','','[]','連珠復合璧，嘆息復何年。',36,'全唐诗/poet.song.243000.json','["連珠復合璧，嘆息復何年。", "顛連多疾苦，道術極乖偏。", "嫠婦不卹緯，杞國常憂天。"]'),
('9eb15009-6ab6-47db-a710-8e5bc71c2841','次答熊去非七夕遇雨見候  其三','陳普','宋','宋诗','song-poetry','','[]','五鬼不害道，含沙非殺身。',36,'全唐诗/poet.song.243000.json','["五鬼不害道，含沙非殺身。", "大和一巨毒，西方無人倫。", "三聖不復作，誰亨萬世屯。"]'),
('ca635921-a40a-47b1-84a6-afdcd3c491a1','次答熊去非七夕遇雨見候  其四','陳普','宋','宋诗','song-poetry','','[]','太玄鑛故在，原道塗猶迷。',36,'全唐诗/poet.song.243000.json','["太玄鑛故在，原道塗猶迷。", "一朝無渣滓，仙派起濂溪。", "未能及鰥寡，不虛五緯奎。"]'),
('81305ced-8c98-47ad-8021-171ec573af55','次答熊去非七夕遇雨見候  其五','陳普','宋','宋诗','song-poetry','','[]','空言未深切，聊可燭朦朧。',36,'全唐诗/poet.song.243000.json','["空言未深切，聊可燭朦朧。", "好辯若無益，庶以雷群聾。", "群仙去已久，吾儕當嗣功。"]'),
('3283a18a-7c97-4fa2-bcdb-464acf7a92eb','旦氣詩','陳普','宋','宋诗','song-poetry','','[]','晝氣如大霧，蒙我大明鏡。',228,'全唐诗/poet.song.243000.json','["晝氣如大霧，蒙我大明鏡。", "主人莫知鄉，奴隸竊權柄。", "不能巍巍蒞，惟聽紛紛命。", "是非既昧瞀，操執豈中正。", "不惟裁截偏，尤苦怠惰病。", "一柱一柔弱，四維俱不競。", "循茲不回首，安得逃禽行。", "爲人自暴棄，造化德獨盛。", "納日息萬物，停止吾視聽。", "魂歸魄不安，靈根復凝定。", "潜龍蟠深淵，不滅飛騰性。", "五更號群雞，陡然得大慶。", "熹微一隙開，洞達八荒聖。", "天地頓軒豁，百度亦餖飣。", "昨非咸昭晰，今是足審訂。", "乃知天於人，父母未足並。", "晦以養其明，止以茁其瑩。", "此而不接續，誠犯不恭令。", "工夫知如何，焚香且虔敬。"]'),
('8cfdfeae-d436-4404-a395-e611c7cf396a','朱文公','陳普','宋','宋诗','song-poetry','','[]','嘗思紫陽翁，功德不下禹。',252,'全唐诗/poet.song.243000.json','["嘗思紫陽翁，功德不下禹。", "平生五人倫，叔世一天柱。", "海嶽久亭毓，二儀厚付與。", "高明挂秋月，精細破毫縷。", "舉目無荀楊，渾身是伊呂。", "百年嗣程邵，千載承鄒魯。", "直上接勛華，益遠益不禦。", "本原無不見，支派自循序。", "遂令天敘秩，有目得再覩。", "建紹乾淳間，三綱散無主。", "仇讎操太阿，利欲浸九土。", "鞠躬上文石，諄諄正心語。", "欲起君以雷，滂沱洗寰宇。", "聖心不見答，浩浩翠烟去。", "當時聽其言，何但報千古。", "廓清草萊闢，櫛沐瘡痍愈。", "奕奕萬世規，百年遽如許。", "天意竟莫回，地氣不可迕。", "但留四部書，萬世開堯禹。", "深翠隔荒臺，寥落招魂具。", "夜半讀中庸，橫空挾風雨。"]'),
('1758f559-77dd-4e46-a5d5-3cdc11335498','程朱之學  其一','陳普','宋','宋诗','song-poetry','','[]','高明若韓蘇，方正如君實。',72,'全唐诗/poet.song.243000.json','["高明若韓蘇，方正如君實。", "太山當面前，瞠目不能識。", "誰能不由戶，可怪亦可惜。", "得若在家庭，迷殆胡越隔。", "向微程朱子，出手爲開闢。", "我輩白日中，夜行至今日。"]'),
('21897d9c-99c9-418c-b52d-b433ddc56d06','程朱之學  其二','陳普','宋','宋诗','song-poetry','','[]','化工溥萬物，不過亦不遺。',192,'全唐诗/poet.song.243000.json','["化工溥萬物，不過亦不遺。", "何以能不勞，一理以貫之。", "寂然莫可跡，桴至鼓必隨。", "一朝十二牛，芒刃不少隳。", "制度自恰好，形樣咸無疑。", "夭桃且灼灼，箓竹各猗猗。", "有鱗盡淵躍，無翼不天飛。", "人心正爾妙，動靜悉如斯。", "樞紐在方寸，運化斯爲基。", "眼前日萬變，堯舜一無爲。", "此理無上下，大小隨所知。", "因物爲順應，歡然鳴塤箎。", "何故天下人，利器不自持。", "妄端忽一起，紛潰終難支。", "天開真儒出，幽探萬化機。", "蒼蒼群生類，何事塗徑迷。"]'),
('9a32d6ed-5a3e-42c5-bca0-f43642654b19','程朱之學  其三','陳普','宋','宋诗','song-poetry','','[]','楊氏枯不生，墨者散無紀。',156,'全唐诗/poet.song.243000.json','["楊氏枯不生，墨者散無紀。", "申韓明不仁，黄老信非禮。", "豈難定邪正，未足容臧否。", "世有顔孟徒，一鼓俘其壘。", "獨惟一妖鳥，來自崑崙趾。", "其高出天地，其毒踰蛇豕。", "名公不能辨，韓愈亦竊喜。", "高士溺其深，愚夫樂其鄙。", "精散不知收，魂飄不能止。", "五典潜掃除，三綱悉淪委。", "遂令四海人，沒溺懷襄水。", "絕非是似聖，大病在近理。", "仁哉天地心，特出程朱子。"]'),
('97831407-a176-4a67-8602-0e7ac39b3b95','程朱之學  其四','陳普','宋','宋诗','song-poetry','','[]','大中豈難明，不偏立可得。',120,'全唐诗/poet.song.243000.json','["大中豈難明，不偏立可得。", "偏似扶醉人，中如正柱石。", "亭亭即道體，截截皆天則。", "一毫不可裒，一髮不可益。", "舜君與堯民，萬世作程式。", "顔仁及曾孝，亦足立人極。", "倘或增減之，病痛自千百。", "立如偏重船，可坐見沒溺。", "形象亦易知，體段非不的。", "柰何秦漢來，如瞽於五色。"]'),
('be008368-b81d-4a4d-a907-f58039d32f12','雲莊勸學','陳普','宋','宋诗','song-poetry','','[]','百川皆望東，三才同面離。',288,'全唐诗/poet.song.243000.json','["百川皆望東，三才同面離。", "半圭崇幼德，六矢志男兒。", "孟子道非高，周公言非欺。", "要須辨方位，乃識窮陬維。", "自從學校廢，俗敝柏梁詩。", "英才陸沈盡，卓犖非無資。", "下車衆皆悅，苟且遂成癡。", "混澒聲一概，沈痼星千朞。", "天生紫陽子，纓冠而救之。", "萬類始根理，六經初有師。", "立心辨邪正，成德在勤嬉。", "曾參作門戶，夫子爲根涯。", "有位民物康，在家兄弟宜。", "敬義貫心筠，德業暢根枝。", "行遠必自邇，登高必自卑。", "不從灑掃起，何以爲類推。", "群居不及義，游宴日相追。", "失學莫此甚，一成而百隳。", "時文築衰末，不直埋馬帷。", "六經不勤讀，學荒身亦危。", "二劉與三蔡，相牖如塤箎。", "師門頼有嗣，流澤今未衰。", "子孫欲不墜，祖訓勤奉持。", "不失伯牙心，不患無子期。"]'),
('a268e05f-eac4-43d7-b2ef-d6754388e6ca','勸考亭收文公書兼聚書','陳普','宋','宋诗','song-poetry','','[]','孟氏繼孔徂，鳳鳥竟寂寞。',252,'全唐诗/poet.song.243000.json','["孟氏繼孔徂，鳳鳥竟寂寞。", "千年性命傳，造化欲廢閣。", "生人無所之，死者不可作。", "人心萬山隔，治統千大落。", "天生周與程，得手始撐拓。", "百年復考亭，體用遂磅礴。", "精密洗麤疏，深厚驅淺薄。", "窾郤靡不周，混沌元無鑿。", "誰家不藏書，心目迷博約。", "身爲行秘書，所適常迷錯。", "考亭三十匣，獨爲百川壑。", "萬善始有條，列聖元非昨。", "千派得一原，靈龜不勞灼。", "卷帙浩無邊，要處自如躍。", "歲月荒苔生，風雨惟丹雘。", "翁死六十年，輒起人哀樂。", "同心在咫尺，閔此無聲鐸。", "爲推去後心，如受生前托。", "倬彼得不磨，壞乎頼爰度。", "人心已開闢，萬象森沖漠。", "重搆理斯文，同盟敢無諾。"]'),
('4a7278ba-c503-40f8-8014-3f1d6c4c1792','感興','陳普','宋','宋诗','song-poetry','','[]','千載荷神物，四書與五經。',276,'全唐诗/poet.song.243000.json','["千載荷神物，四書與五經。", "勛華生萬民，孔顔真儀刑。", "本原盡溟漠，日用垂日星。", "疾契虎豹變，力行鳳凰庭。", "感通窮有氣，潤澤周流形。", "擬議輒破的，宰制動發硎。", "達即雨天下，窮足春林坰。", "自從孟子沒，斯義久晦冥。", "歆雄暨馬鄭，熠熠暗飛螢。", "韓柳至歐蘇，亦如醉不醒。", "白晝瞠兩目，不見太山青。", "蕙蘭亙九畹，鼻塞不聞馨。", "浩浩大城府，無人爲抽扃。", "宗廟失雄麗，樓閣迷岩亭。", "淵淵楚七澤，渺渺東滄溟。", "不識海若面，雄論誇揚舲。", "名爲指南車，認癸作丙丁。", "名夸能作室，戺夾如堂廳。", "異端塞宇宙，不能別渭涇。", "夜光耿砂礫，掉臂不留停。", "文章王介甫，種棘滿朝廷。", "匹夫持僞辯，六合爲血腥。", "讀書不精義，落落空摇精。"]'),
('325018c8-fa4e-48fd-9a3e-3d850e1f4433','文公書厨 於穆元聖','陳普','宋','宋诗','song-poetry','','[]','驪龍抱明珠，高卧萬丈下。',48,'全唐诗/poet.song.243000.json','["驪龍抱明珠，高卧萬丈下。", "豈無善水人，誰是得珠者。", "至人有神手，上智無淺心。", "直須入無倫，始克開重陰。"]'),
('b7599d87-2231-4248-81c7-28172578bc1b','文公書厨 繼天測靈','陳普','宋','宋诗','song-poetry','','[]','天生真聰明，欲子述父作。',48,'全唐诗/poet.song.243000.json','["天生真聰明，欲子述父作。", "法象雖昭陳，參贊良有托。", "述事在繼志，知化先窮神。", "不得天地心，作用皆非真。"]'),
('fc24f3ce-4a12-4def-80bb-ea327969e543','文公書厨 出此謨訓','陳普','宋','宋诗','song-poetry','','[]','仁心憂萬世，出語豈能無。',48,'全唐诗/poet.song.243000.json','["仁心憂萬世，出語豈能無。", "擬之而後言，一字一明珠。", "萬化必有成，大中在方策。", "淵泉端有自，聰明達天德。"]'),
('443372ac-d930-4557-b55c-6d4660306a49','文公書厨 惠我光明','陳普','宋','宋诗','song-poetry','','[]','釋氏矜傳燈，老莊抱生白。',48,'全唐诗/poet.song.243000.json','["釋氏矜傳燈，老莊抱生白。", "自言摩尼珠，誰知黑如漆。", "荀楊不識性，依舊如夜行。", "萬世真日月，四書與五經。"]'),
('b2761dbc-03e2-47c5-883a-059d9378da4e','文公書厨 永言寶之','陳普','宋','宋诗','song-poetry','','[]','世人多可笑，蜣丸富收拾。',48,'全唐诗/poet.song.243000.json','["世人多可笑，蜣丸富收拾。", "復有一般人，燕居加什襲。", "六經與玉府，惠我一何多。", "區區緣實見，沒世抱荆和。"]'),
('f4ad9e4d-9530-4528-95b5-f94b2db66018','文公書厨 匪金滿籝','陳普','宋','宋诗','song-poetry','','[]','人皆愛子孫，貽遺無不至。',48,'全唐诗/poet.song.243000.json','["人皆愛子孫，貽遺無不至。", "苟無深遠心，率以害爲利。", "韋賢未知道，不貴滿籝金。", "欲永金張業，但傳周孔心。"]'),
('6e928e92-36c1-4ea4-8a79-b403d3e26d87','文公書厨 含英咀華','陳普','宋','宋诗','song-poetry','','[]','聖心天地藴，言語其精華。',48,'全唐诗/poet.song.243000.json','["聖心天地藴，言語其精華。", "本末惟一貫，根香非兩家。", "薄言采擷之，入口如含咀。", "始知真滋味，熊掌不足語。"]'),
('52d32836-2c56-4e34-947d-11e1c7f20ca0','文公書厨 百家其承','陳普','宋','宋诗','song-poetry','','[]','仁以生爲道，豈不在子孫。',48,'全唐诗/poet.song.243000.json','["仁以生爲道，豈不在子孫。", "賢愚固難必，厥初同一原。", "無根不能生，有作斯可述。", "罔極垂統心，非禽豈無識。"]'),
('92687f6b-39ac-428e-bccc-052f20d8e692','冬華一夜霜','陳普','宋','宋诗','song-poetry','','[]','天地生萬物，節度各有常。',288,'全唐诗/poet.song.243000.json','["天地生萬物，節度各有常。", "毫髮不可亂，奉時以行藏。", "不惟寡悔吝，尤可免折傷。", "倘不如所受，一一皆自戕。", "今年初冬月，造物如不詳。", "陰陽忽倒植，連朝狀春光。", "無知桃李輩，定序忽迷忘。", "點綴老枝上，紛紛發出狂。", "一桂爲倡首，彈冠起群芳。", "杏思作霞燥，梨亦擬雪香。", "西蜀亦不遠，得無欺海棠。", "洛陽近咫尺，能不動花王。", "凍蜂與寒蝶，入秋皆死僵。", "向令當此日，鼓舞又一場。", "安知理自在，此事無久長。", "一夕天地正，嚴風動昏黄。", "吹起四澤水，結爲萬瓦霜。", "凌晨爲著目，憔悴不可當。", "萎形與死狀，貽笑於大方。", "古來此事多，青史長相望。", "惟有知道者，進退不狂揚。", "有莘必三聘，幡然始就湯。", "草廬亦三顧，然後起南陽。", "萬牛挽不至，粒餌豈足嘗。"]'),
('fc2a26a1-8c69-49e6-ae96-e5046c48fe2b','懸壺','陳普','宋','宋诗','song-poetry','','[]','懸壺大如斗，紫芋高五尺。',48,'全唐诗/poet.song.243000.json','["懸壺大如斗，紫芋高五尺。", "物能充其量，滿徹無不極。", "人稟天地正，性分亦有則。", "充之足爲堯，不充乃爲跖。"]'),
('6b0537f9-4f43-4b90-b873-76b78e651248','水車','陳普','宋','宋诗','song-poetry','','[]','人爲萬物靈，無處不可見。',288,'全唐诗/poet.song.243000.json','["人爲萬物靈，無處不可見。", "天地生物心，得人始周遍。", "有心鄭國渠，關中爲富衍。", "三十六陂流，江南穀爲賤。", "况如禹溝洫，流注周丘甸。", "是皆人所能，區畫固爲善。", "有力皆必爲，有知悉能辨。", "亦可展經綸，未足窮聖彥。", "有如一隅地，同出天地奠。", "未嘗阻耒耜，亦堪致芬薦。", "陂塘不能及，桔橰亦非便。", "鑿井設轆轤，祇益增疲倦。", "何人靜中眼，潛窺出靈變。", "種種田器中，衆美獨車擅。", "鳩集群樸樕，搆以天絲線。", "縱交合散雜，骨節不凌僭。", "相續同相生，如紐亦如辮。", "三十幅一轂，體用無迷眩。", "軋軋遠有聲，在田恍龍戰。", "吸吐皆自能，先後迭相禪。", "形如先天圖，運若坤靈扇。", "東西隔參辰，出沒遞隠見。", "升騰爲銀河，不足惟小欠。", "長流盡碧澗，腑臟悉充羨。"]'),
('f8fae2e4-75c2-4d3f-8446-5d8e1b11b201','筍  其一','陳普','宋','宋诗','song-poetry','','[]','書窗媚幽獨，萬竹真我儀。',288,'全唐诗/poet.song.243000.json','["書窗媚幽獨，萬竹真我儀。", "冰霜茂摧挫，生意自有時。", "斐亹弄月陰，挺拔出風姿。", "鳳吟逐神鬰，春笋效珍奇。", "山林足膏雨，土脈潤以肥。", "震雷摇蟄虺，千根同發機。", "迸芽带珠露，裂地拆伏龜。", "開窗見羅列，繭栗出扶藜。", "艱難或避石，奮逸或攢籬。", "森森麞鹿角，重重虎豹皮。", "地力既莫禦，天工亦不遲。", "志氣凌青雲，風節比伯夷。", "詎容薦清酒，但可供清詩。", "呼童竊取小，不敢言饞饑。", "含殻全其真，活火湯瀹之。", "知心三兩人，一樽留晚曦。", "錦䙀去什襲，玉版參吾師。", "似爲傷惻隠，直是慰肝脾。", "幾爲造化盜，何必鄰童窺。", "作橋周曲意，煮簀又何癡。", "惟應厚牆壁，高插數丈籬。", "護成碧琅玕，長似冰玉兒。", "吾聞北人說，洛下價不低。", "千金買一束，掉頭更還疑。"]'),
('eed5357a-27cd-4066-99fc-d78371b30a0e','筍  其二','陳普','宋','宋诗','song-poetry','','[]','造化運可見，渾天何用儀。',288,'全唐诗/poet.song.243000.json','["造化運可見，渾天何用儀。", "日月轉兩轂，陰陽分四時。", "化育出萬形，加之成氣姿。", "倚筇看生意，莫測其神奇。", "和風隨土至，膏雨著物肥。", "千紅咸競晨，萬玉亦乘機。", "深深起蟄龍，一一破伏龜。", "險不畏臲卼，難不避石藜。", "啟荆披瓦礫，撐屋觸藩籬。", "頭頭出兕角，身身水犀皮。", "大方欺小弱，尖先後止遲。", "不知水先頰，遊客戴鴟夷。", "六經無此物，昉見韓奕詩。", "韓侯富貴人，何况貧儒饑。", "詠形兼咀味，東坡韓退之。", "長鑱君莫訝，容我踏朝曦。", "內戒擣虀婦，外徵老圃師。", "留先鳳凰止，勿積蜜蜂脾。", "味既不可極，斑亦勿再窺。", "待爾林下友，一洗胸中癡。", "清風翠陰動，羽扇日接籬。", "此時林下客，何以并其兒。", "作未爭長日，滕高陵薛低。", "一旦並夷齊，兄弟無相疑。"]'),
('94c8957f-56c0-4eeb-a147-4fb5f280c0a4','和友人韻','陳普','宋','宋诗','song-poetry','','[]','兒童恨芳草，不識春長在。',96,'全唐诗/poet.song.243000.json','["兒童恨芳草，不識春長在。", "簞瓢樂不斷，焉知顔髮改。", "黄鶴雅入聽，鶗鴂亦可罪。", "混沌何曾死，拱璧莫輕碎。", "野馬恣流行，遊絲無罣礙。", "太極物物一，樂事頻年再。", "緬懷良友心，不言默相對。", "願爲蛩駏交，共話螻螘戴。"]'),
('c3688335-ec86-4cfb-b64d-b5cbe4b3c7cc','夫差伍員','陳普','宋','宋诗','song-poetry','','[]','載籍幾千年，相踵興亡跡。',288,'全唐诗/poet.song.243000.json','["載籍幾千年，相踵興亡跡。", "何國非自取，一一有來歷。", "亡必以失道，與必以有德。", "有德無不興，不在防寇賊。", "大綱一端正，上下合于一。", "左右無共鯀，小大皆益稷。", "執此治天下，天下無與敵。", "無道必自亡，不可容智力。", "中心一不正，禍亂起不測。", "計慮非不周，防閑非不密。", "龍蛇起平陸，刀劍出袵席。", "昔常恨吳王，不納伍員策。", "父讎不共天，吳越不兩立。", "敗之于夫椒，足報檇李役。", "殺心如未謝，滅越如呼吸。", "五千棲會稽，甲楯尚流血。", "一舉而盡之，後患永絕息。", "柰何倉卒中，鬼神奪其魄。", "不信忠臣言，坐使良機失。", "瞬息二十年，越兵破吳國。", "遂令泰伯祚，一日不血食。", "至今塵編中，見者皆嘆息。", "抑嘗思其故，此事未足蹙。", "吳亡自有端，滅越故無益。"]'),
('ae8a62a3-3499-4bb3-901a-d6b74d5fa7e2','荆公東坡','陳普','宋','宋诗','song-poetry','','[]','王蘇並世時，價重連城寶。',144,'全唐诗/poet.song.243000.json','["王蘇並世時，價重連城寶。", "讀盡天下書，不聞性天道。", "祇緣操術謬，濟以言辭藻。", "輕巧者便之，承風逐瀾倒。", "本意尊鞅斯，施行愧黄老。", "妄謂世無雙，奮臂肆揮掃。", "雅言類旃孟，給禦堅羿奡。", "及其漏綻時，乃以穿窬盜。", "荆棘日夜生，芝蘭遂枯槁。", "禮樂禹豫州，至今鞠煙草。", "重華不可呼，四罪無復討。", "薄夫迷遠謀，惟貪詩句好。"]'),
('0f766c88-2c7c-4d40-81e5-60dfe2dff087','壽龍津余此溪','陳普','宋','宋诗','song-poetry','','[]','昔在辛酉年，余裁十有八。',288,'全唐诗/poet.song.243000.json','["昔在辛酉年，余裁十有八。", "翁時多十歲，無地貯英發。", "世運欲轉移，正氣久鬰閼。", "科場弊已極，無復分椒樧。", "千里足難羈，須作奔泉竭。", "閉目駭奔騰，掩耳羞嘈囋。", "歸來分躬耕，復不禁芽枿。", "蒯緱走杭越，觸藩不能脫。", "紛紛夢中人，妄與談空闊。", "翁兮獨家居，自得真機栝。", "一日山河新，妙契靜中斡。", "尚堪作子長，亦久抱惻怛。", "遂生肥遯心，確乎不可拔。", "人間閙蜂蝶，過目惟蹙頞。", "惟有燕歸來，捲簾無阻遏。", "室鳴孺悲瑟，門斷陳遵轄。", "惟我拜床下，見侍隆中葛。", "軀爲天地惜，日用詩書豁。", "但見居深深，誰知活潑潑。", "松柏晚叢立，薑桂老逾辣。", "新年俄八十，道氣方蘭茁。", "平生善養氣，不作宋人揠。", "年來滋長茂，略不驚齒髮。", "人生各有志，萬物不能奪。"]'),
('8837ad97-afd0-496a-8241-3fa88cfabfe4','古田女  其一','陳普','宋','宋诗','song-poetry','','[]','昔年過饒州，一事獨希差。',288,'全唐诗/poet.song.243000.json','["昔年過饒州，一事獨希差。", "清川浴婦人，以晝不以夜。", "上流濯垢膩，下流汲歸舍。", "供佛與事尊，共用如啗蔗。", "朝昏賣魚蝦，晴雨親耕稼。", "樵蘇與負戴，咸與夫並駕。", "流污浴豈非，失禮事可訝。", "我時適逆旅，一見爲汗下。", "欲言不可得，况敢加譏駡。", "靜惟天下事，無邊可悲咤。", "一從文王沒，聲教不踰華。", "巴夔與閩粵，至今愧華夏。", "男不耕稼穡，女不專桑柘。", "內外悉如男，遇合多自嫁。", "雲山恣歌謠，湯池任騰藉。", "插花作牙儈，城市稱雄霸。", "梳頭半列肆，笑語皆機詐。", "新奇弄濃粧，會合持物價。", "愚夫與庸奴，低頭受凌跨。", "吾閩自如此，他方我可暇。", "福州縣十三，余幸窮厓下。", "十里近郭縣，此俗獨未化。", "一日來古田，拔秧適初夏。", "青裙半絞扎，水泥和撥迓。"]'),
('cafd5422-dd06-4fd9-8c77-976f8aba21a6','古田女  其二','陳普','宋','宋诗','song-poetry','','[]','北人見颶風，掀簸嗟真差。',288,'全唐诗/poet.song.243000.json','["北人見颶風，掀簸嗟真差。", "君子逢不若，白晝成黑夜。", "日月同一天，寧復殊次舍。", "禮義無華夷，悅心悉如蔗。", "披沙欲出金，惡莠爲害稼。", "朝歌與勝母，賢者同回駕。", "中爲去偏倚，庸但無怪訝。", "安敢亢亢方，却無伈伈下。", "禮不慮咈違，義不卹怒駡。", "恭惟秦漢前，禮樂止河華。", "七閩底處所，目不覩韶夏。", "食才美馬甲，衣僅知壓柘。", "應無雁幣聘，寧識棗脩嫁。", "歷漢晉至唐，談口無可藉。", "令孜與思勖，畏作貂璫霸。", "第從常衮來，始識不逆詐。", "珠玉滿面前，猶或迷光價。", "一二百年來，驊騮漸知跨。", "述古與介夫，各有詩書暇。", "晦翁黄勉齋，遂以教天下。", "昔時蠻隸國，今作齊魯化。", "沂風藹莫春，絃誦殷長夏。", "蹡蹡多規行，穆穆親衡迓。", "方知地無偏，又喜才不借。"]'),
('dbca9247-f2e6-493c-8132-d66c55c9ec95','純父家池雙頭蓮','陳普','宋','宋诗','song-poetry','','[]','天地化育工，兩致一爲要。',288,'全唐诗/poet.song.243000.json','["天地化育工，兩致一爲要。", "對待管流行，並起非橫矯。", "亭亭南北樞，赫赫東西曜。", "仁義與誠明，彼此相契約。", "英皇即堯舜，丰姿巧相肖。", "孤竹秀雙仁，洛水濯二妙。", "人生相遭處，亦有相感召。", "莘摯自犂鋤，尚父由漁釣。", "共卧起烟波，魚水興蓬藋。", "是爲聖人偶，心膽何相照。", "顔淵得仲尼，仲尼有荷篠。", "考亭合朱祭，天津會程邵。", "是爲德不孤，氣味何同調。", "世間閒草木，不足充野燒。", "惟蓮出清水，植立獨奇峭。", "不染淤泥緇，不逐波流漂。", "體骨中庸中，肌肉離騷皭。", "玩花渴頓蘇，食實饑足療。", "靜中對君子，不語潜教詔。", "一朝出蓮枝，此事非人料。", "將興必有祥，事若太阿鞘。", "茲化豈徒爾，可以觀其徼。", "上侍鶴髮慈，齒高德彌劭。", "下盼庭階郎，一一凌風鷂。"]'),
('c206c807-e938-4b34-9179-21660d90c015','玉山東嶽','陳普','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','岱宗夫如何，齊魯青已了。',108,'全唐诗/poet.song.243000.json','["岱宗夫如何，齊魯青已了。", "云胡遍天下，爨婢得祭禱。", "五嶽視三公，稱帝何所考。", "益以天齊名，僭竊良不小。", "置司七十二，妄誕出意表。", "冤哉張睢陽，夜夜蝙蝠繞。", "瀆神既已多，逆理尤不少。", "泰山即林放，末俗空擾擾。", "生辰用莫春，茲事可絕倒。"]'),
('8351e423-9418-41fe-98a7-4bb50b1bce0c','以詩就葉洞春求畫蒲萄','陳普','宋','宋诗','song-poetry','','[]','洞春豪傑士，妙筆出怪奇。',51,'全唐诗/poet.song.243000.json','["洞春豪傑士，妙筆出怪奇。", "寫就大宛根，可怪不可{扌棄}。", "此手豈易得，此手難再携。", "敢將有聲畫，博君無聲詩。"]'),
('7f3ae448-1de9-4e05-bd43-50a60f56ec7b','望雲','陳普','宋','宋诗','song-poetry','','[]','幾愛山中雲，杳靄起無跡。',120,'全唐诗/poet.song.243000.json','["幾愛山中雲，杳靄起無跡。", "晴風吹綠樹，天節日已尺。", "悠揚幾片飛，出岫度絕壁。", "斂作蒼狗形，舒爲鯤鵬翼。", "朝抹峨嵋青，暮蘸滄海碧。", "江南與江北，蕩蕩恣所適。", "何如雲中仙，避囂隠幽寂。", "採藥雲下林，礪劍雲上石。", "乘雲騎茅龍，倚雲吹鐵笛。", "我欲往從之，飄然不可測。"]'),
('bdeb6a95-5781-4819-91bc-6b4265368858','太極詩上范天碧侍郎','陳普','宋','宋诗','song-poetry','','[]','涵涵六合八紘裏，類聚化生何可紀。',384,'全唐诗/poet.song.243000.json','["涵涵六合八紘裏，類聚化生何可紀。", "固然兩人陰與陽，大要一個不得已。", "所從無聲亦無臭，所出如彼復如此。", "成象效法森目前，大自三才小一螘。", "形樣度數各有極，體段一一無偏倚。", "纇疵痕迹毫髮空，可驚可怪復可喜。", "參如交錯天然文，不斷去來川上水。", "堯舜得之御黄屋，不動脚手萬物理。", "孔顔得之洗其心，四時晝夜同行止。", "蓋緣道理元如斯，無非禮義當然耳。", "就中發出太極來，萬化一丸而已矣。", "眼看手搏漠無有，一日無之天地毀。", "片時俄頃不可離，萬古千秋長不死。", "靜爲體而動爲用，來爲神兮去爲鬼。", "不離於物仍猶尊，並行不僭光同體。", "但從化上識中庸，立見源流徹精髓。", "自從夫子繫周易，千古百年沒荆杞。", "一朝道在九疑下，紅輪扶出咸池洗。", "不私其有以示人，意與朋類同甘美。", "隋珠夜光翻不幸，操刀按劍如蠭起。", "唇焦口燥朱晦翁，至今無柰龍無耳。", "終然性在天地間，臭味不患無蘭芷。", "文正有孫已佳絕，混沌相識尤奇偉。", "震澤天台合清秀，洞見無終與無始。"]'),
('a7491505-0d9c-4e5a-a302-612eba3b1cf0','勸學','陳普','宋','宋诗','song-poetry','','[]','七閩四海東南曲，自有天地惟篁竹。',384,'全唐诗/poet.song.243000.json','["七閩四海東南曲，自有天地惟篁竹。", "無諸曾擁漢入秦，歸來依舊蠻夷俗。", "未央長樂不詩書，何怪天涯構板屋。", "人民稀少禽獸多，雲盤霧結成烜燠。", "樓船橫海未入境，淮南早爲愁蛇蝮。", "自從居股徙江淮，鳥飛千里惟溪谷。", "經歷兩世至孫氏，始聞種杏匝廬麓。", "依然未識孔聖書，徒能使虎爲收穀。", "異端神怪非正學，但可出野驚麋鹿。", "三分南北又幾年，匹士單夫無可錄。", "開元天寶唐欲中，闌干始見盤中蓿。", "日南韶石出名公，新羅二士非碌碌。", "七閩轉海即洙泗，僅有令孜與思勗。", "令人不忍讀唐書，不勝林壑溪山辱。", "天心地氣信有時，二三百年漸堪目。", "述古大年創發迹，義理文章相接續。", "蔡襄風任獬廌司，陳烈氣壓龍虎伏。", "介夫當仁竟不讓，了翁守義窮彌篤。", "天開道統游楊胡，一氣北來若蘭馥。", "了翁責沈先識程，子容聞風亦知肅。", "劍龍化作李延平，道理益明仁益熟。", "遂生考亭子朱子，撐拓三才開伭育。", "植立綱常鰲戴地，開發蒙昧龍銜燭。", "三胡三蔡與五劉，新安建安如一族。"]'),
('fbb24d5f-aedb-4dc6-95c7-40ed218fd043','禁酒','陳普','宋','宋诗','song-poetry','','[]','五穀之中有淫液，堯舜未嘗得涓滴。',352,'全唐诗/poet.song.243000.json','["五穀之中有淫液，堯舜未嘗得涓滴。", "剛柔張弛理或容，兩間緣此生儀狄。", "初如濫觴出岷山，中作江漢橫人間。", "沃焦蘇枯亦宜有，滔天襄陵苦不難。", "幾人捐軀乞鮫鰐，幾家蕩析無城郭。", "古今魚鱉劇永嘉，至今無人非畢卓。", "聖人哲士謀慮長，金城鐵壁爲隄防。", "尊崇流水尚泛溢，黜降登躋毋升堂。", "森嚴監史如霜雪，無算無量無踰節。", "僛僛傞傞未嘗有，山立佳人冰玉潔。", "柰何世降波瀾狂，周公不作衛武亡。", "漢家石杠耗海內，唐殿金龍跨遠方。", "上下因循爲日用，勝理腸胃成膏肓。", "病民害物拂后土，愁天怒地干陰陽。", "聖君宵衣急民瘼，一照萬方同忭躍。", "救荒令典固當爾，此事更有加商略。", "東西晉武覆轍新，李白杜甫皆沉身。", "夏后以前皆聖世，豈無貴客與鬼神。", "四維不張既非美，人而無禮不如死。", "阮籍罪當投四裔，山簡接䍦尤亂紀。", "江東命脈王茂弘，荆州父母陶士行。", "更乞十年禁酺蜡，書生鼓腹老太平。"]'),
('b2db8777-51a0-4261-9cf0-ec8f22d4be2d','壬辰日蝕','陳普','宋','宋诗','song-poetry','','[]','憶昔度宗皇帝時，十年十三日食之。',96,'全唐诗/poet.song.243000.json','["憶昔度宗皇帝時，十年十三日食之。", "似道屭贔湖海曲，天子宮庭躭樂嬉。", "滿朝翕翕皆婦人，禍來照鏡方畫眉。", "北軍順流日食既，兩國正爾爭雄雌。", "興亡豈必皆有數，百年以來士氣索。", "文臣髀肉不識馬，武士驚魄怕見旗。"]'),
('0c09daf6-3bf9-447f-8ac2-0802853de184','壽柏峰','陳普','宋','宋诗','song-poetry','','[]','愛道愛寶同縮蝸，福善一點如朝霞。',144,'全唐诗/poet.song.243000.json','["愛道愛寶同縮蝸，福善一點如朝霞。", "稽天利欲渺無路，不妨甪里留巔崖。", "清虛淡素天所覷，百神萬物爭擁遮。", "七十移桃自玄圃，八十意思猶未花。", "含如抱粹不肯露，時對知己抽萌芽。", "我亦一人年在弟，弱質自媿霜蒹葭。", "逢人說項有何見，豈非氣味同一家。", "啖柏茹芝分一葉，朝夕供兄粥與茶。", "一任張良算出去，人生何惜老年華。"]'),
('e500f1ab-77c4-412f-82e9-1f4680bc77d5','久旱得雨','陳普','宋','宋诗','song-poetry','','[]','同堂合席分汝爾，况乃邈然千萬里。',272,'全唐诗/poet.song.243000.json','["同堂合席分汝爾，况乃邈然千萬里。", "寸總不知從何來，一夜擁衾八九起。", "井田未復思扣閽，忍見秋夏田無水。", "甘霖才是渴者飲，何事驕陽驕不止。", "旄倪奔走緣木求，惟有氣龍尚循理。", "焉知天心不廣大，無愚無智皆如子。", "拜泥禱偶都不問，銜石移山良可喜。", "雲飛風起作氣勢，野霧山昏醖甘美。", "三朝遂作渰渰萋，一點一粒不勝紀。", "吁嗟爾輩何惜命，歡呼噎嘔舞欲死。", "有身安得不求生，天地之心固如此。", "草茅藜藿有一策，堯舜是亦人而已。", "端居廊廟同此身，及人及物唯推己。", "宮中聖人念民物，春不折柳漱避蟻。", "論道燮理豈不知，一夫不獲古所耻。", "三年耕有一年食，堯水湯旱無死徙。", "有民心也爲民謀，此道如砥直如矢。"]'),
('23f4823c-69cd-46b7-87a9-68790bfc4057','壽容山','陳普','宋','宋诗','song-poetry','','[]','天下東南有玄圃，左瞰閩浙右俯楚。',240,'全唐诗/poet.song.243000.json','["天下東南有玄圃，左瞰閩浙右俯楚。", "藴瓌露秀周峰巒，異氣時出爲雲雨。", "何年營丘文獻孫，相攸弛檐來胥宇。", "綿綿瓜瓞日蕃滋，福德兩兼一爲主。", "山川歡喜神靈依，五者日用如水土。", "我來昔在旃蒙年，乃翁八十健如虎。", "再來當公六十六，春風習習生談麈。", "即溫聽厲心自凉，不覺人間有炎暑。", "年年今日慶生申，已得河圖天數五。", "今年三合尤奇妙，人生與猨共歌舞。", "樽前萬事皆如意，酒酣屈指爲君數。", "彩衣堂下森芝蘭，四宗人人皆玉樹。", "詩書禮義照人間，謙恭孝弟麒麟武。", "高年壯健幼穉仁，此事天下莫之禦。", "福地何但貯退藏，請以閟宮代梁甫。"]'),
('b5dc4d8f-e5a1-4398-8fac-2b8648f08739','有感','陳普','宋','宋诗','song-poetry','','[]','後人百事不如古，創立造爲難悉數。',352,'全唐诗/poet.song.243000.json','["後人百事不如古，創立造爲難悉數。", "一日苟且成千年，一夫阿狥彌九土。", "神仙不死豈有之，起自秦皇并漢武。", "蜀陵冀角民鼓亂，樓殿至今連海宇。", "從明未載心神飛，無根金人忽如覩。", "膏肓遂成不可治，五教壅塞生民苦。", "帝城元夜移三山，天河七夕橋織女。", "倡優侏儒爲戲樂，淫詞浮文作貢舉。", "賣鹽沽酒充科賦，吹簫執籥送喪死。", "一般更有亂生人，背棄劬勞事歌舞。", "造端良是魏隋間，以至開元遂爲瘉。", "四海之人皆若狂，諛舌紛紛蔽明主。", "五鳳樓前舞千秋，漁陽動地來鼙鼓。", "六飛倉卒冒煙塵，兩京流血欲漂杵。", "此禍端從逸欲生，國無良臣致惑蠱。", "事君事親不在是，福壽自有千門路。", "曲禮三千無一條，六經百氏無一語。", "空隨流俗作愚蒙，並將四海蒼生誤。", "先儒未嘗論及此，共慶重闈或可許。", "不知沿習祇可傷，明知故作非相與。", "忠告善道不是從，己所不欲當絜矩。", "豈知謬致一瓣香，面把黨人作聾瞽。"]'),
('00ad9896-f0d9-45d0-ad74-ae1f73bbfa47','代壽德興尹','陳普','宋','宋诗','song-poetry','','[]','堯蓂五葉開元正，堯雲五色輝紫清。',160,'全唐诗/poet.song.243000.json','["堯蓂五葉開元正，堯雲五色輝紫清。", "漁歌樵唱樂寬政，今日公堂彌兕觥。", "江南春穉寒猶峭，東風先綠銀峰草。", "銀峰百草皆何私，邀得東風來獨早。", "寬厚不愎父母心，父母萬壽兒願深。", "老穉盡作斑衣舞，來聽春風堂上琴。", "黄金臺上凝虛竚，碧雲爲捲琴聲去。", "要令四海皆陽春，不但銀峰沐膏雨。", "區區祝公在此詩，寸草莫報春陽輝。", "秉鈞暫借牛刀手，八荒開壽如堯時。"]'),
('92ef1687-ea17-4bbf-95fb-6e6f6b8bd5a4','天上碧桃','陳普','宋','宋诗','song-poetry','','[]','春階蕩漾春日長，羽林颯颯勾陳蒼。',192,'全唐诗/poet.song.243000.json','["春階蕩漾春日長，羽林颯颯勾陳蒼。", "鈞天寥寥帝不康，一月震悚奔勾芒。", "夜鳩衆功和陰陽，粉白黛綠各一方。", "鑄作娟麗盈盈粧，金烏飛去東藩傍。", "左右前後千毛嬙，青雲衣兮白霓裳。", "重重華蓋十六行，瓊林玉殿積縞霜。", "氣焰薰薄摇籃光，白雲鄉是碧雲鄉。", "騎龍韓愈如漁郎，緱山仙子聞仙方。", "坐鶴之背吹鳳凰，穆子簡子方來王。", "氣迷色眩成肆狂，執法叩閶夕抗章。", "有一於此無不亡，言從諫聽如禹湯。", "斥罷脂澤去芬芳，各服毼衣事蠶娘。"]'),
('32467121-499e-4fa3-9012-7ba0dc5e3eb9','夜臺','陳普','宋','宋诗','song-poetry','','[]','角陵初爲五斗盜，崔浩繼作千尋宮。',208,'全唐诗/poet.song.243000.json','["角陵初爲五斗盜，崔浩繼作千尋宮。", "重黎不生大禹死，鬼魅雜出交蛇龍。", "妄夸奪盡離婁明，虛喝弱却樓煩弓。", "禮樂沉淪入九地，陰邪叫嘯充虛空。", "人寰黯淡如夜臺，百物悽愴生芒鋒。", "虎狼四出食人肉，四溟不受黄流東。", "豈無健士能排遏，末俗骨醉難爲功。", "我欲南游叫虞舜，一怒爲我誅兜共。", "陰陽草昧風氣閉，蒼梧日落天鴻濛。", "代天去惡如拔薤，後剪枝葉先其宗。", "洗心學易見太極，百怪冰釋春流通。", "道在不係後與前，日月東出開群蒙。", "更須講究銅駝事，結正當年河上公。"]'),
('776e3894-84ff-4dd0-b25e-7919d23b3319','德陽林梅麓太守輓章','陳普','宋','宋诗','song-poetry','','[]','殷士皆周祼，南音獨楚冠。',48,'全唐诗/poet.song.243000.json','["殷士皆周祼，南音獨楚冠。", "寢車人更怒，負俎我何安。", "義合雍容就，名應久遠看。", "梅花真鐵石，耐得許多寒。"]'),
('997924f0-7bd5-4a73-88a2-5f4555f86212','輓平山菊澗  其一','陳普','宋','宋诗','song-poetry','','[]','自是斯民手，全成此世身。',48,'全唐诗/poet.song.243000.json','["自是斯民手，全成此世身。", "片言含展席，一室見經綸。", "德業空成己，詩書止事親。", "但贏千載內，一樣不無人。"]'),
('3a9143d2-678e-4f82-9155-09f18f818ac1','輓平山菊澗  其二','陳普','宋','宋诗','song-poetry','','[]','卑卑梯接俗，望重若蒿蓬。',48,'全唐诗/poet.song.243000.json','["卑卑梯接俗，望重若蒿蓬。", "作俑繄何代，彌天以送終。", "閙居常憤切，易簀愈昭融。", "一二人家化，駸駸似洛中。"]'),
('91aee9dd-d018-40d1-996f-2daab19cae78','輓平山菊澗  其三','陳普','宋','宋诗','song-poetry','','[]','小試庖丁刃，天王信不虛。',48,'全唐诗/poet.song.243000.json','["小試庖丁刃，天王信不虛。", "林林驚若鳳，戢戢免其魚。", "一日乾坤定，終身岩谷居。", "人皆疑不仕，莫曉我心初。"]'),
('53d60aab-b97f-46d8-b806-d8758749b93b','輓平山菊澗  其四','陳普','宋','宋诗','song-poetry','','[]','細細香鼻孔，寥希古已然。',48,'全唐诗/poet.song.243000.json','["細細香鼻孔，寥希古已然。", "相逢言尚古，話久許知天。", "太極有形外，幾宵燈火前。", "示人猶不敢，何見遽刊傳。"]'),
('17c0f0f1-b971-42a6-badd-463b1c6a4eee','輓平山菊澗  其五','陳普','宋','宋诗','song-poetry','','[]','獲接阿戎裾，殷勤便手盧。',48,'全唐诗/poet.song.243000.json','["獲接阿戎裾，殷勤便手盧。", "開緘伯淳坐，入夢孔明廬。", "敬事期身役，摳趨刻歲餘。", "天翁如錯誤，流涕看苫苴。"]'),
('43b3a8a6-8c4c-4087-9a45-f8bc642268a9','輓平山菊澗  其六','陳普','宋','宋诗','song-poetry','','[]','詩禮斯文嫡，簞瓢此世人。',48,'全唐诗/poet.song.243000.json','["詩禮斯文嫡，簞瓢此世人。", "心惟憂道屈，眼不見家貧。", "清瘦生來骨，孤高沒後身。", "幾多黄壤客，難朽得如君。"]'),
('f271d185-10d0-4a5a-b47c-3f898f489f98','凭闌  其一','陳普','宋','宋诗','song-poetry','','[]','南浦路東西，佳人不可期。',48,'全唐诗/poet.song.243000.json','["南浦路東西，佳人不可期。", "斷雲荒草渡，歸鳥夕陽枝。", "心事十二曲，頭顱大半絲。", "低回問流水，去去復何之。"]'),
('8c0297b2-5dfc-4b7d-bb03-f3cf3879d82b','凭闌  其二','陳普','宋','宋诗','song-poetry','','[]','高豁乾坤眼，山晴綠雨收。',48,'全唐诗/poet.song.243000.json','["高豁乾坤眼，山晴綠雨收。", "夕陽流水遶，荒草白雲浮。", "柳蔭小溪側，樵歌古渡頭。", "凭虛發清嘯，安得仲宣樓。"]'),
('78aec810-8e42-4e1e-910d-2cd82c726ef8','行藏','陳普','宋','宋诗','song-poetry','','[]','四時晝夜有成姿，用舍行藏亦易知。',64,'全唐诗/poet.song.243000.json','["四時晝夜有成姿，用舍行藏亦易知。", "祭器無周應獨抱，儒冠有越莫空資。", "亂由徑竇人皆笑，不出門庭鬼亦疑。", "千古常經川上水，莫將閑氣動詩脾。"]'),
('00e88226-709c-4b9a-a4f8-66677dd3dfca','感興','陳普','宋','宋诗','song-poetry','','[]','晦翁去後道無傳，智水仁山尚宛然。',64,'全唐诗/poet.song.243000.json','["晦翁去後道無傳，智水仁山尚宛然。", "一室落成方翠碧，四書未竟已黄泉。", "心留雨暗雲深處，魂在月明猿哭邊。", "山上仙靈還聚合，虹橋消息問何年。"]'),
('75484451-eb3a-4431-a754-3c5ad47b5234','讀書有感','陳普','宋','宋诗','song-poetry','','[]','弄舌儀秦久厭看，無言混沌自安閒。',64,'全唐诗/poet.song.243000.json','["弄舌儀秦久厭看，無言混沌自安閒。", "人心何日無堯舜，道學終天有孔顔。", "五鬼不磨吾道義，二秦長是此江山。", "窗前宿草根長在，萬古春風去復還。"]'),
('f2718f98-a76e-49fc-9d46-3d8363be653e','憶昔','陳普','宋','宋诗','song-poetry','','[]','壯歲聲名動洛陽，重重皎日出扶桑。',64,'全唐诗/poet.song.243000.json','["壯歲聲名動洛陽，重重皎日出扶桑。", "筆鋒剛勁萬人敵，文陣縱橫百勝場。", "天下文明仰龍見，胸中韜略困鷹揚。", "喚回三十年前夢，撫案挑燈感慨長。"]'),
('fcf2f4fa-df97-4ede-ac61-79a92dcde350','出行','陳普','宋','宋诗','song-poetry','','[]','半挑行李出藍關，便覺前程地步寬。',64,'全唐诗/poet.song.243000.json','["半挑行李出藍關，便覺前程地步寬。", "鯨力衝開千里浪，龍光射破萬層巒。", "逢人切莫談邊事，開口何須問故山。", "貧殺一身無足道，蒼生百萬要平安。"]'),
('b87d0004-9294-488d-9067-a73b583ddad5','積雨寫懷  其一','陳普','宋','宋诗','song-poetry','','[]','識道知時乃聖賢，合人統物一之天。',64,'全唐诗/poet.song.243000.json','["識道知時乃聖賢，合人統物一之天。", "兩間惟有心長在，萬變咸歸理自然。", "王屋大行從艮止，北溟南海謹坤先。", "行藏悉是乾龍體，要得無慚只在淵。"]'),
('8e4b2a39-2059-4fcb-8696-12c332f4e3ed','積雨寫懷  其二','陳普','宋','宋诗','song-poetry','','[]','一片真純要反觀，纖毫外物不相干。',64,'全唐诗/poet.song.243000.json','["一片真純要反觀，纖毫外物不相干。", "樂天豈向青雲樂，安土須從陋巷安。", "日出扶筇天地喜，雲深撥火鬼神看。", "化機何啻親兄弟，但與爲徒有底難。"]'),
('94c42aa5-aae7-4fb8-86ed-787ba9b3f1eb','野燒','陳普','宋','宋诗','song-poetry','','[]','雜沓平原起電紅，憑陵勢欲逼青峰。',64,'全唐诗/poet.song.243000.json','["雜沓平原起電紅，憑陵勢欲逼青峰。", "草芽不問新開甲，蟄戶尤憐乍啟封。", "何暇徹侯分玉石，略如伯益逐蛇龍。", "際天逸德無人問，獨倚高樓到晚鍾。"]'),
('8beafd1e-bd2e-4328-9f5a-a2fde3c81e7d','暮春始聞雷','陳普','宋','宋诗','song-poetry','','[]','倉庚杜宇已喧卑，出地奔空獨爾遲。',64,'全唐诗/poet.song.243000.json','["倉庚杜宇已喧卑，出地奔空獨爾遲。", "六合中間皆起處，一更前後恰來時。", "吝蝸封閉俄驚破，迷蝶沉酣恐未知。", "菌蠢蟄龍安靜退，不妨奮豫小愆期。"]'),
('9e9a89be-cad6-40c5-82c7-0cc80af4ed30','偶成呈純父','陳普','宋','宋诗','song-poetry','','[]','朋友之倫在天地，何啻玄璜耦赤璋。',64,'全唐诗/poet.song.243000.json','["朋友之倫在天地，何啻玄璜耦赤璋。", "不聆玉人春風話，禁得鐵衾秋雨牀。", "幾人超距作貔虎，三尺弱孺思蠻强。", "幾回合眼在丹碧，講談帝伯鋪皇王。"]'),
('1f4ae27f-7023-483f-8cc0-d59666cf00c6','范雎蔡澤','陳普','宋','宋诗','song-poetry','','[]','戰國諸公敝一言，磨喉礪舌亂乾坤。',64,'全唐诗/poet.song.243000.json','["戰國諸公敝一言，磨喉礪舌亂乾坤。", "儀秦已作風霆過，范蔡方爲河海翻。", "榮耀須臾空自喜，真淳毫髮了無存。", "但憐三代遺孩稚，流血成河暗本原。"]'),
('45f3e3c8-8bcc-4b70-bc0b-6bb13def5f93','謝天爵惠詩和韻','陳普','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','男子須爲顔孟徒，文章義理視公沽。',64,'全唐诗/poet.song.243000.json','["男子須爲顔孟徒，文章義理視公沽。", "不窮六籍不爲學，未了三才未是儒。", "當作大鵬辭斥鷃，又如快鶻入群烏。", "泰山到頂無多路，不肯攀登直是愚。"]'),
('cc1f86bc-e8d5-49c6-b3ab-5c4dae77374b','福城無雪然人物與洛城一也','陳普','宋','宋诗','song-poetry','','[]','入城一見便金蘭，青眼論心視肺肝。',64,'全唐诗/poet.song.243000.json','["入城一見便金蘭，青眼論心視肺肝。", "日用共爲時世笑，晝眠常見鬼神看。", "狂歌雪裏忘年老，高卧城中傲歲寒。", "但願康寧百二十，年年斫雪訪袁安。"]'),
('f3fd62d0-059a-4bd9-8984-94b1ace929b4','謝岩上張伯春伯齊兄弟子姪惠生日詩','陳普','宋','宋诗','song-poetry','','[]','苟食媮衣豈足論，諸公何見爲開尊。',64,'全唐诗/poet.song.243000.json','["苟食媮衣豈足論，諸公何見爲開尊。", "詩書雖讀道何有，爵德咸無齒敢言。", "泉下年年孤祖考，眼前事事負乾坤。", "幸隨草木酣秋色，晚節黄花別立根。"]'),
('a3ce9921-1300-480b-931d-98162e8df43c','賀岩上張商翁新居','陳普','宋','宋诗','song-poetry','','[]','商嶺高風動帝皇，商巖清夢到君王。',64,'全唐诗/poet.song.243000.json','["商嶺高風動帝皇，商巖清夢到君王。", "故將琴劍詩書室，結向烟霞水石旁。", "紫氣遥知穿戶牖，青松應不隔垣牆。", "後堂且設彭宣席，未許鶑鶑燕燕忙。"]'),
('84be3760-d7b9-45fb-87af-6e233edfc384','賀叔父爲猶子成室','陳普','宋','宋诗','song-poetry','','[]','五典三綱宇宙人，千金九鼎祖宗身。',64,'全唐诗/poet.song.243000.json','["五典三綱宇宙人，千金九鼎祖宗身。", "茶租急切同胞義，冰蘗規模一箇仁。", "日月照臨倫理得，山川迴合棟梁新。", "教人以意非言語，此事由家更及民。"]'),
('d2f602a1-d9d6-40ab-ba61-b3228da2bbe8','賀純父修考亭成','陳普','宋','宋诗','song-poetry','','[]','宇宙中間此考亭，接連千聖集三靈。',64,'全唐诗/poet.song.243000.json','["宇宙中間此考亭，接連千聖集三靈。", "乍年松柏參天翠，無事莓苔滿地青。", "道統拳拳俄棟宇，人心隠隠又雷霆。", "世間萬事無難者，但把純心對六經。"]'),
('42b1f86a-75df-47b2-8f49-a58ffc350ae2','懷古','陳普','宋','宋诗','song-poetry','','[]','世事悠悠一轉頭，斷雲荒草古今愁。',64,'全唐诗/poet.song.243000.json','["世事悠悠一轉頭，斷雲荒草古今愁。", "青山北去黄河隔，白日西飛東水流。", "秦有金牛開劍閣，楚無熊虎割鴻溝。", "無情蕭寺峰前月，幾夜蛩聲影半樓。"]'),
('c16b44e0-826a-4a3c-9f20-b1781cb7caec','呈縣尹  其一','陳普','宋','宋诗','song-poetry','','[]','生賢造物意何仁，一本從來只爲民。',64,'全唐诗/poet.song.243000.json','["生賢造物意何仁，一本從來只爲民。", "擇取易中五陽卦，要令到處四時春。", "黄扉紫闥終行志，碧水丹山且愛人。", "滿縣栽花祇悅目，桑麻雨露是公真。"]'),
('f93d0ac4-9efb-4825-9297-f9acfecf5af3','呈縣尹  其二','陳普','宋','宋诗','song-poetry','','[]','富貴能無不俛眉，太玄久作覆瓿資。',64,'全唐诗/poet.song.243000.json','["富貴能無不俛眉，太玄久作覆瓿資。", "柴荆晝刻聲何駛，芹草春風浪已披。", "似此深心寧爲己，其如淺學謬蒙知。", "位無大小心惟一，已是當年吐哺時。"]'),
('ba9fab6b-5f51-4543-8e2d-56fbdc4149a5','贈葉洞春畫葡萄','陳普','宋','宋诗','song-poetry','','[]','引蔓牽藤寸管頭，扶驪剔蚌出風流。',64,'全唐诗/poet.song.243000.json','["引蔓牽藤寸管頭，扶驪剔蚌出風流。", "三千龍女拋珠佩，一個儒生擁碧油。", "莫是前生封即墨，便堪作酒博青州。", "齊奴倘會清妍意，免得紅裙逐翠樓。"]'),
('e4e44e21-5f37-4a7f-a8ec-931b82af70f7','和清叟自勉','陳普','宋','宋诗','song-poetry','','[]','緝熙正學勿虛過，立志悠悠得幾何。',64,'全唐诗/poet.song.243000.json','["緝熙正學勿虛過，立志悠悠得幾何。", "黄卷工夫當猛省，青春齒髮莫蹉跎。", "筆頭有燄由充養，鏡面無塵在洗磨。", "六籍四書無釋手，胸中治具看森羅。"]'),
('e287addd-d88b-4ecb-a481-72c882425022','和清叟奉御大都','陳普','宋','宋诗','song-poetry','','[]','帝里春深草木苞，御河滾滾浪翻桃。',64,'全唐诗/poet.song.243000.json','["帝里春深草木苞，御河滾滾浪翻桃。", "萬千紅紫跡如掃，九十青皇壽已高。", "南國江山歸夢遠，東宮松桂晝陰交。", "丘園喜有平安報，新竹初成集鳳梢。"]'),
('c56343fa-faa1-4c51-83be-ee2acd1d7f9b','和友人惠詩','陳普','宋','宋诗','song-poetry','','[]','萬事無非理數成，吾徒但向此研精。',64,'全唐诗/poet.song.243000.json','["萬事無非理數成，吾徒但向此研精。", "介鱗有分當咸若，麟鳳何緣許瘦生。", "愧我詩書空盜竊，喜君學易有功程。", "相逢亦似非人力，十載昏花一日明。"]'),
('2c4f5ef8-3171-4996-83b9-ddfea70826d6','挽熊去非','陳普','宋','宋诗','song-poetry','','[]','疇昔鼇峰乍盍簪，爲予一動伯牙琴。',64,'全唐诗/poet.song.243000.json','["疇昔鼇峰乍盍簪，爲予一動伯牙琴。", "文明濟濟英雄集，祭禮洋洋上聖臨。", "古道違時成握手，狂言駭俗頼知心。", "群居離索非今日，宿草萋萋得訃音。"]'),
('f507f7f3-ec2b-4c0a-b4b2-3ce91ea64645','和叔父九日後樓集  其一','陳普','宋','宋诗','song-poetry','','[]','霞邊鶩表見羅浮，左右東南數十州。',64,'全唐诗/poet.song.243000.json','["霞邊鶩表見羅浮，左右東南數十州。", "天近先看洗光日，地高略數下灘漚。", "乾坤廣大千峰玉，人物英雄百尺樓。", "衰暮來茲更重九，菊花須滿雪霜頭。"]'),
('2117e396-5fa3-457a-bef0-31cead204c8b','和叔父九日後樓集  其二','陳普','宋','宋诗','song-poetry','','[]','萬化區中總莫逃，範圍不得是清高。',64,'全唐诗/poet.song.243000.json','["萬化區中總莫逃，範圍不得是清高。", "天將萸菊溫存晚，秋把山川貼助豪。", "祭禰五更薦儀禮，上樓萬境擥離騷。", "化工似欲重重九，催促霜前辦兩螯。"]'),
('984f30da-c5b6-49c0-8d06-fc7aecedcef0','和開元余兄儒術悮身  其一','陳普','宋','宋诗','song-poetry','','[]','安得茅茨美化流，絃歌多著武城游。',64,'全唐诗/poet.song.243000.json','["安得茅茨美化流，絃歌多著武城游。", "文章久矣經天地，孝悌非徒淑黨州。", "惟有命焉軻不謂，貧非病也憲何羞。", "曼相能使人相類，莫信詩人浪訴愁。"]'),
('701c6e46-5ec3-42bc-aab9-3a942cd762ed','和開元余兄儒術悮身  其二','陳普','宋','宋诗','song-poetry','','[]','莫逐嗟卑嗟老流，謀身先向呂宮遊。',64,'全唐诗/poet.song.243000.json','["莫逐嗟卑嗟老流，謀身先向呂宮遊。", "力耕不怕水和旱，篤信能行貊與州。", "寡悔到頭終得祿，不恒自古或承羞。", "藜羹布被君休嘆，五十無聞却是愁。"]'),
('797f47e7-efd2-41fa-8ee9-8b2b1826ecf6','柳絮','陳普','宋','宋诗','song-poetry','','[]','去跡來蹤莫可尋，辱人頭面與衣襟。',64,'全唐诗/poet.song.243000.json','["去跡來蹤莫可尋，辱人頭面與衣襟。", "若爲蟣虱蟲蛆類，亦享軒窗庭戶陰。", "六合中間不知數，兩儀化育亦何心。", "手彈劍擊皆遷怒，只待霜風響竹林。"]'),
('bbb261e7-811d-4a37-b243-fa128e22d859','和答友人','陳普','宋','宋诗','song-poetry','','[]','萬事云何只有吁，閑調經世月牙吾。',64,'全唐诗/poet.song.243000.json','["萬事云何只有吁，閑調經世月牙吾。", "要知剝復無非數，不定乾坤未用儒。", "莫問蹠非并舜是，但存房範與膺模。", "洗心□有義方易，閒氣須教半點無。"]'),
('b3c17bc6-05b8-49dd-9725-161d080c0b11','和荼䕷','陳普','宋','宋诗','song-poetry','','[]','綠霜和雪揉爲裁，消得玻瓈紫玉杯。',64,'全唐诗/poet.song.243000.json','["綠霜和雪揉爲裁，消得玻瓈紫玉杯。", "擾擾開時違賞翫，匆匆落去謾遲回。", "顛迷蝶夢留蝸國，荏苒龍珠入蚌胎。", "急作招魂傾桂酒，尚餘半面在蒼苔。"]'),
('7829bc77-03e5-4b0f-a725-207b366f7760','挽蒼崖','陳普','宋','宋诗','song-poetry','','[]','自君綦迹絕茲邦，共訝君爲採藥龐。',64,'全唐诗/poet.song.243000.json','["自君綦迹絕茲邦，共訝君爲採藥龐。", "疾景更先伯淳一，佳兒獨欠郭公雙。", "一經有托死何恨，兼善未酬心肯降。", "淚滿平生師友事，山中幾度酒盈缸。"]'),
('cd05e2d5-abac-4941-ae75-cd28e87c9e37','和菜花  其一','陳普','宋','宋诗','song-poetry','','[]','天公大似慰顔貧，二月滿園瓜子金。',64,'全唐诗/poet.song.243000.json','["天公大似慰顔貧，二月滿園瓜子金。", "不問異根仍異味，盡令同色亦同心。", "輪蹄見棄各有路，蜂蝶爭趨亦若林。", "魏紫姚黄來課此，如聞太古簣桴音。"]'),
('b4e5dad3-a785-46a6-bfdd-c09cca1a4485','和菜花  其二','陳普','宋','宋诗','song-poetry','','[]','華實根荄若箇般，深知始解識鹹酸。',64,'全唐诗/poet.song.243000.json','["華實根荄若箇般，深知始解識鹹酸。", "爭春豈敢當紅紫，貼地何能助碧丹。", "未說餘膏尤濟用，最令中色直堪餐。", "洛陽個個知揚撥，此物却無人會看。"]'),
('8b68801f-de06-4be5-a5c9-d8bc02c6033b','夜坐','陳普','宋','宋诗','song-poetry','','[]','書債如山未有涯，幽懷耿耿夜眠遲。',64,'全唐诗/poet.song.243000.json','["書債如山未有涯，幽懷耿耿夜眠遲。", "官無蟈氏蛙何橫，天靜狼星狗不知。", "談易入神山鬼笑，端襟持鏡玉蟾窺。", "悠悠窗下新功小，羞見凌空萬玉姿。"]'),
('d4d3afe3-2cb6-4a15-88a8-5a0666bec704','山中','陳普','宋','宋诗','song-poetry','','[]','便是人間一洞天，墮樵煮茗晝騰烟。',64,'全唐诗/poet.song.243000.json','["便是人間一洞天，墮樵煮茗晝騰烟。", "深春笋蕨千鍾祿，落日漁樵三島仙。", "一脈甘泉生白石，數竿修竹對青氈。", "天關九府高無路，莫助椒芹獻小鮮。"]'),
('bbb1cef9-bb06-488b-9b2a-3c28882de784','野景','陳普','宋','宋诗','song-poetry','','[]','衮風柳絮亂溪橋，一抹輕烟野外遥。',64,'全唐诗/poet.song.243000.json','["衮風柳絮亂溪橋，一抹輕烟野外遥。", "獨釣漁翁占江上，耦耕農父伴山腰。", "黄鸝百轉趁紅日，白鷺一行登碧霄。", "只怕時光如水迅，前村忍聽一聲蜩。"]'),
('fc106618-98c4-4f6c-a494-5aa0ef95f057','答友人','陳普','宋','宋诗','song-poetry','','[]','雲作交游山作賓，道心爲主自安貧。',64,'全唐诗/poet.song.243000.json','["雲作交游山作賓，道心爲主自安貧。", "柴門無鑰見同物，竹帛有名終累人。", "綠水一潭澄靜性，青山萬疊裹閑身。", "紛紛望拜馬蹄下，不見胸中萬斛塵。"]'),
('88876148-85f1-43c2-a7d8-8d89a1e7094b','學詩  其一','陳普','宋','宋诗','song-poetry','','[]','先知老嫩辨精粗，又識寒酸與富腴。',64,'全唐诗/poet.song.243000.json','["先知老嫩辨精粗，又識寒酸與富腴。", "要落前人舊窠臼，也須作我大規模。", "英豪好是不緣酒，妥帖豈須由撚鬚。", "最好堯夫擊壤集，胸中閒氣一毫無。"]'),
('0c015d3c-07e6-44eb-bee0-e4ac999ef4fa','學詩  其二','陳普','宋','宋诗','song-poetry','','[]','摇膝支頤未冠年，已將采擷勝雕鎸。',64,'全唐诗/poet.song.243000.json','["摇膝支頤未冠年，已將采擷勝雕鎸。", "未能動地驚天句，且誦吟風弄月篇。", "擊壤莫拋康節集，煎膠可續上林弦。", "東山七月無人解，只是周公學有源。"]'),
('9c5f1901-7b08-4a95-8213-232fa5614431','雨霽山皆秋色','陳普','宋','宋诗','song-poetry','','[]','一朝積雨豁然收，待我凝眸百尺樓。',64,'全唐诗/poet.song.243000.json','["一朝積雨豁然收，待我凝眸百尺樓。", "遠遠修眉明碧落，稜稜瘦骨出清秋。", "同姿遠岸遥生靄，一意寒江亦露洲。", "此即化工無信息，天機衮衮不曾留。"]'),
('715ed4bc-7c14-4f63-bf8d-c39976d1faab','喜晴','陳普','宋','宋诗','song-poetry','','[]','炎天積雨氣如秋，今日新晴快倚樓。',64,'全唐诗/poet.song.243000.json','["炎天積雨氣如秋，今日新晴快倚樓。", "神女收雲清客夢，羲和鞭日慰民愁。", "昨朝苔砌行螻蟈，破曉松梢亂栗留。", "暑氣猶輕如四月，欲從溪上問輕舟。"]'),
('3b4624dd-9608-4b4b-b480-da312c4910b5','長夏竹中  其一','陳普','宋','宋诗','song-poetry','','[]','四圍碧玉遶盤河，六月此爲安樂窩。',64,'全唐诗/poet.song.243000.json','["四圍碧玉遶盤河，六月此爲安樂窩。", "且喜身心各清凈，但愁歲月爲消磨。", "洞門開闢元無鎖，暑氣羞慚自倒戈。", "只要人心明內外，紅塵取此本無多。"]'),
('ea3d3668-7006-464e-aa93-03b84aa61049','長夏竹中  其二','陳普','宋','宋诗','song-poetry','','[]','暑威赫赫甑寰區，繞屋琅玕足自娛。',64,'全唐诗/poet.song.243000.json','["暑威赫赫甑寰區，繞屋琅玕足自娛。", "四面塵埃渾不受，一年炎熱竟成無。", "絕稀人跡天同處，閲盡詩書日未晡。", "爲惜分陰故來此，時人疑是七賢徒。"]'),
('eec3e2bc-1c51-4e84-b317-d6518547c45b','連山一峰獨秀','陳普','宋','宋诗','song-poetry','','[]','雲屏屏斷亂山稠，中有青螺百尺修。',64,'全唐诗/poet.song.243000.json','["雲屏屏斷亂山稠，中有青螺百尺修。", "拔萃出群高地步，導前擁後作班頭。", "上連霄漢不盈尺，俯視岡陵總下流。", "吾道與君亦相似，功全一簣便相侔。"]'),
('af060173-6e3b-409f-b11f-931eea74059f','東作','陳普','宋','宋诗','song-poetry','','[]','經綸一札急農功，駿發公私四海同。',64,'全唐诗/poet.song.243000.json','["經綸一札急農功，駿發公私四海同。", "婦饁尚存豳國俗，耦耕不間楚鄉風。", "烏犍紛亂烟雲裏，布穀焦勞風雨中。", "隴外輟耕相賀處，年來隳突絕西東。"]'),
('ae5e82e4-ea2e-49d8-82a9-03e7d37b64ba','自杭來有四聖觀佛所言','陳普','宋','宋诗','song-poetry','','[]','浮杭江海備間關，金甲煌煌亦厚顔。',64,'全唐诗/poet.song.243000.json','["浮杭江海備間關，金甲煌煌亦厚顔。", "一夕蒼黄生病眼，百年丹碧照青灣。", "但聞兀朮聲翻海，不謂羅延力拔山。", "瑣瑣廢興何足道，傷身空在暗香間。"]'),
('fae7002f-8dae-4456-a767-b01e7f8128b9','呈汪主簿及茗源諸公','陳普','宋','宋诗','song-poetry','','[]','章甫公西愧點雩，斷纓子路羨柴愚。',64,'全唐诗/poet.song.243000.json','["章甫公西愧點雩，斷纓子路羨柴愚。", "天知人棄終多福，道屈身伸頼讀書。", "有日官曹須忍耐，薰天聲利儘欷歔。", "行藏謾似琅琊客，採藥深山日不虛。"]'),
('e1391c10-a0b9-4cf1-bc73-503643baf74d','挽詩','陳普','宋','宋诗','song-poetry','','[]','蠅頭蝸角總虛名，公擅儒林一老成。',64,'全唐诗/poet.song.243000.json','["蠅頭蝸角總虛名，公擅儒林一老成。", "四德兼全空翠袖，一丘何暇問蒼生。", "書窗掩月雞同夢，琴室臨溪魚識聲。", "可惜哲人今已矣，尚存畏敬儘堪刑。"]'),
('61c72328-5e55-440b-9e9c-25bcbd23fa90','贈清叟行','陳普','宋','宋诗','song-poetry','','[]','共君一夜話三生，語正投機君又行。',64,'全唐诗/poet.song.243000.json','["共君一夜話三生，語正投機君又行。", "溪柳效顰添別恨，岸花和意送離程。", "驚時莫問歸巢燕，贈別愁聞求友鶑。", "今夜夢中重聚首，鷄聲茅店已三更。"]'),
('f42f21bd-56b0-4bea-a71e-e169afa83d18','遠望','陳普','宋','宋诗','song-poetry','','[]','浮雲盡掃暖微霄，去鷺歸鴻入望遥。',64,'全唐诗/poet.song.243000.json','["浮雲盡掃暖微霄，去鷺歸鴻入望遥。", "積雨纔收平野闊，夕陽未卷大江豪。", "近看飄絮如千葉，遠見修眉若一毫。", "不有危樓高百尺，也應無處可呼號。"]'),
('72501507-5108-4036-b9c7-c68c04e2c787','和黄雲甫韻','陳普','宋','宋诗','song-poetry','','[]','志欲鑽研探本原，聖言爭柰遠如天。',64,'全唐诗/poet.song.243000.json','["志欲鑽研探本原，聖言爭柰遠如天。", "爬沙愧我遲而鈍，穿石輸君敏且專。", "方識立身須廣大，也知去道每輕儇。", "若將中正在正鵠，砥鏃磨鋒必入旃。"]'),
('e7461add-8869-4080-958a-f8c9485f16a9','和答友人','陳普','宋','宋诗','song-poetry','','[]','無一能攀古聖賢，僅能澄凈一腔天。',64,'全唐诗/poet.song.243000.json','["無一能攀古聖賢，僅能澄凈一腔天。", "新於梅畔見無極，久向心中閲逝川。", "文暢惠勤同錫飯，東園甪里共衾眠。", "儀秦肩穀難參錯，莫怪香山去學禪。"]'),
('cd1d4485-b64e-419d-858e-bd55e08e4831','次答姚考成留別','陳普','宋','宋诗','song-poetry','','[]','別後相逢各問年，依然綠髮對華顛。',64,'全唐诗/poet.song.243000.json','["別後相逢各問年，依然綠髮對華顛。", "閒雲獨占半間住，伴客那無一榻眠。", "酒爲愁多全欠力，詩因料少未成聯。", "却憐壁上留題句，時有閒情到月邊。"]'),
('389279e7-2804-42b0-9ff9-42ef1fdfe0f0','儒家秋  其一','陳普','宋','宋诗','song-poetry','','[]','講堂寂寂夜鳴蛩，苦爲兒曹課日功。',64,'全唐诗/poet.song.243000.json','["講堂寂寂夜鳴蛩，苦爲兒曹課日功。", "道體渾淪參太極，臯比冷落坐西風。", "研硃點易露華白，剪燭談經帳影紅。", "禮樂斯民開治教，閩中常衮蜀文翁。"]'),
('e498c638-bfe0-4a77-a9fd-5a0e220b504f','儒家秋  其二','陳普','宋','宋诗','song-poetry','','[]','離離秋色上梧枝，向曉烟雲冷硯池。',64,'全唐诗/poet.song.243000.json','["離離秋色上梧枝，向曉烟雲冷硯池。", "絳帳談經千古道，青山對酒幾聯詩。", "西風紅葉林邊樹，夜雨青燈鬢上絲。", "竹瘦荷枯籬菊凈，暫韜筆硯徹臯比。"]'),
('425fedb1-9579-444b-838d-7a86cda9f3a2','儒家秋  其三','陳普','宋','宋诗','song-poetry','','[]','蘆葦西風雁影孤，凄凄凉氣入郊墟。',64,'全唐诗/poet.song.243000.json','["蘆葦西風雁影孤，凄凄凉氣入郊墟。", "鐵檠灼爍三更雨，道脈精微幾卷書。", "潘鬢星霜愁髮短，韓堂風露故交疏。", "朝廷有道奎星顯，何苦蓬窗守蠹魚。"]'),
('0099b8df-75b4-4a08-886b-00afb60b8603','烈女秋  其一','陳普','宋','宋诗','song-poetry','','[]','陽臺春夢逐浮雲，燈影西風獨閉門。',64,'全唐诗/poet.song.243000.json','["陽臺春夢逐浮雲，燈影西風獨閉門。", "一點清心霜六月，半簾紅葉雨黄昏。", "守符終古漸臺水，墜血經今金谷園。", "何事文君無雅操，琴聲一動便思奔。"]'),
('65dd4b3d-eb40-4b79-87bc-050fb135451e','烈女秋  其二','陳普','宋','宋诗','song-poetry','','[]','不思粉黛學傾城，心對冰壺貯月明。',64,'全唐诗/poet.song.243000.json','["不思粉黛學傾城，心對冰壺貯月明。", "魏國節操成令女，湘江竹淚泣娥英。", "床頭明鏡春容減，桑下黄金秋葉輕。", "守靜不因時物感，西風荒草自蛩聲。"]'),
('23bacf4a-930f-4ab1-82c3-630ab359036f','烈女秋  其三','陳普','宋','宋诗','song-poetry','','[]','一盞殘燈對影居，鳳飛西去彩鸞孤。',64,'全唐诗/poet.song.243000.json','["一盞殘燈對影居，鳳飛西去彩鸞孤。", "毀身令女生全節，沉水齊姜死守符。", "月色半簾閒翡翠，蛩聲孤枕冷珊瑚。", "柏舟歌罷塵埋鏡，淅瀝秋聲在竹梧。"]'),
('cf6adb8c-5e4e-488b-870b-7edc37bfee6e','秋日即事  其一','陳普','宋','宋诗','song-poetry','','[]','夜床輾轉恨明遲，曉髮梳寒倚竹扉。',64,'全唐诗/poet.song.243000.json','["夜床輾轉恨明遲，曉髮梳寒倚竹扉。", "樹影紙窗風作色，蛩聲壁罅月流輝。", "三盃白酒窮年客，滿篋紅塵隔歲衣。", "遥想白鷗江上路，蓼花楓葉雨霏霏。"]'),
('44f311ec-96d5-4ca3-b261-833a61a1bd66','秋日即事  其二','陳普','宋','宋诗','song-poetry','','[]','玉露金莖曉髮寒，秋風仍作去年看。',64,'全唐诗/poet.song.243000.json','["玉露金莖曉髮寒，秋風仍作去年看。", "蛩聲疏雨長爲客，雁影殘蟬獨倚欄。", "錢硯窗欞雲影淡，丹楓溪曲水痕乾。", "西風曾與黄花約，擬掇繁英貰酒餐。"]'),
('662dca00-d556-42d0-9f55-99f3c44c40dd','秋日即事  其三','陳普','宋','宋诗','song-poetry','','[]','二尺書檠對影居，西風吹雪上吟鬚。',64,'全唐诗/poet.song.243000.json','["二尺書檠對影居，西風吹雪上吟鬚。", "雲邊月色人千里，竹裏秋聲酒一壺。", "客思邇來紅葉亂，雁聲南去白雲孤。", "季鷹自是知機者，一念蓴鱸便到吳。"]'),
('5189da37-1a20-4f53-9d2e-a7e83ea5fce4','秋日即事  其四','陳普','宋','宋诗','song-poetry','','[]','書餘飲水枕長肱，四壁啼蛩訴不平。',64,'全唐诗/poet.song.243000.json','["書餘飲水枕長肱，四壁啼蛩訴不平。", "月色滿窗詩骨冷，露華半枕夢魂清。", "西風歲歲長堤柳，流水朝朝滄海情。", "紅葉山深無雁過，殘砧幾處搗愁聲。"]'),
('a0850cbc-ab7c-4128-a753-726be372fa31','秋日即事  其五','陳普','宋','宋诗','song-poetry','','["\u534e\u5c71"]','遊絲閃閃掛虛簷，翔隼號寒華嶽尖。',64,'全唐诗/poet.song.243000.json','["遊絲閃閃掛虛簷，翔隼號寒華嶽尖。", "白髮束來閑點易，烏衣歸去寂鉤簾。", "三千客路飛楓葉，四五人家賣酒帘。", "魚笛水寒江上晚，半叢豆葉雨纖纖。"]'),
('918b43cd-f007-4824-9b11-09bb357070cf','鼓瑟  其一','陳普','宋','宋诗','song-poetry','','[]','滿樓明月調雲和，五十絃中急雨過。',64,'全唐诗/poet.song.243000.json','["滿樓明月調雲和，五十絃中急雨過。", "彩鳳拂衣鳴翠竹，素鱗鼓鬣出寒波。", "凄凉楚客新愁斷，清切湘靈舊怨多。", "一曲更沉人已靜，江頭雲掛綠嵯峨。"]'),
('62ad4bff-4e15-48c7-9e79-8d58e66a0584','鼓瑟  其二','陳普','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','朱絃聲奏徹雲清，有客沉吟倚柱聽。',64,'全唐诗/poet.song.243000.json','["朱絃聲奏徹雲清，有客沉吟倚柱聽。", "遺響一時存楚曲，斷魂千載寫湘靈。", "珠隨明月生滄海，船挾悲風過洞庭。", "絃索無言膠柱倒，遥遥江上數峰青。"]'),
('5e06ce04-52d1-4a85-9336-b443f388832c','鼓瑟  其三','陳普','宋','宋诗','song-poetry','','[]','五十朱絃不與琴，一絃一柱調清音。',64,'全唐诗/poet.song.243000.json','["五十朱絃不與琴，一絃一柱調清音。", "南華喚醒莊生夢，西蜀傳留望帝心。", "魚躍滄波風嫋嫋，鳳飛丹穴月沉沉。", "此情不待鏗而作，一攬新聲見古今。"]'),
('a3306e79-ce5e-4187-a6b3-d84c48368de0','夜坐','陳普','宋','宋诗','song-poetry','','[]','竹雲亂相逐，明月羞如女。',24,'全唐诗/poet.song.243000.json','["竹雲亂相逐，明月羞如女。", "青山鎖幽人，饑民卧茅宇。"]'),
('cddeb58a-dbbc-410f-88cf-9eb96f244917','有感','陳普','宋','宋诗','song-poetry','','[]','益州桑柘雨，莘野稻粱秋。',24,'全唐诗/poet.song.243000.json','["益州桑柘雨，莘野稻粱秋。", "功業髯秋兔，行藏汗萬牛。"]'),
('c9990b2e-d637-4c6b-9593-5582f2cff812','高宗帖','陳普','宋','宋诗','song-poetry','','[]','寢苫枕干子，有暇綰秋蛇。',24,'全唐诗/poet.song.243000.json','["寢苫枕干子，有暇綰秋蛇。", "仁人不忍見，俗子持相誇。"]'),
('6f02a969-e84b-4964-a09c-5c6aa737ed4b','姚國秀十詠 東塾','陳普','宋','宋诗','song-poetry','','[]','濂溪義安取，新鄭與新豐。',24,'全唐诗/poet.song.243000.json','["濂溪義安取，新鄭與新豐。", "所以東塾子，拳拳東塾翁。"]'),
('6d399c29-4fe1-4f9c-ac1f-41da85e77055','姚國秀十詠 溪莊','陳普','宋','宋诗','song-poetry','','[]','疇昔何來此，青山與白鷗。',24,'全唐诗/poet.song.243000.json','["疇昔何來此，青山與白鷗。", "絮飛春不去，潮返月頻留。"]'),
('0f467e98-3776-4d9a-8dfb-7235b4d8028f','姚國秀十詠 玉女峰','陳普','宋','宋诗','song-poetry','','[]','道心苦難足，造物冷看人。',24,'全唐诗/poet.song.243000.json','["道心苦難足，造物冷看人。", "鐵漢未成就，遺渠妍笑顰。"]'),
('492e797b-6ef9-4a77-b7af-7b1581d15515','姚國秀十詠 勒馬山','陳普','宋','宋诗','song-poetry','','[]','六合橫馳騖，道人門不開。',24,'全唐诗/poet.song.243000.json','["六合橫馳騖，道人門不開。", "回頭顧明命，鞭辟入身來。"]'),
('e7c9516c-d4bf-442d-828a-fd338643e1e4','姚國秀十詠 圓山','陳普','宋','宋诗','song-poetry','','[]','道人見此山，指作太極圖。',24,'全唐诗/poet.song.243000.json','["道人見此山，指作太極圖。", "中宵挂明月，請看頭上無。"]'),
('829da421-9caf-43a5-bae2-ff6341a48178','姚國秀十詠 信芳亭','陳普','宋','宋诗','song-poetry','','[]','德馨何酷烈，同心皆與知。',24,'全唐诗/poet.song.243000.json','["德馨何酷烈，同心皆與知。", "靈根在何許，暗室毋自欺。"]'),
('f80644b8-8199-49f9-9d50-67bf9e6db8a3','姚國秀十詠 小山','陳普','宋','宋诗','song-poetry','','[]','平生一丘願，不忘岳連姿。',24,'全唐诗/poet.song.243000.json','["平生一丘願，不忘岳連姿。", "若求靜壽意，一簣有餘師。"]'),
('f3c2b790-df72-4f04-b49a-511cedee434a','姚國秀十詠 竹塢','陳普','宋','宋诗','song-poetry','','[]','竹靜塵不染，塢深人不到。',24,'全唐诗/poet.song.243000.json','["竹靜塵不染，塢深人不到。", "欲海不可航，聊須從吾好。"]'),
('43061eac-f823-47c7-86b5-c3fc0e72e8a4','姚國秀十詠 菱塘','陳普','宋','宋诗','song-poetry','','[]','廉隅集謠詠，舉世尚和光。',24,'全唐诗/poet.song.243000.json','["廉隅集謠詠，舉世尚和光。", "平生憎老子，蓄雨肥菱塘。"]'),
('f7f9caee-9a13-4e92-a785-a94dd936870a','姚國秀十詠 梅窗','陳普','宋','宋诗','song-poetry','','[]','年年佩溫故，先入一枝來。',24,'全唐诗/poet.song.243000.json','["年年佩溫故，先入一枝來。", "歲寒吾與女，欲別重徘徊。"]'),
('853268d5-4eaa-49bf-8f89-60697419390f','贈南豐姚敬仲','陳普','宋','宋诗','song-poetry','','[]','孔門縲絏可妻，董生孝慈有翁。',28,'全唐诗/poet.song.243000.json','["孔門縲絏可妻，董生孝慈有翁。", "天與仲尼不恕，人間處處流通。"]'),
('54fa7f1e-9249-4a9f-a592-1ef3417b0cee','野步  其一','陳普','宋','宋诗','song-poetry','','[]','南雁數聲嘹唳，西風雙鬢䰐鬖。',28,'全唐诗/poet.song.243000.json','["南雁數聲嘹唳，西風雙鬢䰐鬖。", "病葉夕陽滿樹，斷雲殘雨歸岩。"]'),
('ee0861c5-536c-4c6d-a22b-57b1db10abbf','野步  其二','陳普','宋','宋诗','song-poetry','','[]','瀟灑枯藤老屨，行行只復行行。',28,'全唐诗/poet.song.243000.json','["瀟灑枯藤老屨，行行只復行行。", "泥路野人屐跡，石橋流水琴聲。"]'),
('a3e5a8da-22ce-4401-9866-31c315b011a1','野步  其三','陳普','宋','宋诗','song-poetry','','[]','黄犢眼中荒草，鷺鷥立處枯荷。',28,'全唐诗/poet.song.243000.json','["黄犢眼中荒草，鷺鷥立處枯荷。", "宦海風濤舟楫，故山烟雨松蘿。"]'),
('8a8387a8-6cbc-4bbf-878c-a66b05913054','野步  其四','陳普','宋','宋诗','song-poetry','','[]','愁思冥鴻杳杳，吟情敗葉紛紛。',28,'全唐诗/poet.song.243000.json','["愁思冥鴻杳杳，吟情敗葉紛紛。", "歸去滿身溪雨，醉眠半枕山雲。"]'),
